export interface ExtendedContent {
  up2: string
  rev2: string
  love2: string
  career2: string
  spirit2: string
  faq: Array<{ q: string; a: string }>
}

export const CARD_EXTENDED: Record<string, ExtendedContent> = {

  'the-fool': {
    up2: `The Fool's deeper invitation is to examine your relationship with uncertainty itself. Most people treat the unknown as something to be managed, minimised, or eliminated before taking action — The Fool suggests the opposite: that leaping before the net appears is sometimes the only way the net ever gets woven. Psychologically, this card points to what developmental theorists call beginner's mind — a state of genuine openness that adults rarely inhabit because accumulated experience creates filtering assumptions. The Fool doesn't lack wisdom; he carries it lightly. Notice the small pack on his stick — he travels with essentials only. This card asks what you are over-packing: what outdated beliefs, defensive habits, or exhausted identities are weighing down your next beginning. The cliff edge isn't a warning; it's the starting line.`,
    rev2: `The Fool reversed rarely signals that you are literally foolish. More often it indicates a paralysis dressed up as caution — the endless preparation that keeps you safely rehearsing rather than performing. It can also surface as recklessness of a different kind: impulsive decisions made without any reflection, all leap and no looking. In either case, the relationship with risk has become distorted. There may be a fear of being seen as naive or inexperienced, causing you to present a false maturity that costs more than it protects. Alternatively, you may be numbing anxiety through constant action with no roots. The reversed Fool asks you to locate the difference between wisdom and fear — and to notice which one is actually running the show right now.`,
    love2: `In love, The Fool reversed often shows up as commitment-phobia masquerading as independence, or as rushing into connection without pausing to consider compatibility. You may be so afraid of being hurt that you either hold people at arm's length indefinitely or attach too quickly before real trust has been established. Either pattern reflects the same underlying wound: a belief that vulnerability is dangerous. Genuine intimacy requires a willingness to step off the cliff.`,
    career2: `Professionally, The Fool reversed can indicate a good idea that keeps getting postponed because conditions never feel quite right. The business plan perpetually in draft, the application never submitted, the conversation endlessly rehearsed. It can also signal leaping into work situations without due diligence — taking a role or contract that looked exciting but wasn't examined carefully. Both extremes share a disconnect between instinct and discernment.`,
    spirit2: `Spiritually, The Fool reversed points to a practitioner going through the motions without genuine freshness. Rituals calcify, beliefs become inherited furniture rather than lived discoveries. The invitation is to approach your practice as if for the first time — to let go of what you think you already know and allow direct experience to teach you again.`,
    faq: [
      {
        q: 'What does The Fool mean in tarot?',
        a: `The Fool is the first card of the Major Arcana, numbered 0, and represents the soul at the beginning of its journey — open, unformed, full of potential. It's a card of new beginnings, spontaneity, and the courage to step into the unknown. Psychologically it speaks to beginner's mind: approaching life without the defensive filters that experience can create. It asks whether you're living with genuine openness or performing a safety that's actually holding you back. The Fool isn't naive — he's brave enough to not yet know.`,
      },
      {
        q: 'Is The Fool a yes or no card?',
        a: `Upright, The Fool leans strongly toward yes — especially for questions about new ventures, taking a leap, or starting fresh. Its energy is affirmative and forward-moving. Reversed, the answer is more nuanced: not a flat no, but a prompt to examine whether your timing is genuinely right or whether fear is either rushing you or holding you back. The Fool reversed in a yes/no reading suggests the answer depends on getting your inner relationship with risk sorted before acting.`,
      },
      {
        q: 'What does The Fool mean in love?',
        a: `In love readings, The Fool upright is one of the most exciting cards to receive — it suggests a relationship full of freshness, spontaneity, and genuine possibility. It may indicate a new romance beginning, or an established relationship entering a lighter, more playful phase. It can also suggest you need to take a romantic risk you've been avoiding. Reversed in love, it points to fear of commitment, premature rushing, or not learning from past patterns. The core question is whether you're showing up open-hearted or self-protected.`,
      },
    ],
  },

  'the-magician': {
    up2: `Beyond the surface reading of skill and willpower, The Magician carries a deeper teaching about the relationship between inner resources and outer manifestation. The four tools on his table — cup, wand, sword, pentacle — represent the four suits of the tarot, which themselves map to the four dimensions of human experience: emotion, intuition, thought, and material reality. The Magician's power is not supernatural; it is integrative. He works because he brings all of himself to bear on a single point of focus. Most people operate from one or two preferred modes — thinkers who suppress feeling, feelers who avoid analysis — and wonder why their efforts feel incomplete. The Magician asks: which of your tools are you leaving on the table? Real agency arrives when you stop specialising in yourself and start using everything you have.`,
    rev2: `The Magician reversed often points to misdirected skill — genuine talent and intelligence being used in service of manipulation, self-deception, or goals that don't actually align with your deeper values. It can indicate someone in your life wielding charm and persuasion to serve their own ends at your expense, or it may be showing you an internal pattern: ways you talk yourself into or out of things using sophisticated reasoning that is, at its core, avoidance. There's also a simpler reading: untapped potential. The tools are present, the ability is real, but something — fear of failure, perfectionism, lack of focus — is keeping the wand lowered. The reversed Magician is rarely about lack of ability. It is about a misalignment between what you're capable of and what you're currently doing with it.`,
    love2: `In love, The Magician reversed can signal that someone is being charming rather than honest — performing attraction while keeping real vulnerability locked away. You may be dazzling a partner with your best self while hiding the rest. Alternatively, it can indicate a relationship where one person is subtly manipulative, using persuasion rather than genuine communication. The invitation is to swap performance for presence. Real intimacy doesn't require a show.`,
    career2: `Professionally, The Magician reversed often appears when skills are being squandered — either through lack of focus, wrong environment, or a feeling of going through the motions. You may be capable of far more than your current role demands, leading to frustration or stagnation. It can also signal a colleague or competitor who isn't playing fairly, using their abilities to gain advantage through deception rather than merit. Discernment about who to trust professionally is advised.`,
    spirit2: `Spiritually, The Magician reversed warns against mistaking spiritual performance for genuine transformation. Collecting practices, reading prolifically, and speaking the language of growth can all become a form of ego management rather than real work. The question is whether your spiritual life is changing how you actually live — how you treat people, how you handle fear — or whether it remains a sophisticated identity you wear.`,
    faq: [
      {
        q: 'What does The Magician mean in tarot?',
        a: `The Magician is the first numbered card of the Major Arcana and represents directed will, skill, and the power to translate intention into reality. He stands at the meeting point of heaven and earth — one hand raised, one pointing down — suggesting that he channels higher potential into tangible form. His four tools represent the complete resources available to any human: feeling, intuition, intellect, and material capacity. As a card, he speaks to your ability to create outcomes when you bring focus and full engagement to bear. He is a card of agency, resourcefulness, and intentional action.`,
      },
      {
        q: 'Is The Magician a yes or no card?',
        a: `Upright, The Magician is a strong yes — particularly for questions about whether you have what it takes to achieve something or whether now is a good time to act. His energy is one of capability and focused will. He affirms that the resources you need are available, even if you haven't fully deployed them yet. Reversed, the answer shifts toward a conditional yes: the ability is present, but something in your approach — focus, integrity, or alignment — needs examination before you're likely to succeed. It's a card of potential waiting to be properly directed.`,
      },
      {
        q: 'What does The Magician mean in love?',
        a: `In love readings, The Magician upright is an excellent card suggesting chemistry, magnetic attraction, and the ability to create the kind of relationship you genuinely want. It can signal a new connection with strong potential or an established partnership entering a creative, energised phase. It may also be asking you to take more active responsibility for the quality of your love life rather than waiting for things to happen to you. Reversed in love, watch for charm over substance — either in a potential partner or in your own approach to relating.`,
      },
    ],
  },

  'the-high-priestess': {
    up2: `The High Priestess represents a mode of knowing that Western culture has systematically undervalued: the kind that comes through stillness, through the body, through dreams and metaphor rather than logic and argument. She sits between the pillars of Boaz and Jachin — opposing forces — suggesting she doesn't resolve duality into a tidy answer but holds it, allowing understanding to emerge from the tension itself. This is precisely what the rational mind struggles to do. Where The Magician acts, The High Priestess waits — not passively, but with acute attentiveness. She is the archetype of the unconscious mind, the part of you that processes vast amounts of information below the threshold of awareness and periodically surfaces a knowing you can't fully explain. When she appears, something important is trying to reach you through channels your logical mind normally filters out.`,
    rev2: `The High Priestess reversed points to a severance from inner knowing — a state where external noise, the opinions of others, or the relentless pressure to decide and perform have drowned out the quieter signal of genuine intuition. You may be making decisions by committee or by spreadsheet in areas of life that actually require a different kind of intelligence. There's also a shadow expression: using mystery as a protective barrier, withholding not out of genuine discretion but out of fear of being known. In some readings, she reversed indicates repressed emotions or unconscious material that is beginning to exert pressure — things you've declined to look at that are now making their presence felt in symptoms, dreams, or inexplicable anxiety.`,
    love2: `In love, The High Priestess reversed often appears when someone is intellectualising their feelings rather than feeling them — analysing a relationship to death rather than simply being present within it. There may also be a pattern of emotional unavailability dressed up as independence or mystery. If you're in a relationship, ask whether genuine intimacy is present or whether both people are orbiting each other at a careful, armoured distance.`,
    career2: `Professionally, The High Priestess reversed suggests decisions being made without sufficient reflection — a rush to action, a tendency to override gut feelings in favour of what looks sensible or what others advise. It can also indicate a workplace where intuition and creative intelligence are systematically undervalued in favour of measurable output. If you have a nagging sense that something isn't right in your professional life, this card is asking you to take that seriously rather than reason it away.`,
    spirit2: `Spiritually, The High Priestess reversed points to a practitioner who has become too busy for the silence that genuine inner work requires. Meditation turns into achievement, journalling becomes performance, and the very practices designed to create space become additional things to get through. The card asks you to stop doing your spirituality and simply be inside it.`,
    faq: [
      {
        q: 'What does The High Priestess mean in tarot?',
        a: `The High Priestess is the archetype of inner knowing, intuition, and the unconscious mind. She represents the intelligence that operates beneath conscious awareness — the part of you that knows things you can't yet explain. Seated between two pillars and holding a scroll of hidden knowledge, she is the guardian of mystery, of what cannot be forced into the daylight of rational explanation. When she appears, she is almost always asking you to pause, listen inwardly, and trust a knowing that arrives quietly rather than loudly. She is one of the tarot's most powerful cards for inner work.`,
      },
      {
        q: 'Is The High Priestess a yes or no card?',
        a: `The High Priestess is one of the more ambiguous yes/no cards because her nature is inherently non-committal — she holds questions open rather than resolving them. In yes/no readings, she's best understood as "not yet clear" or "look deeper." She's asking you to sit with the question rather than force an answer prematurely. If you already have a strong gut feeling about the situation, she may be affirming that feeling. If you have no feeling yet, she's advising you to wait before deciding. She is rarely a flat yes or no.`,
      },
      {
        q: 'What does The High Priestess mean in love?',
        a: `In love, The High Priestess upright is a card of depth, mystery, and the slow unfolding of genuine connection. She suggests that what's most important about a relationship isn't yet visible — there are layers to explore, feelings not yet spoken, potential not yet realised. She can also signal that you need to listen to your own intuition about someone rather than rationalising away what you're sensing. Reversed in love, she points to emotional guardedness, over-analysis, or a refusal to let someone close enough to actually know you.`,
      },
    ],
  },

  'the-empress': {
    up2: `The Empress represents the principle of creative abundance operating through the natural world — the intelligence that turns seed into fruit, that moves through seasons without forcing, that generates life as an intrinsic expression of what it is. Psychologically she maps to what Jungians call the Great Mother archetype: the containing, nurturing, generative force that makes growth possible. Her deeper teaching is that true creativity is not primarily about production but about fertility — the creation of conditions in which things can grow. This is subtly but significantly different from manufacturing outcomes through effort. The Empress thrives; she doesn't grind. When she appears, she often signals that you are either entering a period of genuine creative or material abundance, or that you need to stop depleting yourself and restore the conditions — rest, pleasure, sensory engagement, genuine self-care — that make you generative.`,
    rev2: `The Empress reversed points to disruptions in the cycle of giving and receiving — usually an excess in one direction. You may be over-giving to the point of depletion, so busy nurturing others that you've abandoned your own needs entirely. Or the pattern runs the opposite way: a withholding of care, a numbness to pleasure and beauty, a disconnection from the body and its signals. There's also the shadow of the mother archetype: the smothering impulse, the control dressed up as care, the inability to let those you love grow beyond your oversight. Creative blocks often appear with this card — not a lack of talent but a severance from the receptive, fallow state that creativity actually needs. You may be forcing output when you need to be composting.`,
    love2: `In love, The Empress reversed can signal over-nurturing — smothering a partner with care that's really about your own anxiety — or a neglect of the relationship's emotional warmth and tenderness. Sensuality may have gone quiet; the relationship might feel more functional than alive. There can also be issues around motherhood, fertility, or family dynamics. The invitation is to ask what the relationship needs to feel genuinely nourishing rather than merely dutiful.`,
    career2: `Professionally, The Empress reversed can appear when creative work has stalled — when inspiration has dried up, when projects feel laboured and joyless. This is often a signal of burnout: the conditions for genuine creativity (rest, play, spaciousness) have been deprioritised in favour of relentless output. It can also indicate a work environment that is harsh, competitive, or emotionally cold in ways that are genuinely affecting your wellbeing and productivity.`,
    spirit2: `Spiritually, The Empress reversed can indicate a disconnection from the body as a site of wisdom — an overly cerebral or disembodied approach to inner life. Spirit is being sought in concepts and abstractions rather than in sensation, nature, and direct experience. Practices that restore connection to the physical — walking in nature, somatic work, creative making — are likely to be more nourishing right now than further reading or study.`,
    faq: [
      {
        q: 'What does The Empress mean in tarot?',
        a: `The Empress is the archetype of abundant creative and natural life — she represents fertility, sensuality, nurturing, and the generative power of the natural world. Seated among lush vegetation with the planet Venus as her emblem, she embodies the principle that life creates more life when the conditions are right. She speaks to creativity, abundance, maternal energy, bodily wisdom, and the importance of pleasure and beauty as sustaining forces. When she appears, she's often affirming a period of growth and flourishing, or asking you to restore the conditions — rest, pleasure, care — that make such growth possible.`,
      },
      {
        q: 'Is The Empress a yes or no card?',
        a: `Upright, The Empress is a warm, affirmative yes — especially for questions about creative projects, relationships, family matters, or anything involving growth and abundance. She is one of the most positive cards in the deck for questions about fertility (in its broadest sense), nurturing ventures to fruition, and whether the conditions are right for something to flourish. Reversed, she suggests the conditions need attention before a confident yes is warranted — there may be depletion, imbalance, or a creative block that needs addressing. The potential is there; the soil needs tending.`,
      },
      {
        q: 'What does The Empress mean in love?',
        a: `In love, The Empress is one of the most auspicious cards — she brings warmth, sensuality, genuine nurturing, and the kind of easy, embodied intimacy that doesn't need to be forced. She can indicate a deeply nourishing relationship, a phase of increased closeness and physical affection, or the beginning of a family chapter. She's particularly positive for questions about conception or pregnancy. Reversed in love, she may point to codependency, smothering dynamics, or a relationship that has lost its warmth and vitality — asking what needs to be tended to restore genuine connection.`,
      },
    ],
  },

  'the-emperor': {
    up2: `The Emperor represents mature masculine authority — not domination, but the capacity to provide structure that enables others to flourish within it. The distinction is critical and often missed. Genuine authority creates safety by establishing clear boundaries, consistent principles, and reliable systems. It is fundamentally in service of something beyond the self: family, community, values. The shadow reading of The Emperor confuses this with control, but real imperial energy — at its healthy expression — is more interested in the integrity of the structure than in personal power. Psychologically, this card maps to the healthy development of the ego: the capacity to make decisions, hold a course under pressure, and resist being moved by every passing mood or external pressure. When The Emperor appears, you may be called to embody this kind of steadiness — or to recognise that you've been refusing to.`,
    rev2: `The Emperor reversed is one of the tarot's more complex reversals because it can represent two quite different problems. The first is excess: authority that has hardened into authoritarianism, rigidity masquerading as principle, an inability to adapt because flexibility feels like weakness. The father who cannot hear "no," the manager who mistakes compliance for respect — this is one face of the reversed Emperor. The second is absence: a deficit of healthy structure, an unwillingness to take responsibility, a passive relationship to your own life in which you wait for external permission or direction before moving. Both readings share a core dysfunction: a confused relationship to power and its proper exercise.`,
    love2: `In love, The Emperor reversed often points to control issues — either you or your partner using authority, emotional withholding, or dominance to manage intimacy rather than allow it. There may be a marked power imbalance in the relationship. Alternatively, it can indicate someone who won't commit to the structure and responsibility that a genuine partnership requires. The question is whether the relationship has a foundation of mutual respect or whether power is being used as a substitute for vulnerability.`,
    career2: `Professionally, The Emperor reversed can manifest as a problematic authority figure — a domineering or micromanaging boss, or an institutional structure so rigid it prevents any genuine initiative or creativity. It can also reflect your own relationship to authority at work: difficulty accepting direction, conflict with hierarchies, or conversely a reluctance to step into leadership when the situation genuinely calls for it. Examine where you are with power in your professional life.`,
    spirit2: `Spiritually, The Emperor reversed often signals an over-reliance on structure and doctrine at the expense of direct experience. Following a teacher, tradition, or set of rules without genuine personal engagement can become its own form of avoidance. The card asks whether your spiritual framework is supporting growth or simply providing a sense of order that keeps the real questions safely at bay.`,
    faq: [
      {
        q: 'What does The Emperor mean in tarot?',
        a: `The Emperor is the archetype of stable authority, structure, and mature masculine power. He represents the capacity to create reliable systems and clear boundaries through which others can grow and flourish. He's associated with fatherhood in its broadest sense — not just biological fatherhood but any role that involves providing dependable structure and protection. As a card, he often appears when structure, discipline, or a firmer grip on your own life is needed. He can also represent authority figures, institutions, or the father archetype in the context of someone's personal history.`,
      },
      {
        q: 'Is The Emperor a yes or no card?',
        a: `Upright, The Emperor leans toward yes — particularly for questions about stability, structure, taking control of a situation, or whether a plan is well-founded enough to succeed. His energy is one of confident authority and follow-through. He is especially affirmative for questions about business ventures, organisational matters, and anything requiring sustained discipline. Reversed, the answer becomes more cautious: there may be obstacles in the form of authority figures, structural problems, or your own resistance to taking necessary responsibility. Not a no, but a signal to examine the foundations before proceeding.`,
      },
      {
        q: 'What does The Emperor mean in love?',
        a: `In love, The Emperor upright can indicate a relationship with strong foundations and genuine stability — a partnership built on mutual respect, clear values, and real commitment. He can also represent a partner who is protective, reliable, and takes relationship seriously. In some readings, he asks whether you're willing to commit to the structure and responsibility that lasting love requires. Reversed in love, he may signal controlling dynamics, emotional rigidity, a domineering partner, or conversely — a person who won't take relational responsibility or make genuine commitments.`,
      },
    ],
  },

  'the-hierophant': {
    up2: `The Hierophant is frequently misread as a card of mere conformity, but his deeper function is more interesting: he represents the transmission of wisdom through form — the idea that some truths need to be held in structures (rituals, traditions, institutions) to survive long enough to be passed on. Every spiritual tradition, ethical system, and cultural practice is a Hierophant: an attempt to embody and transmit something meaningful across time and community. His real question is not "are you obedient?" but "what are you a student of, and what traditions are you a steward of?" There's also a relational dimension here: the Hierophant presides over formal commitments, shared values, and the sacred agreements between people that give life its moral coherence. When he appears, you may be in a moment that calls for learning from established wisdom rather than reinventing everything from scratch.`,
    rev2: `The Hierophant reversed often signals that the structures you've been working within — whether institutions, belief systems, cultural expectations, or family traditions — are no longer serving your genuine development. There is a difference between a rule that holds wisdom and a rule that merely holds power, and this card in reverse asks you to distinguish between them. It can indicate an awakening to the ways you've outsourced your own moral and spiritual authority to external sources — teachers, organisations, doctrines — that may not deserve the degree of trust you've placed in them. This is rarely comfortable. It can also, in its less developed expression, manifest as blanket rebellion: a rejection of all form and tradition simply because form feels constraining.`,
    love2: `In love, The Hierophant reversed can indicate that a relationship is bucking convention — choosing a path that doesn't follow expected scripts around timing, structure, or social approval. This isn't inherently negative; sometimes conventional relationship forms don't fit. It can also point to a mismatch in values between partners, or pressure from family and community that is creating conflict. The question is whether you're building something meaningful together on your own terms.`,
    career2: `Professionally, The Hierophant reversed often appears when someone is chafing against institutional constraints — corporate culture, professional norms, or hierarchical structures that feel at odds with their values or actual capabilities. It can signal that it's time to find or create a more aligned professional context. Less positively, it can indicate someone bucking legitimate professional standards, or a workplace culture with a problematic relationship to authority and accountability.`,
    spirit2: `Spiritually, The Hierophant reversed is a classic card for those moving from inherited religion to personally constructed spirituality. The form has been outgrown; the transmission mechanism no longer carries the signal. This is not a failure of faith but an invitation to do the harder work of deciding, from your own experience, what you actually believe and what values you genuinely hold. Spiritual adulthood requires exactly this.`,
    faq: [
      {
        q: 'What does The Hierophant mean in tarot?',
        a: `The Hierophant is the archetype of spiritual and social tradition — he represents established wisdom, institutional structures, formal learning, and the transmission of values through communities and rituals. Often depicted as a religious authority figure, he embodies the idea that some knowledge is best received through tradition and mentorship rather than individual discovery. He's associated with marriage, formal education, organised religion, and the ethical frameworks that societies build to hold shared meaning. When he appears, he's often asking about your relationship to tradition: are the structures you're working within genuinely serving your growth?`,
      },
      {
        q: 'Is The Hierophant a yes or no card?',
        a: `Upright, The Hierophant tends toward yes for questions about conventional paths, formal commitments, or situations where following established wisdom or a proven system is the wisest course. He's particularly affirmative for questions about marriage, formal education, joining a community, or seeking mentorship. Reversed, his answer is more nuanced — closer to "not in the conventional way." He may be suggesting an unconventional approach or indicating that the usual structure won't serve this particular situation. He's rarely a flat no, but he asks whether the conventional path is the right one for you.`,
      },
      {
        q: 'What does The Hierophant mean in love?',
        a: `In love, The Hierophant upright is classically associated with formal, committed partnership — marriage, long-term commitment, or a relationship that is recognised and blessed by the community or family. He suggests shared values as the foundation of lasting love and can indicate that a relationship is moving toward formal commitment. He can also represent a relationship in which spiritual or moral values are deeply important to both partners. Reversed in love, he may indicate a relationship that challenges convention, a mismatch of values, or family pressure around a romantic choice.`,
      },
    ],
  },

  'the-lovers': {
    up2: `The Lovers card contains a subtlety that most readings miss: the primary theme is not romance but discernment — the capacity to make an authentic choice from your deepest values rather than from social pressure, habit, or fear. The angel above the couple in the Rider-Waite image is Raphael, the archangel of air and communication, suggesting that genuine love requires clarity of mind alongside openness of heart. The deeper invitation of this card is to examine what you truly value — not what you've been told to value or what seems safest to want, but what genuinely calls to you when you're fully honest with yourself. It often appears at genuine crossroads: not just in love, but wherever a choice will fundamentally shape who you are becoming. The card asks not just "what do you choose?" but "who are you in the choosing?"`,
    rev2: `The Lovers reversed points to dysfunction in the realm of choice and connection — specifically, a tendency to make choices from the wrong level of yourself. This can manifest as choosing from fear (staying in situations that don't serve you because the alternative feels worse), from others' expectations (living someone else's version of a good life), or from avoidance (refusing to choose at all and hoping circumstances will decide for you). In relationship contexts, it can indicate a genuine incompatibility that is being ignored, or a relationship in which one or both people aren't being honest about what they actually want. The reversed Lovers also sometimes points to a specific temptation — an attractive option that, on closer examination, conflicts with your deeper values.`,
    love2: `In love, The Lovers reversed can indicate a relationship where genuine alignment is lacking — you may be staying for the right historical reasons rather than because of present-tense truth. There may be dishonesty, including the dishonesty of silence, about core incompatibilities. It can also surface as commitment avoidance, an inability to fully choose a partner, or a third-party complication — emotional or literal — that is disrupting the primary connection.`,
    career2: `Professionally, The Lovers reversed often appears when someone is in a career that doesn't reflect their genuine values or interests — working for money, status, or others' approval rather than from authentic motivation. It can also indicate a working relationship that has become strained, a partnership with fundamental value misalignment, or a moment of ethical compromise at work that is creating an inner conflict you haven't fully acknowledged.`,
    spirit2: `Spiritually, The Lovers reversed points to a fragmented inner life — a split between what you profess to believe and how you actually live. The spiritual work here is integration: bringing your outer choices into alignment with your deepest values, closing the gap between the person you claim to be and the one whose daily actions you actually observe.`,
    faq: [
      {
        q: 'What does The Lovers mean in tarot?',
        a: `The Lovers is one of the Major Arcana's most significant cards, but its meaning is richer than its name suggests. Yes, it speaks to love, attraction, and deep connection — but its core theme is authentic choice: the capacity to choose from your truest values rather than from fear, habit, or external pressure. It represents the moment of genuine decision, particularly where that decision will define who you are. In relationship readings, it speaks to deep compatibility, real chemistry, and relationships built on genuine alignment rather than convenience. It's a card of both the heart and the conscience working together.`,
      },
      {
        q: 'Is The Lovers a yes or no card?',
        a: `Upright, The Lovers is generally a yes — especially for questions about relationships, partnerships, choices that align with your values, or situations where following your heart is appropriate. It's particularly affirmative for questions about whether a connection is genuine or whether a choice reflects who you really are. Reversed, it suggests that the situation is more complicated — there may be a misalignment, an unacknowledged conflict, or a temptation that doesn't actually serve you. In that case, it's less a no and more an invitation to be more honest with yourself before deciding.`,
      },
      {
        q: 'What does The Lovers mean in love?',
        a: `In love readings, The Lovers upright is one of the most positive cards you can receive — it suggests genuine chemistry, deep compatibility, and a connection that speaks to who you truly are rather than just circumstantial proximity. It can indicate the beginning of a significant relationship, a deepening of an existing bond, or confirmation that a particular person is a genuine match. The card's emphasis on authentic choice means it also affirms that being in this relationship reflects your real values. Reversed, it may point to unacknowledged incompatibility, dishonesty within the relationship, or difficulty committing fully.`,
      },
    ],
  },

  'the-chariot': {
    up2: `The Chariot's deeper teaching is about the kind of victory that requires integration rather than brute force. The two sphinxes pulling the chariot in the Rider-Waite image are black and white — opposing forces — and the charioteer holds no reins. The control is achieved through sheer force of will and the capacity to hold competing impulses in purposeful alignment rather than by suppressing one side. This is a crucial distinction: The Chariot doesn't win by eliminating opposition; it wins by directing it. Psychologically, this maps to the process of consciously holding your own contradictions — the part of you that wants to advance and the part that wants to retreat, the emotional urgency and the strategic patience — and moving forward anyway. This card often appears when you need to recognise that the opposing forces in your situation are not problems to be solved but energies to be harnessed.`,
    rev2: `The Chariot reversed can indicate a loss of direction and the sense of being pulled apart by competing demands or desires, with no clear principle of organisation to bring them into alignment. You may be forcing outcomes from a place of raw stubbornness rather than genuine conviction, or conversely, you may be surrendering control to circumstances and feeling dragged along rather than directed. There's also a warning about aggression: the charioteer's confident drive can tip into bulldozing when the card reverses, running roughshod over obstacles — including people — in ways that will cost more than they gain. The question the reversed Chariot always asks is: are you moving toward something meaningful, or simply away from something uncomfortable?`,
    love2: `In love, The Chariot reversed can indicate that willpower is being misapplied in relationship — trying to force connection, control dynamics, or steer a partner rather than allowing genuine mutual movement. A relationship can't be driven like a chariot; it requires two people moving together. It can also indicate that outside pressures — family, career, competing priorities — are pulling you in too many directions to give a relationship the focus it needs.`,
    career2: `Professionally, The Chariot reversed may signal drive that has become compulsion — working hard not from genuine ambition but from anxiety, proving something, or an inability to stop. Burnout often precedes or follows this card. It can also indicate a professional project that has lost momentum, facing obstacles that require a more flexible strategy than pure force. Sometimes you need to change course rather than simply push harder.`,
    spirit2: `Spiritually, The Chariot reversed raises the question of whether your spiritual ambition is serving genuine growth or feeding ego. The desire to advance, to achieve mastery, to win at the spiritual game can become its own obstacle. The card asks you to check your motivation: are you seeking transformation, or are you using spiritual practice as another arena for the competitive self to prove its worth?`,
    faq: [
      {
        q: 'What does The Chariot mean in tarot?',
        a: `The Chariot represents victory through disciplined will, self-mastery, and the capacity to direct opposing forces toward a single purpose. It's a card of determined forward movement — the kind that comes not from ignoring obstacles or internal conflict but from integrating and directing them. The charioteer doesn't suppress the two sphinxes; he aligns them through sheer force of focused intention. As a card, it speaks to ambition, willpower, overcoming challenges, and the kind of success that comes from not allowing circumstances or your own inner contradictions to knock you off course.`,
      },
      {
        q: 'Is The Chariot a yes or no card?',
        a: `Upright, The Chariot is a confident yes — particularly for questions about whether you can overcome a challenge, whether to push forward with a plan, or whether you have the determination to succeed. It's one of the most affirmative cards in the deck for questions about achieving difficult goals through sustained will and effort. Reversed, it leans more cautious — there may be obstacles ahead that require strategy rather than force, or your current approach may be more compulsive than truly directed. It suggests reconsidering your tactics before charging forward.`,
      },
      {
        q: 'What does The Chariot mean in love?',
        a: `In love, The Chariot upright can indicate pursuing a romantic interest with confidence, or a relationship that is moving forward with momentum and clear direction. It can suggest that overcoming obstacles to be together is entirely possible with genuine commitment. However, it's worth noting that the Chariot's energy is quite determined and focused — in love contexts, this energy works best when directed toward shared goals rather than toward controlling or steering a partner. Reversed in love, it may indicate that you're trying too hard to force a connection that needs to develop more naturally.`,
      },
    ],
  },

  'strength': {
    up2: `The Strength card is one of the tarot's most psychologically sophisticated teachings — it reframes power entirely. The woman in the traditional image doesn't fight the lion; she holds its jaws with bare hands and a serene expression, wearing a crown of flowers. This is the image of courage that doesn't require the suppression of fear or the eradication of the wild self, but rather a loving, confident relationship with your own instinctual nature. The lion represents everything typically deemed unacceptable: anger, appetite, sexuality, the raw animal self. Most people manage these forces through either suppression (the beast in a cage) or unrestrained expression (the beast runs riot). Strength offers a third option: gentle mastery through relationship. This requires genuine self-knowledge and a quality of self-acceptance that allows you to be with your own darkness without either condemning it or being consumed by it.`,
    rev2: `Strength reversed points to a breakdown in this relationship with the inner animal — usually in one of two directions. The first is excessive self-control: a harsh, punitive approach to your own instincts and desires, an attempt to be more than human by denying the animal aspects of your nature. This tends to produce rigidity, shame around normal human needs, and eventually an explosive surfacing of everything that was forced below. The second expression is the opposite: a capitulation to impulse, a state where the lion is entirely running the show — reactivity, compulsive behaviour, emotional flooding. In both cases, the card is asking the same thing: what would it mean to be in a genuinely compassionate and honest relationship with yourself, including the parts you find least acceptable?`,
    love2: `In love, Strength reversed can indicate that fears, insecurities, or old wounds are running the relationship rather than genuine choice. You may be acting from the lion — reactive, jealous, controlling — rather than from the wise, compassionate self who holds it. Alternatively, you may be so tightly controlled that genuine passion and vulnerability are inaccessible. Real intimacy requires both: the lion's aliveness and the woman's wisdom to hold it well.`,
    career2: `Professionally, Strength reversed often appears when fear is driving behaviour at work — whether that's aggression under pressure, compulsive overworking, or a paralysis born of anxiety about not being enough. It can also indicate a workplace that demands constant emotional suppression, creating a slow accumulation of pressure that eventually needs an outlet. Honest examination of the emotional climate of your work life is warranted.`,
    spirit2: `Spiritually, Strength reversed invites examination of self-flagellation dressed up as discipline. Harsh inner voices, excessive spiritual ambition, and a punitive relationship to your own failures are all signs that the feminine wisdom of this card has been replaced by something harder and less forgiving. True spiritual strength includes tenderness toward yourself.`,
    faq: [
      {
        q: 'What does Strength mean in tarot?',
        a: `The Strength card represents courageous, compassionate inner power — specifically, the capacity to be in a loving, wise relationship with your own instinctual and emotional nature rather than either suppressing or being ruled by it. Depicted traditionally as a woman gently mastering a lion, it speaks to the kind of courage that doesn't require brute force or emotional suppression, but rather a deep self-knowledge and genuine self-acceptance. It's a card of resilience, inner authority, patience, and the wisdom to meet your own darkness with understanding rather than condemnation. It often appears when endurance and inner calm are more needed than outer action.`,
      },
      {
        q: 'Is Strength a yes or no card?',
        a: `Upright, Strength is a yes — particularly for questions about whether you have what it takes to endure, overcome, or persevere through a difficult situation. It affirms your inner resources and capacity for patient, compassionate action even under pressure. It's especially affirmative for situations that require emotional intelligence, self-regulation, or courage that isn't brash. Reversed, it suggests that there are inner obstacles — fear, self-doubt, compulsive patterns — that need addressing before you can act from your genuine strength. Not a no, but a signal to do some inner work first.`,
      },
      {
        q: 'What does Strength mean in love?',
        a: `In love, Strength upright is a beautiful card — it suggests a relationship in which both people can bring their full, authentic selves without fear of rejection, and where genuine courage and compassion characterise how difficulties are handled. It can indicate that you have the inner resources to navigate a challenging relationship moment without either shutting down or overreacting. It may also be asking you to extend compassion toward a partner's struggles — to hold their lion as well as your own. Reversed in love, it points to fear-based reactivity, control issues, or emotional unavailability.`,
      },
    ],
  },

  'the-hermit': {
    up2: `The Hermit stands on a mountain peak holding his lantern — not pointing it outward in a gesture of guidance (though that reading exists) but using it to illuminate the ground immediately ahead. This is a card of focused, solitary illumination: the understanding that comes only through genuine withdrawal from the noise of collective life. The Hermit has earned his altitude through genuine ascent — this is not escapism but the particular clarity that comes from having walked a long path and then turned to look back at it with honest eyes. Psychologically, this is the archetype of the inner life, of introversion as a wisdom practice rather than a social deficiency, of the person who knows that certain truths are only accessible in stillness. When he appears, he frequently signals a need for deliberate solitude — not avoidance of others, but the creation of genuine inner space.`,
    rev2: `The Hermit reversed can manifest as either forced isolation or its opposite: an inability to tolerate being alone with yourself long enough for genuine insight to surface. The first expression sees someone withdrawn not through wisdom but through fear of the world — using the mountain as a hiding place rather than a vantage point. The second is a restless, distraction-seeking avoidance of the inner life, a compulsive filling of silence with noise, scroll, and company because genuine solitude feels threatening. In either case, the relationship with your own interior has become dysfunctional. The reversed Hermit also sometimes indicates that a period of necessary isolation has gone on too long and is now becoming a protective cage rather than a restorative retreat.`,
    love2: `In love, The Hermit reversed can indicate a withdrawal from intimacy that has crossed from healthy independence into emotional unavailability. Someone who is genuinely unable to let another person into their inner world will struggle to sustain deep connection. Conversely, it can signal an inability to be alone — a fearful clinging to relationship as avoidance of one's own company. Both patterns are asking for the same thing: a more honest relationship with yourself before a genuinely mutual relationship with another becomes possible.`,
    career2: `Professionally, The Hermit reversed may signal isolation that isn't serving you — working too much alone, avoiding collaboration, or withdrawing from professional communities in ways that are limiting your growth. It can also indicate the opposite: a frenetic busyness that prevents the kind of deep focus and reflection that your best work actually requires. The card asks whether you have adequate solitude in your professional life and whether you're using it wisely.`,
    spirit2: `Spiritually, The Hermit reversed points to a practice that has become isolated from life — wisdom that stays safely in the cave and never gets walked back down the mountain to meet the world. Genuine spiritual development eventually moves outward as well as inward: the insights gained in solitude need to be tested, lived, and shared. A spirituality that only functions in retreat isn't yet fully formed.`,
    faq: [
      {
        q: 'What does The Hermit mean in tarot?',
        a: `The Hermit represents the wisdom that comes from solitude, introspection, and a deliberate turning inward. He is the archetype of the inner sage — the part of you that holds hard-won understanding and can illuminate the path forward, but only in quiet, away from the crowd. He represents retreat not as escapism but as a necessary phase of integration and deepening. When he appears, he often signals that you need — or are already in — a period of genuine withdrawal for the purpose of honest self-reflection. He's associated with soul-searching, inner guidance, spiritual seeking, and the slow accumulation of genuine wisdom.`,
      },
      {
        q: 'Is The Hermit a yes or no card?',
        a: `The Hermit is neither a clear yes nor a clear no — he is primarily a card of timing and process. His message is almost always "not yet" or "go within before deciding." He suggests that the insight you need to make this decision wisely hasn't fully arrived yet, and that forcing an answer prematurely will produce a less wise outcome than taking time for genuine reflection. If your question is "should I take time to think before acting?" his answer is an unambiguous yes. For external action questions, he's asking for patience and inner consultation first.`,
      },
      {
        q: 'What does The Hermit mean in love?',
        a: `In love, The Hermit upright can suggest a need for space and solitude within or alongside a relationship — time to understand your own needs and patterns before they become relationship problems. It can indicate a period of intentional withdrawal for reflection, or the presence of a solitary, introspective partner whose inner life is rich but private. It sometimes appears when someone needs to spend time alone before they're truly ready to partner. Reversed in love, it may indicate emotional withdrawal becoming unavailability, or an inability to tolerate solitude that creates unhealthy dependency.`,
      },
    ],
  },

  'wheel-of-fortune': {
    up2: `The Wheel of Fortune operates on a level beyond personal will — it is the card of cycles, flux, and the patterns larger than any individual life that nonetheless shape it profoundly. The four figures in the corners of the Rider-Waite image — the bull, eagle, lion, and angel — are fixed, reading their books, while the wheel turns: suggesting that underneath the apparent randomness of fate, there is a comprehensible order. This is a card that invites contemplation of timing: not every difficulty is a failure, not every windfall is permanent, not every stagnation means something is broken. All of it is the wheel moving. Psychologically, the deeper work this card points to is developing what Stoics called amor fati — not mere acceptance of change, but something closer to active love of the flux that is the very nature of existence. This requires relinquishing the fantasy of a life without reversals.`,
    rev2: `The Wheel of Fortune reversed often signals someone fighting the natural movement of cycles — resisting an ending that needs to happen, clinging to a chapter that the wheel has already moved past, or refusing to act during a turning point because change feels threatening. It can also indicate a sense of being a passive victim of circumstances, a belief that outcomes are determined by forces entirely beyond your influence — forgetting that while you don't control the wheel, you do control how you meet it. In some readings, it indicates a run of genuinely poor luck or timing, and the honest message is simply to wait: this particular cycle hasn't finished turning yet, and forcing a move now is likely to compound difficulty rather than resolve it.`,
    love2: `In love, The Wheel of Fortune reversed can indicate that a relationship is stuck in a repetitive cycle — the same argument, the same pattern of distance and reconnection, the same dynamic despite surface changes. The wheel is turning but you're arriving at the same point. It can also signal that a relationship is ending as part of a natural cycle, and the resistance to that ending is creating more suffering than the ending itself would. Honest assessment of what's truly changing and what isn't is needed.`,
    career2: `Professionally, The Wheel of Fortune reversed often appears during a run of difficult timing — opportunities missed, projects stalled, circumstances conspiring in unhelpful directions. It can indicate that the professional cycle you're in hasn't yet turned toward the upswing, and patience is genuinely required. It can also point to a failure to adapt to changing conditions — insisting on strategies that worked in a previous cycle rather than reading and responding to where things actually are now.`,
    spirit2: `Spiritually, The Wheel of Fortune reversed invites examination of your relationship to impermanence. A resistance to the wheel's turning is ultimately a resistance to the nature of existence itself — and this resistance is the root of a great deal of suffering. The spiritual work here is not resignation but genuine acceptance: letting life be the cyclical, unpredictable, profoundly non-linear experience it actually is.`,
    faq: [
      {
        q: 'What does the Wheel of Fortune mean in tarot?',
        a: `The Wheel of Fortune is the Major Arcana's great card of cycles, change, and fate. It represents the ever-turning wheel of life — the understanding that everything is in constant flux, that fortune rises and falls, that circumstances change, and that no current situation (good or bad) is permanent. It speaks to timing, to the patterns that operate beyond individual will, and to the deeper order underlying apparent randomness. When it appears, it often signals an important turning point — a moment when the wheel is visibly moving and change, whether welcome or not, is underway.`,
      },
      {
        q: 'Is the Wheel of Fortune a yes or no card?',
        a: `Upright, the Wheel of Fortune tends toward yes — particularly suggesting that circumstances are moving in a favourable direction and that timing is on your side. It carries an energetic of good luck, fortunate timing, and things working out. Reversed, it cautions that timing may be off — circumstances may not yet be aligned in your favour, and patience may serve better than pressing forward now. However, it's important to remember that the wheel always turns: a reversed Wheel doesn't mean permanent bad fortune, only that the current cycle hasn't yet completed its downward arc.`,
      },
      {
        q: 'What does the Wheel of Fortune mean in love?',
        a: `In love, the Wheel of Fortune upright is generally positive — it suggests that relationship circumstances are moving and that new chapters are opening. For those seeking love, it can indicate that fortunate timing is bringing someone significant into your orbit. For those in relationships, it may signal a turning point — a natural evolution in the connection. Reversed in love, it can indicate a stagnant relationship caught in repetitive patterns, or a moment of poor timing — wanting things to move faster or differently than they naturally will right now. Patience and honest assessment of actual patterns are advised.`,
      },
    ],
  },

  'justice': {
    up2: `Justice is not primarily a card about external legal proceedings, though it certainly applies there. At its deeper level, it represents the principle of cause and effect operating in human life — the understanding that actions have consequences, that patterns have origins, and that honest reckoning with both is the only foundation for genuine change. The figure of Justice is often depicted with a veil — suggesting that true justice transcends immediate appearances and requires the kind of discernment that sees clearly through both self-deception and the sympathetic distortions of bias. This card asks for ruthless honesty about your own role in current circumstances — not self-blame, but clear-eyed accountability. It also carries a reassurance: when you have genuinely acted with integrity, you don't need to manage outcomes. The scales will find their balance. Trust in the long arc of consequence is one of Justice's most significant gifts.`,
    rev2: `Justice reversed points to situations where accountability is being avoided, where truth is being managed rather than told, or where consequences are being delayed through rationalisation or denial. This can be an external situation — an unjust outcome, a system that isn't working fairly, a person who isn't being held accountable — or it can be an internal pattern: the ways you avoid honest reckoning with your own choices and their effects. It can also indicate a harsh, punitive approach to justice — all punishment and no mercy, rule without wisdom. The reversed Justice is rarely comfortable, but its discomfort is almost always informative. Whatever is being avoided or distorted here will eventually demand reckoning.`,
    love2: `In love, Justice reversed can indicate an imbalance in fairness within a relationship — one person consistently carrying more responsibility, making more sacrifices, or being less honest. It can also point to a refusal to acknowledge the impact of your own behaviour on a partner, or to accept accountability for patterns that are harming the relationship. Sometimes it signals lingering resentment from a past injustice that is poisoning present connection. Honest, unflinching conversation about what is and isn't fair is needed.`,
    career2: `Professionally, Justice reversed can indicate a workplace or industry that isn't operating fairly — biased decisions, lack of transparency, consequences that don't match actions. It can also signal a situation where you're being asked to make or accept a decision that your conscience can't fully endorse. Trust that discrepancy: if something feels fundamentally unfair or dishonest, the reversed Justice is affirming that your perception is probably accurate.`,
    spirit2: `Spiritually, Justice reversed points to an imbalance between the principles you claim to hold and the life you're actually living. Real spiritual maturity requires a willingness to examine your own motivations honestly, to accept the consequences of your choices without playing the victim, and to bring genuine consistency between inner belief and outer behaviour. Where is the gap between who you aspire to be and who you're actually showing up as?`,
    faq: [
      {
        q: 'What does Justice mean in tarot?',
        a: `Justice represents truth, accountability, cause and effect, and fair outcome. It's the principle that actions have consequences, that patterns have origins, and that honest reckoning is both necessary and ultimately clarifying. The figure of Justice holds scales (weighing evidence fairly) and a sword (the capacity to cut through confusion to truth). It speaks to legal matters, ethical decisions, and situations requiring honest self-assessment. It's also a card of reassurance: when you've acted with genuine integrity, the scales will eventually find their balance. Trust in consequence is one of Justice's central gifts.`,
      },
      {
        q: 'Is Justice a yes or no card?',
        a: `Upright, Justice is a conditional yes — affirming that the situation will resolve fairly if you approach it with honesty and integrity. It's particularly affirmative for legal matters, situations requiring a fair decision, and questions about whether truth will prevail. Reversed, it cautions that something is out of alignment — either circumstances aren't as fair as they should be, or there's something in your own approach that needs examination. It rarely gives a clean no; rather, it asks for greater honesty about what's really happening before an accurate answer is possible.`,
      },
      {
        q: 'What does Justice mean in love?',
        a: `In love, Justice upright speaks to relationships built on genuine fairness, mutual respect, and honest communication — partnerships where both people show up with accountability and care. It can indicate a moment of honest reckoning in a relationship: a necessary conversation about what's actually working and what isn't, conducted with clarity and without blame. It can also affirm that a past hurt will be addressed fairly. Reversed in love, it points to imbalances in fairness, dishonesty, or a reluctance to take genuine accountability for your impact on a partner or the relationship.`,
      },
    ],
  },

  'the-hanged-man': {
    up2: `The Hanged Man is one of the tarot's most counterintuitive teachings — a card about the wisdom of voluntary surrender, of choosing to stop in a world that relentlessly demands motion. The figure hangs willingly (his expression is serene, not anguished) from a living tree by one foot, the other leg crossed comfortably. His halo indicates illumination; his suspension indicates pause. The deeper teaching is that certain insights are structurally inaccessible from the normal vantage point of doing, striving, and managing outcomes. You have to go upside-down to see them — to give up the orientation that usually governs your approach and allow a genuinely new perspective to emerge. This is not defeat. It is the deliberate sacrifice of the ego's usual control strategies in service of something that will prove more valuable than anything those strategies could have produced.`,
    rev2: `The Hanged Man reversed can indicate a refusal to pause — an insistence on keeping moving precisely because the stillness would be too revealing. There's often something being avoided in the compulsion to keep acting, and this card in reverse is asking you to look at what that is. It can also indicate a suspension that has gone on too long and is no longer productive: a limbo state that once held potential for insight but has become merely stuck — waiting rather than genuinely pausing, stagnation rather than contemplation. The distinction between productive waiting and merely avoiding decision is important to discern here. Ask yourself honestly: am I in this pause because something important is forming, or because I'm afraid of what committing to a direction will cost me?`,
    love2: `In love, The Hanged Man reversed can indicate a relationship trapped in an indefinite holding pattern — neither progressing nor ending, with both parties in suspended animation around a decision that actually needs to be made. It can also signal a refusal to examine your own patterns: the thing that would shift the relationship is an honest look at what you yourself are bringing to it, and that look is being avoided. Sometimes it points to a relationship that needs a genuine sacrifice — not martyrdom, but a willingness to let go of something that isn't serving either person.`,
    career2: `Professionally, The Hanged Man reversed often appears when someone is stuck in a waiting mode — expecting a breakthrough without having genuinely paused to gain the new perspective that would make breakthrough possible. It can also indicate that a voluntary pause is needed but being resisted: a sabbatical, a deliberate slowing down, a step back from constant doing would be genuinely regenerative, but the ego won't allow it. The refusal to stop is, paradoxically, what's keeping you stuck.`,
    spirit2: `Spiritually, The Hanged Man reversed points to an attachment to understanding before surrendering — wanting to know what the pause is for before consenting to it. But the insight this card offers can only be received in the actual experience of suspension, not in advance of it. The spiritual challenge is allowing not-knowing to be genuinely okay; to trust the process of your own unfolding even when you can't see where it leads.`,
    faq: [
      {
        q: 'What does The Hanged Man mean in tarot?',
        a: `The Hanged Man is the Major Arcana's card of willing suspension, sacrifice, and the insights that only become available when you choose to stop. The figure hangs serenely by one foot from a living tree — suggesting a chosen, purposeful pause rather than defeat. He represents the understanding that certain perspectives are only accessible when you relinquish your normal orientation and allow yourself to see things differently. It's a card of waiting with purpose, of sacrifice that leads to illumination, and of the wisdom that comes not from doing more but from genuinely stopping. When he appears, a pause is usually being called for.`,
      },
      {
        q: 'Is The Hanged Man a yes or no card?',
        a: `The Hanged Man is one of the tarot's most clearly "not yet" cards in yes/no readings. His energy is one of suspension, waiting, and perspective-shifting — not of action or forward movement. He suggests that the answer you're looking for isn't available yet, and that pressing for one prematurely will not serve you. In a practical sense, his answer to "should I do this now?" is almost always "wait." However, this waiting is meant to be productive: use the pause to gain the new perspective that will make your eventual decision wiser than it would be right now.`,
      },
      {
        q: 'What does The Hanged Man mean in love?',
        a: `In love, The Hanged Man upright can indicate a relationship pause — a breathing space that allows both people to gain perspective. It may suggest that you need to stop trying to fix or manage a connection and simply be present within it for a while. It can also indicate a necessary sacrifice in the context of love: letting go of a fixed idea about what a relationship should look like in order to see what it actually is. Reversed in love, it often points to a holding pattern that has stalled — a relationship neither moving forward nor resolving, stuck in avoidance of a necessary decision.`,
      },
    ],
  },

  'death': {
    up2: `The Death card is the tarot's most misunderstood and, in many ways, its most philosophically rich card. It almost never indicates physical death — instead, it represents the principle of transformation through ending: the understanding that genuine renewal requires something to actually die first. The skeleton knight rides a white horse (purity of change, not threat) and before him, all human conditions are equal — king and child, bishop and maiden. This is the great leveller: no life remains untouched by endings. The deeper teaching is that we cannot receive what comes next if we haven't genuinely released what's past. Incomplete griefs, avoided endings, clinging to chapters that are finished — these create the stagnation that Death, at its healthiest, comes to dissolve. The card asks what you are ready to release completely, not merely in words but in genuine inner letting go.`,
    rev2: `Death reversed most commonly indicates resistance to a necessary ending — a clinging to something (a relationship, identity, belief, phase of life) that has genuinely run its course, refusing to acknowledge the ending that is already in progress. This resistance is rarely conscious; it often presents as hope that things will change back, or as a frantic redoubling of effort to resuscitate what is no longer alive. It can also indicate stagnation: an inability to move through a transition because the grief of the ending hasn't been genuinely processed. Sometimes the card reversed signals the opposite — a transformation that has been forced too quickly, without adequate grieving of what was lost. The message in either case is the same: real change requires genuine passage, not shortcuts or avoidance.`,
    love2: `In love, Death reversed often signals a relationship that has effectively ended but hasn't been formally completed — both people remaining in the structure of connection while the actual living heart of it has already departed. Or it can indicate someone stuck in grief over a past relationship, unable to genuinely let go and therefore unable to be fully present to what might come next. Real transformation in love requires the courage to acknowledge when something is truly finished.`,
    career2: `Professionally, Death reversed can point to staying in a role, career, or company well past the point where it was serving your genuine development — through fear of change, financial anxiety, or sheer habit. The chapter is complete; what you needed from this environment, you've received. Remaining now is costing you more than leaving would. It can also indicate resistance to change within an organisation — the refusal to adapt to genuinely new conditions because the old way feels safer.`,
    spirit2: `Spiritually, Death reversed invites examination of old identities and beliefs you're still carrying that no longer reflect your actual understanding. Spiritual growth inevitably requires dying to previous versions of yourself — the beliefs that served you at one stage of life may become constraints in the next. The card asks what version of yourself you're holding on to that you've actually already outgrown.`,
    faq: [
      {
        q: 'What does Death mean in tarot?',
        a: `Despite its dramatic imagery, the Death card almost never indicates physical death in a reading. It is fundamentally a card of transformation through endings — the principle that genuine renewal requires something to genuinely conclude first. The skeleton on a white horse before whom all social conditions are equal represents the great leveller of change: no life remains in one form forever. As a card, Death asks what needs to end in your life so that something genuinely new can begin. It speaks to transitions, completions, letting go, and the courage required to close a chapter that is genuinely finished.`,
      },
      {
        q: 'Is Death a yes or no card?',
        a: `In yes/no readings, Death upright is typically a no to continuity but a yes to transformation. If you're asking "will things stay as they are?" — no. If you're asking "is this the right time to make a major change or let something go?" — possibly yes, particularly if that change has been building for some time. Reversed, Death tends to say no to the transformation being resisted: whatever ending you're trying to avoid is either not yet complete or is being made harder by your resistance to it. It suggests that facing and processing the ending will ultimately serve better than continued avoidance.`,
      },
      {
        q: 'What does Death mean in love?',
        a: `In love readings, Death most commonly signals transformation rather than loss — the end of one phase of a relationship and the beginning of something genuinely different. It can indicate a relationship undergoing deep change, shedding old patterns to allow something more authentic to emerge. It can also, honestly, signal the genuine ending of a relationship — but even then, it is asking you to honour the ending properly so that both people can move forward. Reversed in love, it often indicates an inability to let go of a relationship or person who is no longer truly present in your life.`,
      },
    ],
  },

  'temperance': {
    up2: `Temperance is one of the tarot's most quietly profound cards — an image of patient alchemy rather than dramatic transformation. The angel in the Rider-Waite image pours liquid between two cups, one foot on land and one in water, standing at the boundary between the earthly and the spiritual. The flowing between cups is not mixing but blending — a continuous, patient process of integration. The card speaks to the art of holding opposites in productive relationship rather than forcing them into resolution: the active and the receptive, the rational and the intuitive, the personal and the universal. What Temperance achieves cannot be rushed or forced; it requires sustained engagement with the process itself rather than fixation on the outcome. This is why the card is associated with patience: not a passive waiting but an active, engaged trust in the alchemy of time when you're genuinely participating in the work.`,
    rev2: `Temperance reversed points to a loss of balance — an excess in one direction that is disrupting the patient alchemical process. This is often literal: overindulgence, compulsive behaviour, an inability to moderate something (consumption, work, emotional intensity) that is creating real disruption. It can also indicate an imbalance in how you're approaching a situation: all fire and no water, or all restraint and no vitality. There may be a forced quality to an attempted integration — trying to rush synthesis that needs time, or imposing a false harmony on a situation that actually requires honest acknowledgment of genuine conflict. The underlying message is almost always about returning to patience, flow, and honest examination of where excess has developed.`,
    love2: `In love, Temperance reversed can indicate a relationship where the balance has been disrupted — too much togetherness, too much distance, unequal investment, or the gradual erosion of easy flow between two people. It can also signal that one or both people are trying to force a specific outcome (a commitment, a reconciliation, a particular shape of relationship) rather than allowing the connection to develop at its natural pace. What's needed is a return to patient, attentive, genuinely mutual engagement.`,
    career2: `Professionally, Temperance reversed often manifests as work-life imbalance that has reached a genuinely unsustainable point — chronic overwork, inability to recover, the blurring of all boundaries between work and rest. It can also appear when a long-term project is being rushed, when synthesis is being forced before the constituent elements are ready, or when patience with a process has completely run out in ways that are beginning to compromise the quality of what's being built.`,
    spirit2: `Spiritually, Temperance reversed invites honest examination of spiritual imbalance — too much discipline, too little devotion; too much feeling, too little discernment; too focused on transcendence to remain grounded in ordinary life. True spiritual integration finds the middle path not by avoiding both extremes but by consciously inhabiting the space between them. Where have you drifted from that balanced centre?`,
    faq: [
      {
        q: 'What does Temperance mean in tarot?',
        a: `Temperance represents balance, patience, moderation, and the slow alchemy of integration. The angel pouring liquid between two cups embodies the idea of blending opposites through patient, sustained process — not forcing resolution but allowing genuine synthesis to emerge over time. It's associated with healing, the middle path, healthy habits, and the kind of long-term project that requires consistent, moderate engagement rather than intense bursts. As a card, it often appears when you need to slow down, moderate an excess, or trust a gradual process that you may be tempted to rush. It is a card of flow rather than force.`,
      },
      {
        q: 'Is Temperance a yes or no card?',
        a: `Upright, Temperance is a gentle yes — particularly for questions about whether patience will be rewarded, whether a slow-developing situation will eventually come good, or whether the moderate, measured approach is the right one. It's affirmative for questions about healing, long-term projects, and situations requiring sustained effort rather than dramatic action. Reversed, it cautions that something is out of balance and needs correcting before progress can be made. It's less a no than a "not like this" — suggesting that the current approach or pace needs adjustment before the answer can be a clean affirmative.`,
      },
      {
        q: 'What does Temperance mean in love?',
        a: `In love, Temperance upright is a genuinely lovely card — suggesting a relationship characterised by ease, balance, and the kind of patient, attentive care that allows love to deepen steadily over time. It speaks to compatibility that doesn't require drama to sustain itself, and to a partnership where both people can flow between closeness and independence without disruption. It can also indicate healing within a relationship — the slow, patient work of restoring trust or tenderness after difficulty. Reversed in love, it points to imbalance, rushed decisions, or a relationship that has lost its easy flow.`,
      },
    ],
  },

  'the-devil': {
    up2: `The Devil card is the tarot's most psychologically illuminating image — and arguably its most important for self-examination. The Baphomet figure presides over two chained figures, but look closely at the Rider-Waite image: the chains around the couple's necks are loose. They could remove them. They stay not because they must but because something about the captivity is serving them — comfort, familiarity, the numbing of some deeper pain. This is the card's central teaching: the most significant bondages in human life are chosen, maintained by the parts of us that prefer a known constraint to an unknown freedom. The Devil represents all forms of compulsion, addiction, and self-limitation that are sustained by a lie we tell ourselves about our own helplessness. When he appears, it is almost never to condemn but to illuminate: what are you staying chained to, and what story about yourself makes that staying seem necessary or inevitable?`,
    rev2: `The Devil reversed is one of the more hopeful reversals in the deck — it often signals a genuine awakening to a pattern that has held you captive, and the beginning of movement toward freedom. The chains are being noticed, perhaps for the first time with clear eyes. This is rarely comfortable; liberation from a pattern you've been unconsciously maintaining always involves the discomfort of honest reckoning with your own participation in it. The card can also indicate a pattern not yet released but beginning to weaken — addictions in early recovery, compulsions that are becoming conscious, relationships that are being examined more honestly. Less positively, the reversed Devil can sometimes signal a suppression of healthy instincts dressed up as liberation, or the exchange of one form of bondage for another.`,
    love2: `In love, The Devil reversed can signal the beginning of release from an unhealthy relationship pattern — codependency, toxic attraction, staying with someone for reasons that don't actually serve either person. There may be an awakening to how much your own fears and wounds have been driving relationship choices. The path forward involves genuine honesty about the role your own patterns play in the dynamics you find yourself in — compassionately and without self-flagellation.`,
    career2: `Professionally, The Devil reversed can indicate the beginning of release from work arrangements that have been draining rather than sustaining — a toxic workplace culture, an exploitative dynamic, or a career driven by fear or compulsion rather than genuine motivation. There's an awakening to how much external factors have been controlling your professional life. The invitation is to move gradually toward work that is genuinely chosen rather than merely defaulted into.`,
    spirit2: `Spiritually, The Devil reversed points to the early stages of shadow work — the process of making conscious what has been operating in the darkness. Becoming aware of your own compulsions, reactive patterns, and unconscious defences is not comfortable, but it is genuine spiritual progress. True freedom in the spiritual sense comes not from transcending the shadow but from honestly meeting it.`,
    faq: [
      {
        q: 'What does The Devil mean in tarot?',
        a: `The Devil card represents bondage, compulsion, addiction, and the specific lie that you have no power to change your situation. The crucial detail in the traditional imagery is that the chains binding the two figures are loose — they could remove them. This speaks to the card's core message: most of the significant limitations in human life are not imposed from outside but are unconsciously chosen and maintained from within. The Devil invites examination of what you're staying chained to — patterns, relationships, substances, beliefs about yourself — and the honest question of what that captivity is actually providing that makes you keep choosing it.`,
      },
      {
        q: 'Is The Devil a yes or no card?',
        a: `Upright, The Devil is generally a no — particularly for questions about whether a situation is healthy, whether a compulsive behaviour or pattern should be continued, or whether a tempting option is actually wise. He's asking you to look more carefully at what's driving the choice before committing. Reversed, the answer shifts toward a cautious yes, particularly for questions about whether it's possible to break a pattern, leave a limiting situation, or regain agency over something that has felt compulsive. He affirms that freedom is genuinely possible, though the work of achieving it is real.`,
      },
      {
        q: 'What does The Devil mean in love?',
        a: `In love, The Devil upright most commonly points to unhealthy patterns — compulsive attraction to people who aren't good for you, staying in a relationship for the wrong reasons, toxic or codependent dynamics, or a relationship in which one or both people are behaving in ways driven by fear, insecurity, or addiction. It's not a pleasant card to receive in a love reading, but it's a valuable one: it's asking you to examine what is actually happening in this connection beneath the surface of what you prefer to see. Reversed in love, it can indicate the beginning of genuine release from a destructive pattern.`,
      },
    ],
  },

  'the-tower': {
    up2: `The Tower is the card most people dread and most misunderstand. Yes, it represents sudden disruption, the collapse of structures that can no longer stand — but the crucial question is: what were those structures built on? The Tower falls because its foundations are inadequate — pride, illusion, a false security built on sand. The lightning bolt is not punishment; it's revelation. What the Tower destroys was always going to fail; the only question was when and how. This card carries a fierce mercy: it removes what cannot serve genuine growth regardless of how much you've invested in it. The two figures falling from the tower in the Rider-Waite image are the crown and the people who lived inside it — the ego's constructs and the identities built upon them. After the Tower, the ground is cleared. The aftermath is not what the card is about; the aftermath is what becomes possible once the necessary clearing has happened.`,
    rev2: `The Tower reversed can indicate that a necessary disruption is being delayed — the structures that need to fall are still standing through a combination of desperate maintenance and avoidance. The energy of collapse is present but being held back, and this holding back often costs more than the collapse itself would. It can also indicate that a Tower moment has occurred internally without external expression — a private shattering, a profound disorientation, a crisis of faith or identity that hasn't yet been acknowledged or spoken. Sometimes the reversed Tower signals that a disruption has already occurred and you are now in the aftermath: the smoke is clearing, and the question is what you will build on the cleared ground.`,
    love2: `In love, The Tower reversed can signal that an existing relationship has already gone through its Tower moment — a revelation or confrontation that fundamentally changed the landscape — but the aftermath hasn't been properly processed. It can also indicate a relationship built on illusions that are beginning to crack, with the full revelation not yet arrived but approaching. Honest examination of what your relationship is actually built on, rather than what you hope it's built on, is genuinely needed.`,
    career2: `Professionally, The Tower reversed may indicate a situation teetering at the edge of disruption — a company, role, or industry in genuine instability that hasn't yet collapsed but is showing structural weakness. It can also signal that a necessary professional change is being resisted, and that the energy of that resistance is becoming increasingly costly. Sometimes it indicates that you are already in the aftermath of a significant professional disruption and are trying to rebuild without having fully assessed what went wrong.`,
    spirit2: `Spiritually, The Tower reversed points to a crisis of faith or worldview that is unfolding gradually rather than suddenly — a slow erosion of a belief system that no longer holds, without the clean break of a sudden Tower moment. The spiritual work here is courage: allowing the structures that no longer serve genuine understanding to fall, even when the collapse feels devastating, trusting that clearer ground awaits below.`,
    faq: [
      {
        q: 'What does The Tower mean in tarot?',
        a: `The Tower represents sudden disruption, revelation, and the collapse of structures built on inadequate foundations. The lightning bolt that strikes the tower reveals what was always true: this building could not stand. As a card, it speaks to unexpected upheaval, forced change, the shattering of illusions, and the kind of crisis that reveals truth beneath comfortable fictions. It is often feared but frequently misunderstood: the Tower doesn't destroy what was good; it removes what was always going to fail. It clears ground for something more genuinely solid to be built. The aftermath of a Tower moment, painful as it is, is often the beginning of more authentic life.`,
      },
      {
        q: 'Is The Tower a yes or no card?',
        a: `Upright, The Tower is generally a no for questions about stability and continuation, but a complex yes for questions about change, disruption, and clearing away what isn't working. If you're asking whether a current structure will hold — no. If you're asking whether change is coming — yes. Reversed, it suggests that disruption may be delayed or internal rather than immediate and external, but the energy of necessary change is present. It's worth asking whether your "no to disruption" is actually serving you, or whether you're prolonging the inevitable at significant cost.`,
      },
      {
        q: 'What does The Tower mean in love?',
        a: `In love, The Tower upright is one of the more confronting cards — it often signals a sudden revelation or disruption in a relationship: an unexpected revelation, a conflict that brings hidden truths to light, or a sudden ending of something that appeared stable. This is rarely comfortable, but it is frequently clarifying: what emerges after a Tower moment in love is usually more honest than what existed before it. Sometimes the Tower in love clears the way for a genuinely better foundation; sometimes it signals that this relationship cannot be rebuilt. Reversed, it often points to a relationship in which necessary truths are being avoided.`,
      },
    ],
  },

  'the-star': {
    up2: `The Star follows The Tower and The Devil in the tarot sequence — and this positioning is meaningful. She arrives after the shattering, after the chains, as the first genuinely clear night sky. She is a card of restoration and hope, but not naive hope: the hope that comes after you've genuinely been through the dark and found, on the other side of it, that something essential remains intact. The nude woman kneeling at the water pours simultaneously into a pool and onto land — she is generous because she trusts the source will replenish her. This is the card's central spiritual teaching: radical trust in the generative, restorative nature of life itself. The Star doesn't promise that nothing hard will happen; she offers something different — the knowledge that beneath the upheaval, there is a living source that remains reliable, that genuine renewal is always possible, that the self can be restored without pretending the darkness didn't happen.`,
    rev2: `The Star reversed points to a deficit of hope and the particular kind of exhaustion that comes when you've been waiting for renewal and it hasn't arrived. This card reversed can indicate genuine despair — a state in which the ability to trust in positive possibility has been depleted by accumulated difficulty or disappointment. It can also manifest as a more subtle cynicism: a guarding against hope because hope has been disappointed before, a refusal to allow yourself to want things fully. There may also be a disconnect from a sustaining sense of meaning or purpose — the feeling that your guiding star has gone out. The invitation of this card reversed is not false positivity but honest grief about what has felt dark, followed by a genuine search for what remains worth trusting.`,
    love2: `In love, The Star reversed can indicate a weariness around romantic hope — a guardedness born of past hurt, a difficulty believing that something genuinely nourishing is possible for you. It can also signal a relationship that has lost its sense of genuine possibility and renewal, where both people feel slightly dimmed, going through motions rather than genuinely illuminated by each other. The invitation is to examine honestly whether the light is genuinely gone or whether it can be kindled again.`,
    career2: `Professionally, The Star reversed can indicate a loss of inspiration and sense of purpose in your work — the vision that once sustained you has dimmed, and what remains feels mechanical or uninspiring. Burnout and disillusionment both appear with this card. It can also indicate a creative block that is rooted not in lack of ability but in a disconnection from the deeper motivation that your work once carried. Finding or remembering what genuinely calls you is the real work here.`,
    spirit2: `Spiritually, The Star reversed points to a dark night of the soul — a period in which the sustaining sense of connection to something meaningful and larger has become inaccessible. This is one of the most significant, if least comfortable, experiences in genuine spiritual development. Rather than resolving it prematurely with forced positivity, allow it to be what it is: a genuine reckoning that, honestly moved through, typically opens into a more grounded and authentic faith.`,
    faq: [
      {
        q: 'What does The Star mean in tarot?',
        a: `The Star is the tarot's card of hope, renewal, and inspired trust in life's restorative capacity. Following the devastation of The Tower in the sequence, she represents the clear sky after the storm — the discovery that even after significant difficulty, something essential remains and can be rebuilt. The woman pouring water simultaneously into a pool and onto the earth represents the generosity that flows naturally from genuine trust in the source. She speaks to healing, renewed faith, creative inspiration, a sense of guiding purpose, and the particular quality of hope that has survived difficulty and become stronger for it.`,
      },
      {
        q: 'Is The Star a yes or no card?',
        a: `Upright, The Star is a warm and affirmative yes — particularly for questions about healing, renewal, long-term hope, and whether good things are coming after a difficult period. She is one of the most genuinely positive cards in the Major Arcana, carrying an energy of deep reassurance about the future. She's especially affirming for creative endeavours, questions about recovery from difficulty, and anything involving inspiration or a sense of renewed purpose. Reversed, her answer is more tentative: "potentially yes, but not yet" — there may be some healing or restoration of hope needed before the good she promises becomes accessible.`,
      },
      {
        q: 'What does The Star mean in love?',
        a: `In love, The Star upright is a beautiful and genuinely hopeful card. It can indicate a new relationship that feels genuinely healing and restorative — someone who sees you clearly and treats you with real tenderness. It can also signal a renewal of hope and inspiration within an existing relationship, a phase of increased closeness and genuine nourishment. For those who have been through difficult relationship experiences, The Star often arrives as a reassurance that what you've been hoping for is genuinely possible. Reversed in love, it may point to difficulty trusting in love's possibility, or to a relationship that has lost its sense of inspiration and renewal.`,
      },
    ],
  },

  'the-moon': {
    up2: `The Moon is the tarot's most honest card about the interior landscape — it depicts everything the daylight of consciousness prefers not to see: the shadows, the distortions, the creatures that rise from the depths of the unconscious when rational control is loosened. The two towers in the background frame the path that must be walked through this terrain, not around it. The crayfish emerging from the water represents the stirring of unconscious material; the dog and wolf howling at the moon represent the domesticated and wild aspects of the psyche both responding to what they cannot fully comprehend. The Moon doesn't promise clarity — she promises honest contact with what is actually in you, which is more valuable than a comfortable fiction. This card is almost always about the gap between surface appearances and underlying reality, and the importance of being willing to look carefully before trusting what you see.`,
    rev2: `The Moon reversed can indicate either the beginning of clarity emerging from confusion — the fog lifting, the distorted perceptions clarifying — or a more challenging expression: a deeper suppression of the unconscious material the upright card surfaces. When the moon is reversed, what is in the depths can be driven down rather than rising to be seen and integrated, creating a kind of pressure-cooked unconscious that will find its way out through symptoms, dreams, or unexpected emotional flooding. It can also indicate that you are becoming more aware of how much confusion has been operating in a situation — the revelation of what has been hidden, the recognition of a deception, the sudden clarity about motivations (your own or another's) that were previously obscured.`,
    love2: `In love, The Moon reversed can signal that illusions about a partner or relationship are beginning to clear — either because truth is surfacing or because you're choosing to look more honestly. This may be relief (discovering that fears were unfounded) or difficult (recognising that something you hoped was solid isn't). It can also indicate that unprocessed emotions — old wounds, unconscious patterns — are beginning to surface in ways that are affecting the relationship and need genuine attention rather than management.`,
    career2: `Professionally, The Moon reversed may indicate that a confusing or deceptive professional situation is beginning to clarify — hidden motivations becoming visible, miscommunications untangling, the actual dynamics of a workplace emerging more clearly. It can also signal that anxiety-driven decision-making is beginning to ease, allowing more rational assessment of a situation that felt overwhelming. Trust the increased clarity but don't assume you have the full picture yet.`,
    spirit2: `Spiritually, The Moon reversed can indicate the beginning of integration of shadow material — the unconscious contents that the upright Moon surfaced are starting to be worked with consciously rather than simply experienced as disorientation. This is genuine progress, even if uncomfortable. It can also signal spiritual confusion beginning to resolve, or the recognition that a particular spiritual path or teacher was more about projection than actual wisdom.`,
    faq: [
      {
        q: 'What does The Moon mean in tarot?',
        a: `The Moon is the tarot's card of the unconscious, illusion, confusion, and the rich complexity of what operates beneath the surface of rational awareness. She illuminates by a reflected, incomplete light — things are visible, but not clearly. She speaks to dreams, intuitions, fears, projections, and the hidden dimensions of a situation that daylight consciousness prefers not to examine. When she appears, she almost always signals that things are not entirely as they appear — either you are not seeing a situation clearly, or unconscious material (fear, old wounds, projection) is significantly influencing your perceptions and decisions.`,
      },
      {
        q: 'Is The Moon a yes or no card?',
        a: `The Moon is one of the least decisive cards in yes/no readings — her nature is ambiguity and partial illumination rather than clear answers. In a yes/no reading she most commonly signals "unclear" or "not what it seems." She's advising against making firm decisions based on current perceptions, because something important may not yet be visible. If you have a strong sense of doubt, confusion, or a feeling that something is being hidden in a situation, The Moon is validating that sense. Wait for more clarity before acting. Reversed, she may indicate that clarity is beginning to emerge.`,
      },
      {
        q: 'What does The Moon mean in love?',
        a: `In love, The Moon points to confusion, hidden dimensions, and the role of unconscious patterns in how a relationship is being perceived or experienced. It can indicate that you're seeing a partner through the lens of old wounds or projections rather than clearly, or that genuine deception is present. It may also surface strong intuitions about a relationship that deserve more examination. Dreams and gut feelings around this connection are likely to be informative. Reversed in love, it can indicate that confusion is clearing — either reassuringly (fears turn out to be unfounded) or revealingly (something hidden becomes visible).`,
      },
    ],
  },

  'the-sun': {
    up2: `The Sun is the tarot's most unambiguous affirmative — and it earns that status by representing something genuinely rare: authentic, undefended joy. Not performed happiness, not the grim pursuit of positive thinking, not contentment achieved through avoidance, but the clear, warm vitality of a self that has stopped managing its own light. The child on horseback in the Rider-Waite image is not cautious — she rides with her arms open, wearing flowers and nothing else, in full daylight. This is the image of uninhibited delight: the capacity to be completely present to an experience without the filtering anxiety that asks whether you're doing it right, whether it will last, whether you deserve it. The Sun speaks to the natural state of the self when fear, shame, and accumulated armour are genuinely laid down. It's not a promised land; it's an available moment. This card asks: where in your life are you dimming your own light unnecessarily?`,
    rev2: `The Sun reversed doesn't extinguish the sun — the light is still there. But something is obscuring it: a glass of anxiety, a cloud of self-doubt, a persistent inability to let good things be straightforwardly good. This can manifest as difficulty receiving joy or recognition without immediately diminishing it or worrying it away. There may be a genuine depression operating — a neurological or circumstantial dimming that needs real attention and support, not just positive thinking. The reversed Sun can also indicate an excessive, blinding positivity — a refusal to see difficulty or shadow, a toxic brightness that is actually defensive. In all its expressions, the card reversed is asking about your relationship with the light itself: are you able to inhabit genuine warmth when it is available, or does something in you deflect it?`,
    love2: `In love, The Sun reversed can indicate that joy, playfulness, and genuine delight have dimmed in a relationship — what was once easy and light-filled has become effortful or flat. It may also signal that insecurity or self-doubt is preventing you from fully inhabiting the good that is actually present in a connection. Sometimes it points to a relationship that looks sunny from the outside but has a more complex interior reality that isn't being acknowledged. The invitation is to find and protect the genuine warmth within the relationship rather than performing it.`,
    career2: `Professionally, The Sun reversed often appears when work has lost its genuine engagement — the tasks that once felt energising now feel merely obligatory, and the sense of purpose or satisfaction has dimmed. It can also indicate that success, when it comes, isn't landing — either it's not being recognised by others appropriately, or you're not able to feel it fully even when it's there. Both deserve examination. The card invites you to reconnect with what genuinely excites you professionally rather than continuing on fumes.`,
    spirit2: `Spiritually, The Sun reversed points to a spiritual practice or worldview that has become heavy, serious, or anxious rather than genuinely alive. If your spirituality is producing more self-criticism, obligation, and gravity than genuine joy, aliveness, and wonder, something is misaligned. The sun of genuine spiritual experience is not solemn — it is deeply, warmly, embodied alive.`,
    faq: [
      {
        q: 'What does The Sun mean in tarot?',
        a: `The Sun is the tarot's clearest positive card — a card of joy, vitality, clarity, and the warm confidence that comes from genuine self-expression. The child on horseback represents the self in its natural, undefended state: fully present, uninhibited, delighting in existence. As a card, The Sun speaks to success, optimism, clarity after confusion, and the kind of authentic happiness that doesn't require anything to be hidden or managed. It often arrives after periods of difficulty or confusion (it follows The Moon in the sequence), bringing the relief of clear seeing and genuine warmth. Whatever the question, The Sun is one of the deck's most affirming answers.`,
      },
      {
        q: 'Is The Sun a yes or no card?',
        a: `The Sun is one of the tarot's strongest yes cards — full stop. For almost any question, it brings warm, affirmative energy and suggests that outcomes will be positive, that clarity will come, that circumstances are genuinely favourable. It's particularly affirming for questions about success, happiness, health, children, and creative endeavours. Even reversed, The Sun doesn't typically become a no — it becomes a "yes, but something is currently dimming the light" — suggesting that the positive outcome is available but something in the situation or your approach is currently obscuring access to it.`,
      },
      {
        q: 'What does The Sun mean in love?',
        a: `In love, The Sun is one of the most joyful cards you can receive — it suggests warmth, genuine happiness, playfulness, and the kind of easy, luminous connection that doesn't require effort to sustain its light. It can indicate a relationship in which both people genuinely bring out the best in each other, or the beginning of a connection that feels immediately bright and uncomplicated. It can also signal a return of warmth and vitality to a relationship that had gone through a difficult phase. For those seeking love, it's a strongly affirmative card suggesting that what you're hoping for is genuinely on its way.`,
      },
    ],
  },

  'judgement': {
    up2: `Judgement — the penultimate card of the Major Arcana — depicts an awakening rather than a verdict. The angel blows a trumpet, and the dead rise from their coffins: this is the image of a profound inner call, the summons to a larger version of yourself that has been preparing through the entire journey of the Major Arcana. The card speaks to the moment of genuine reckoning: not a harsh external judgement but the inner recognition of who you have been, who you are, and who you are now being called to become. This card is about vocational clarity — the experience of being genuinely called to something, of hearing an unmistakable inner summons that cannot be un-heard once it has sounded. Psychologically it maps to the experience of realisation: things you've been circling around suddenly become undeniable. The question isn't "will you be judged?" — it's "will you answer when called?"`,
    rev2: `Judgement reversed points to a deafening of the inner summons — either refusing to hear it, or hearing it and choosing not to answer. This can manifest as a prolonged avoidance of a significant life question that has actually already been answered inwardly; you know what the call is, but the implications feel overwhelming. It can also indicate a harsh, punitive self-judgement that is preventing the kind of honest reckoning the upright card invites — not the clear-eyed recognition of where you've been and where you're going, but an unforgiving verdict against yourself that produces shame rather than movement. In some readings, it suggests a genuine inability to forgive yourself or another, a refusal to close a chapter that needs to be closed so that the next one can begin.`,
    love2: `In love, Judgement reversed can indicate that a significant conversation or decision about a relationship is being perpetually deferred — you know something important needs to be said or decided, but the courage to say it hasn't yet arrived. It can also signal unresolved guilt or shame around past relationship behaviour that is interfering with present connection. The card asks: what do you need to acknowledge, forgive, or decide in order to genuinely move forward in this relationship?`,
    career2: `Professionally, Judgement reversed often appears when a genuine vocational calling is being ignored — when the work that is actually calling to you is being suppressed in favour of the safe, familiar, or financially convenient choice. It can also indicate a significant professional evaluation or decision being avoided, or the refusal to honestly assess where a career is and isn't working. The summons has sounded; the question is whether you'll answer it.`,
    spirit2: `Spiritually, Judgement reversed points to a reluctance to fully reckon with your spiritual history — either to grieve what has passed, honestly assess what has genuinely served your growth and what has been avoidance, or accept the call to a deeper engagement with your own life. The spiritual work here is fundamentally about honesty and the courage that genuine self-reckoning requires.`,
    faq: [
      {
        q: 'What does Judgement mean in tarot?',
        a: `Judgement is the second-to-last card of the Major Arcana and represents a profound inner awakening — a genuine call to a larger version of yourself, heard when the journey of self-knowledge has sufficiently prepared you to receive it. The traditional imagery of the dead rising to an angel's trumpet speaks to this: old versions of yourself, old ways of being, rising to answer an undeniable summons. As a card, Judgement speaks to vocational clarity, significant life evaluations, the capacity for honest self-reckoning without either self-condemnation or self-deception, forgiveness, and the experience of being genuinely called to something that matters.`,
      },
      {
        q: 'Is Judgement a yes or no card?',
        a: `Upright, Judgement leans toward yes — particularly for questions about major decisions, life changes aligned with a deep inner calling, whether to answer a significant vocational summons, or whether honest reckoning with a situation will lead somewhere worthwhile. It affirms that the time for an important assessment or decision has genuinely arrived. Reversed, it cautions that something is being avoided — the answer may still be yes, but there's a reluctance to face what the question actually requires of you before it can be properly answered. Self-honesty is needed before the card can give you a clean affirmative.`,
      },
      {
        q: 'What does Judgement mean in love?',
        a: `In love, Judgement upright can indicate a moment of genuine clarity about a relationship — a realisation that cuts through confusion and shows you clearly what this connection is and whether it is serving your deepest growth. It can also signal the need for a significant, honest conversation: bringing something important into the open rather than letting it remain unsaid. For those reviewing past relationships, it may invite genuine reckoning and forgiveness — both of a former partner and of yourself. Reversed in love, it often points to deferred decisions or unresolved guilt that is preventing honest assessment of where things actually stand.`,
      },
    ],
  },

  'the-world': {
    up2: `The World is the final card of the Major Arcana, and its depiction is worth examining carefully: the dancer at its centre is wrapped in a purple cloth but otherwise open to the four directions, held within a laurel wreath — a completion that is also a continuous circle. She holds two wands, mirroring The Magician with whom the journey began. The four figures in the corners are the same ones from The Wheel of Fortune: the fixed signs of the zodiac, representing the full range of existence. The card's message is not "you have arrived" in a way that ends movement; it is "you have completed one full cycle and earned the capacity to begin the next from a genuinely different level." The World's wholeness is dynamic, not static. It speaks to mastery earned through genuinely engaging the full journey — including its losses, reversals, and dark passages — rather than avoiding or bypassing any of it. This is integration; not perfection.`,
    rev2: `The World reversed most commonly indicates a completion that hasn't been properly received or acknowledged — either because you are so close to the finish line that you can't let yourself arrive, because there is a final fear or resistance preventing the last step, or because external circumstances are genuinely blocking the fulfilment of something long in preparation. It can also indicate a perfectionism that prevents completion: the project, relationship, or phase of growth is "almost done" indefinitely because something in you is unable to declare it finished. There may also be a sense of premature closure: declaring something complete before the genuine work of integration has happened, moving on before the learning has been fully absorbed. The World reversed is rarely about fundamental failure; it is almost always about the final yard.`,
    love2: `In love, The World reversed can indicate a relationship nearing completion in one of two senses: either genuinely coming to a natural end after its cycle has been fulfilled, or stuck at the threshold of a significant deepening — an engagement, commitment, or vulnerable opening that both people are circling but haven't yet stepped fully into. Examine honestly which kind of completion is relevant to your situation. The card asks what final step, acknowledgment, or release would genuinely complete this chapter.`,
    career2: `Professionally, The World reversed often appears when a significant achievement or completion is within reach but something is preventing arrival — perfectionism, fear of what comes next, external obstacles, or an inability to declare something done and allow yourself the recognition it deserves. It can also signal that a career chapter is complete and a new one is genuinely waiting, but the transition is being resisted. The invitation is to ask what genuine completion would look like and what is standing between you and it.`,
    spirit2: `Spiritually, The World reversed points to a genuine integration that is almost — but not quite — complete. There may be a final piece of understanding to be received, a last forgiveness to be offered, or a remaining resistance to fully embodying what the journey has taught. It can also indicate a readiness to begin the next cycle that hasn't yet been acknowledged: the completion is ready; the new beginning is already calling.`,
    faq: [
      {
        q: 'What does The World mean in tarot?',
        a: `The World is the final card of the Major Arcana and represents wholeness, integration, completion, and the deep satisfaction of a cycle genuinely fulfilled. The dancing figure at its centre, surrounded by the laurel wreath of achievement and the four elemental forces, embodies the idea of mastery earned through full engagement with the entire journey — including its difficulties. It speaks to genuine accomplishment, the integration of experience into wisdom, a sense of expansive freedom and arrival, and the readiness — because completion always contains a new beginning — to step into the next level of the journey from a place of genuine wholeness rather than aspiration.`,
      },
      {
        q: 'Is The World a yes or no card?',
        a: `The World is the tarot's most complete yes — a wholehearted, unqualified affirmative that carries the weight of the entire Major Arcana journey behind it. For almost any question, The World upright signals that outcomes will be genuinely positive, that completion and success are available, and that the circumstances are as favourable as they could be. It's particularly powerful for questions about whether a long-pursued goal will be achieved, whether a significant chapter is ready to conclude, or whether you have what it takes to succeed. Reversed, it becomes a conditional yes: the outcome is available, but something — a final step, a resolution, a completion — needs to happen first.`,
      },
      {
        q: 'What does The World mean in love?',
        a: `In love, The World is one of the most fulfilling cards to receive — it speaks to a sense of completeness and wholeness within a relationship, a partnership that has genuinely grown through its challenges and arrived somewhere that feels earned and real. It can indicate a relationship reaching a significant milestone — marriage, a deepened commitment, a sense of genuine arrival after a long and sometimes difficult journey together. For those seeking love, it suggests that a deeply satisfying connection is genuinely possible and may be closer than it seems. Reversed in love, it points to a completion that is almost within reach but hasn't quite been claimed.`,
      },
    ],
  },
  'ace-of-wands': {
    up2: `The Ace of Wands speaks to something more than mere excitement — it represents the moment when latent potential becomes a living impulse. Psychologically, it marks the emergence of intrinsic motivation: the drive that comes not from obligation or external reward, but from a genuine internal spark. When this card appears, you may feel an almost physical restlessness, an urge to begin, to build, to create something that didn't exist before. This energy is raw and unformed, which is precisely its gift. You are not being handed a finished plan; you are being handed the will to forge one. The challenge is to honour this impulse without immediately taming it into a tidy to-do list. Let the fire breathe first. The Ace asks you to trust that the enthusiasm itself is meaningful information — a signal worth following before the rational mind steps in to audit it.`,
    rev2: `A reversed Ace of Wands rarely means the fire is gone — more often it means the fire is being suppressed, misdirected, or struggling to find adequate fuel. You may feel a gnawing restlessness without any clear outlet: the itch to create or begin something, but no obvious entry point. There can also be a pattern of ignition without follow-through — a graveyard of half-started projects that felt compelling in the moment but lost momentum before they found form. Sometimes this reversal points to external circumstances smothering genuine enthusiasm: an environment or relationship that implicitly discourages boldness. Other times, it reflects internal blocks — perfectionism preventing a start, or fear of failure dressed up as pragmatism. The question this card poses in reversal is not "do you have passion?" but "what is standing between you and acting on it?" That distinction opens up far more useful avenues for reflection.`,
    love2: `In matters of the heart, a reversed Ace of Wands can point to a relationship that feels stuck before it's truly started — attraction that never quite ignites into genuine connection, or a mutual holding-back that leaves both parties waiting for the other to move first. If you're single, it may reflect a reluctance to be vulnerable enough to truly pursue someone. In an established relationship, the spark may feel muted; not absent, but dormant. Small, deliberate acts of playfulness and novelty can help coax it back.`,
    career2: `At work, this reversal often describes a creative block or a promising project that stalls on the launchpad. You may have a strong instinct about a direction but find yourself paralysed by indecision, waiting for conditions that never quite feel right. It can also indicate burnout masquerading as lack of motivation — your energy reserves are genuinely depleted rather than your ideas being poor. Addressing the underlying exhaustion, rather than simply pushing harder, is often the more productive path.`,
    spirit2: `Spiritually, the reversed Ace of Wands invites you to examine whether you are honouring your inner impulses or consistently overriding them in favour of convention. The sacred fire of purpose dims when it is chronically ignored. Meditation or journalling that asks simply "what do I actually want to create?" — without filtering for practicality — can help reconnect you with the original signal beneath the noise.`,
    faq: [
      {
        q: 'What does the Ace of Wands mean in tarot?',
        a: 'The Ace of Wands is the seed card of the fire suit, representing pure creative potential and the initial spark of inspiration. It appears when a new beginning is possible — not as a guaranteed outcome, but as a genuine invitation. In psychological terms, it reflects the emergence of intrinsic motivation: the desire to act, create, or initiate something driven by authentic enthusiasm rather than duty. It encourages you to trust an impulse even before you have a full plan, recognising that the energy itself carries meaningful direction.',
      },
      {
        q: 'Is the Ace of Wands a yes or no card?',
        a: 'The Ace of Wands leans firmly toward yes, particularly for questions involving new ventures, creative projects, or taking initiative. It is one of the more optimistic cards in the deck when upright, suggesting that the conditions for beginning are favourable and that your enthusiasm is well-founded. However, it speaks more to the rightness of starting than to guaranteed success at the finish line — the work of sustaining that initial fire still lies ahead. Reversed, it softens to a "not yet" rather than a hard no.',
      },
      {
        q: 'What does the Ace of Wands mean in love?',
        a: 'In love readings, the Ace of Wands often heralds a relationship full of passion, chemistry, and spontaneous energy. For those who are single, it can signal an exciting new connection on the horizon — someone who genuinely ignites your interest rather than merely ticking boxes. For those already in a relationship, it encourages rekindling the adventurous, playful dimension of the partnership. The card reminds us that long-term love benefits from regularly treating each other with the same curiosity and enthusiasm you brought at the very beginning.',
      },
    ],
  },

  'two-of-wands': {
    up2: `The Two of Wands inhabits an interesting psychological territory: the moment after the initial spark has been claimed, but before the journey has truly begun. The figure holding the globe is not dreaming idly — they are conducting a genuine assessment of possibility, weighing ambition against capacity and timing. This card speaks to the quality of strategic imagination: the ability to hold a vision of the future clearly enough to make present decisions in its service. It asks whether your plans extend beyond wishful thinking into something you are genuinely prepared to act upon. There is also a theme of horizon-gazing that can cut both ways — it can represent healthy forward planning or a subtle reluctance to stop planning and actually depart. The Two of Wands invites you to notice whether contemplation has become comfortable in itself, and whether the safety of the castle wall is beginning to substitute for the aliveness of the road.`,
    rev2: `When the Two of Wands reverses, the quality of anticipation sours into something closer to anxiety or stagnation. The plans that felt expansive now feel overwhelming; the vision of the horizon prompts dread rather than excitement. This can manifest as chronic indecision — cycling through options without ever committing, or allowing the perfect to become the enemy of the adequate. There may also be a reluctance to relinquish control: a fear that stepping into the unknown means losing the stability you have carefully constructed. In some cases, reversed, this card reflects the pain of a plan that has genuinely collapsed — a path forward that no longer exists — and asks you to grieve that before rushing toward a replacement. The deeper invitation is to distinguish between the fear of moving and a legitimate reason to pause, because both feel similar from the inside but call for very different responses.`,
    love2: `Reversed in a love context, the Two of Wands can point to a relationship in which one or both partners are unclear about where they want things to go. There may be an underlying desire to keep options open rather than commit to a shared direction. For couples, differing visions of the future — around lifestyle, location, or long-term goals — may be quietly creating distance. The reversal calls for honest conversation about what each person actually wants, even if that conversation is uncomfortable.`,
    career2: `Professionally, this reversal can signal a promising plan that is indefinitely postponed through over-preparation or fear of risk. You may keep refining the strategy without ever executing it, which eventually drains the original enthusiasm. It can also reflect a situation where external constraints — market conditions, organisational resistance — are genuinely blocking forward movement. Identifying which dynamic is at play helps clarify whether you need more courage or more patience.`,
    spirit2: `Spiritually, the reversed Two of Wands asks whether you are genuinely discerning your path or simply avoiding the vulnerability of choosing one. The spiritual life requires commitment — not rigidity, but a willingness to say "this is the direction I am facing." Sustained contemplation without corresponding action can become a kind of spiritual avoidance. What would it mean to take one concrete step in the direction your intuition has been pointing?`,
    faq: [
      {
        q: 'What does the Two of Wands mean in tarot?',
        a: 'The Two of Wands represents the phase of strategic anticipation — the point at which an idea has taken hold and you are beginning to map out the territory ahead. It reflects ambition that is becoming concrete: not just a wish, but a plan in formation. The card often appears when you are standing at a crossroads between the familiar and the expansive, weighing whether to stay within what you know or to commit to a broader vision. It encourages bold thinking without naivety, asking you to pair your enthusiasm with honest assessment of what the journey will actually require.',
      },
      {
        q: 'Is the Two of Wands a yes or no card?',
        a: 'The Two of Wands generally reads as a conditional yes — the potential is real, but the outcome depends significantly on your willingness to move from planning into action. It supports decisions that involve stepping beyond your comfort zone or expanding your horizons, particularly in career and creative contexts. However, it carries a note of personal responsibility: the card suggests that the result will reflect the quality of your preparation and the courage of your follow-through. Reversed, it leans toward "not yet" — recommending further reflection before committing.',
      },
      {
        q: 'What does the Two of Wands mean in love?',
        a: 'In love, the Two of Wands often appears when a relationship is at a pivotal moment of choice — both parties may be sensing that they need to either invest more deeply or acknowledge that their paths are diverging. It can signal a desire to build something lasting and intentional together, moving beyond the early phase of attraction into genuine partnership with shared direction. For those who are single, it may reflect a willingness to look beyond familiar types or contexts and open to connections that feel genuinely expansive rather than simply comfortable.',
      },
    ],
  },

  'three-of-wands': {
    up2: `The Three of Wands represents the satisfaction of a plan that has been set in motion and is now unfolding beyond the horizon of immediate control. The figure watches ships sail outward — their work of preparation is done. This is a card of earned confidence: not arrogance, but the quiet self-assurance that comes from having done the groundwork and now trusting the process. Psychologically, it speaks to the capacity to sustain belief in a long-range vision when results are not yet visible. Many people collapse at this stage, mistaking the absence of immediate feedback for failure. The Three of Wands asks you to resist that contraction. It also carries a genuinely international or expansive flavour — there is often a sense of ideas, influence, or resources extending into territory you cannot personally supervise. The invitation is to trust what you have set in motion rather than scrambling to pull it back under direct control.`,
    rev2: `In reversal, the Three of Wands often describes the frustration of waiting for progress that is overdue, or the demoralising experience of watching carefully made plans encounter unexpected resistance in execution. Delays that were not anticipated begin to erode confidence in the original vision. It can also point to a specific pattern of over-reaching: expanding into territory before the foundations are solid enough to support it, or taking on ventures beyond current resources. In some readings, the reversed Three suggests a fear of expansion itself — a reluctance to let the work travel beyond your direct oversight. There may be a need to examine whether your relationship with control is limiting growth. The card also occasionally surfaces when external factors — economic shifts, unreliable partners, or simply bad timing — are genuinely impeding progress, asking you to reassess the plan rather than simply push harder against real obstacles.`,
    love2: `Reversed in love, the Three of Wands can indicate a relationship in which growth feels blocked — perhaps you are waiting for a partner to move toward greater commitment, or a promising connection has stalled due to distance or circumstance. There may be a sense of plans made together that are failing to materialise. It also sometimes surfaces when one person has outgrown the current dynamic and feels an unspoken tension between staying and expanding. Honest acknowledgement of this feeling is more productive than suppressing it.`,
    career2: `Professionally, this reversal often marks a period of frustrating delay — projects launched with genuine momentum that are now stalled by bureaucracy, unreliable collaborators, or market conditions that shifted. It can also indicate premature expansion: moving into new territory before consolidating what already exists. Taking stock of current assets and shoring up existing foundations may be more valuable right now than continuing to push outward. Patience here is strategic, not passive.`,
    spirit2: `Spiritually, the reversed Three of Wands invites reflection on whether you trust the processes you have set in motion. A practice of faith — in the broadest sense — involves releasing outcomes you cannot directly control. If you find yourself anxiously checking and rechecking whether your efforts are "working," the card gently asks you to practise a deeper form of patience: the kind that does not require constant reassurance to remain steady.`,
    faq: [
      {
        q: 'What does the Three of Wands mean in tarot?',
        a: 'The Three of Wands marks the stage at which initiative has become momentum. Plans have been launched, the first steps taken, and now results are beginning to unfold in ways that extend beyond your immediate reach. It speaks to vision with staying power — the capacity to keep believing in a direction even when outcomes are still distant. The card often appears to confirm that you are on the right track and that the groundwork you have laid is sound, while encouraging you to remain patient with the longer timescale that ambitious ventures naturally require.',
      },
      {
        q: 'Is the Three of Wands a yes or no card?',
        a: 'The Three of Wands is a confident yes, particularly for questions about ventures already in motion, collaborative projects, or anything involving expansion and growth over time. It suggests that the trajectory you are on is positive and that results, though perhaps not instantaneous, are on their way. It is especially favourable for questions about business, career development, or any situation where you have already done the preparatory work and are now waiting to see it pay off. Reversed, it shifts toward a more cautious "perhaps, with adjustments needed."',
      },
      {
        q: 'What does the Three of Wands mean in love?',
        a: 'In love, the Three of Wands often signals a relationship that is progressing meaningfully — moving from the initial excitement into something with genuine long-term potential. There may be thoughts of the future: shared plans, deepening commitment, or possibly a connection that spans distance and is nonetheless growing. It can also speak to the patience required in relationships where timing is complicated — the card assures that the emotional investment you have made is not wasted, even if the visible progress feels slower than you would like.',
      },
    ],
  },

  'four-of-wands': {
    up2: `The Four of Wands carries a quality of relief as much as celebration — the relief of having built something stable enough to pause and appreciate. It marks one of those genuinely joyful moments in the Wands narrative where fire energy has been successfully channelled into structure, and the result is a foundation worth celebrating with others. Psychologically, this card speaks to the importance of marking milestones rather than perpetually racing toward the next objective. Many driven people — those for whom Wands energy is a natural temperament — find it difficult to pause and acknowledge what has been achieved. The Four gently insists on this pause. There is also a communal dimension: this celebration is shared, not solitary. The card recognises that most meaningful achievements are supported by relationships, and that genuine gratitude for that support is both emotionally healthy and relationally nourishing. It is a card of belonging as much as success.`,
    rev2: `A reversed Four of Wands rarely indicates that celebration is unwarranted — more often it suggests that something is preventing the full experience of joy or stability. This might be internal: a tendency to minimise your own achievements, to feel that celebration is premature until the next goal is reached, or an underlying anxiety that disrupts the ability to feel genuinely settled even when circumstances are objectively good. It can also reflect external disruption: a community or home environment that lacks the warmth or stability that this card upright represents. Relationship tensions within a household or close group may be dampening what should be a period of genuine ease. The reversed Four asks you to examine what is standing between you and the experience of contentment. It is also sometimes a signal that the stability you are celebrating is more fragile than it appears — worth investigating whether the foundations are truly as solid as they look.`,
    love2: `Reversed in love, the Four of Wands can indicate that a relationship, though perhaps functioning on the surface, lacks the genuine sense of home and safety that nourishes long-term partnership. There may be celebrations or milestones that feel hollow rather than genuinely joyful — going through the motions without the underlying warmth. For those navigating living together or considering formalising a commitment, it can point to unresolved tensions in the domestic sphere that need addressing before the transition can feel truly celebratory.`,
    career2: `Professionally, this reversal may indicate that a project completion or achievement isn't receiving the recognition it deserves — either from others or from yourself. There could be instability within a team or organisation that makes it difficult to pause and consolidate gains. It sometimes surfaces when a workplace environment lacks genuine community or psychological safety, leaving achievements feeling empty despite their objective merit. Seeking out environments with more genuine collegiate warmth may become an increasingly important consideration.`,
    spirit2: `Spiritually, the reversed Four of Wands invites inquiry into your relationship with contentment. Many spiritual traditions emphasise non-attachment, but there is a meaningful difference between genuine equanimity and a compulsive inability to rest in satisfaction. If you consistently feel that peace is something you will experience "once the next thing is done," this card asks you to examine that pattern directly. The capacity to be genuinely present to good things as they happen is itself a spiritual practice.`,
    faq: [
      {
        q: 'What does the Four of Wands mean in tarot?',
        a: 'The Four of Wands is one of the most warmly positive cards in the tarot, representing celebration, stability, and the joy of reaching a meaningful milestone with people you care about. It often appears around completions — finishing a project, reaching a goal, or transitioning into a new phase — and encourages you to genuinely mark and appreciate the moment rather than immediately rushing ahead. It also carries strong associations with home, community, and belonging, suggesting that your sense of security is grounded not just in what you have achieved but in who you have around you.',
      },
      {
        q: 'Is the Four of Wands a yes or no card?',
        a: 'The Four of Wands is an enthusiastic yes, particularly for questions involving celebrations, gatherings, homecoming, commitment ceremonies, or any situation where you are hoping for warmth, stability, and positive reception. It is one of the most favourable cards for questions about community, belonging, and the enjoyment of what you have built. For questions about new ventures, it leans positive but carries more of a "this is the right environment" connotation rather than guaranteeing specific outcomes. Reversed, it softens somewhat, suggesting the positive outcome is possible but may require more groundwork.',
      },
      {
        q: 'What does the Four of Wands mean in love?',
        a: 'In love, the Four of Wands is a wonderful card — associated with joy, harmony, and the kind of relationship that genuinely feels like home. It often appears in contexts of commitment, celebration, or the deepening of a partnership into something stable and mutually sustaining. For those who are single, it can indicate that the social environments you are entering — gatherings, community events, shared celebrations — are fertile ground for meaningful connection. It suggests that love, when it comes, will feel easeful rather than turbulent: a genuine sense of arriving rather than striving.',
      },
    ],
  },

  'five-of-wands': {
    up2: `The Five of Wands describes the inevitable friction that arises when multiple strong personalities or competing ideas occupy the same space. This is not necessarily destructive conflict — it can be the productive tension of genuine debate, collaborative brainstorming that hasn't yet resolved into consensus, or the healthy challenge of competition that pushes everyone to perform at a higher level. Psychologically, the card asks how you relate to conflict and competition. Some people avoid both at significant cost to their authenticity and effectiveness; others engage but in ways that are more about dominance than genuine exchange. The Five of Wands invites a third posture: engaged, direct, confident in your perspective, while remaining genuinely open to having your thinking sharpened by opposition. It also acknowledges that not all conflict resolves tidily — sometimes you simply have to hold your ground without expecting everyone to agree by the end. The willingness to do so, without aggression, is itself a form of maturity.`,
    rev2: `The reversed Five of Wands can swing in two very different directions. For some, it represents conflict that has finally de-escalated — the chaos of competing agendas begins to settle and clarity emerges. This can be a genuinely welcome relief, particularly if the upright Five has been present for some time. For others, however, the reversal indicates avoidance: a retreat from necessary conflict that leaves core disagreements unresolved beneath a surface of apparent calm. Unexpressed anger or resentment can quietly accumulate in this configuration. The reversal can also point to internal conflict — a person at war with themselves, unable to commit to a direction because competing desires are not being honestly acknowledged. The task here is not to force resolution but to look honestly at what the conflict is actually about, because avoided conflict rarely disappears; it tends to resurface in less manageable forms.`,
    love2: `In love, the reversed Five of Wands often describes a relationship in which conflict is either avoided entirely or has escalated beyond productive argument into something more corrosive. If arguments are being suppressed to maintain a fragile peace, important issues are likely building beneath the surface. Conversely, if fighting has become habitual, the card invites reflection on whether disagreements are actually attempts to be heard. Learning to argue well — with honesty and care — is often more valuable than achieving the absence of conflict.`,
    career2: `At work, this reversal can indicate a team or organisation where dysfunction has set in: competing agendas, unclear roles, and an inability to align on priorities. Alternatively, it can reflect the aftermath of workplace tension — things have calmed, but the underlying issues that sparked the conflict have not been properly addressed. It sometimes points to someone who is withdrawing from professional competition out of exhaustion or self-doubt, and the card asks whether that withdrawal is truly a strategic pause or an avoidance of necessary assertiveness.`,
    spirit2: `Spiritually, the reversed Five of Wands draws attention to inner discord — the competing voices, beliefs, and desires that can make it difficult to feel settled in your values or direction. Practices that create space for honest self-inquiry, such as journalling or contemplative dialogue, can help you listen to these competing inner voices without being overwhelmed by them. Spiritual integration is not the silencing of these voices but learning to understand what each one needs.`,
    faq: [
      {
        q: 'What does the Five of Wands mean in tarot?',
        a: 'The Five of Wands represents conflict, competition, and the friction that emerges when multiple strong forces or ideas collide. It is not inherently negative — the card often points to productive tension, lively debate, or the kind of competition that sharpens thinking and raises performance. In a reading, it frequently appears when there is chaos, disagreement, or a need to assert yourself clearly among competing voices. The key question it raises is not whether conflict is happening, but whether you are engaging with it in a way that is honest and ultimately constructive rather than merely combative.',
      },
      {
        q: 'Is the Five of Wands a yes or no card?',
        a: 'The Five of Wands is generally considered a no or a "not straightforwardly" card — not because the outcome is negative, but because it indicates conditions of disorder, competition, or obstacles that complicate a simple answer. The situation it describes is likely to require more effort, negotiation, or assertiveness than you might hope. Rather than reading it as a definitive no, treat it as a warning that the path forward requires navigating genuine opposition. If you are well-prepared for that challenge, the eventual outcome can still be positive.',
      },
      {
        q: 'What does the Five of Wands mean in love?',
        a: 'In a love reading, the Five of Wands often points to friction, misunderstanding, or a relationship dynamic in which both partners are struggling to be heard at the same time. It can indicate a phase of genuine disagreement — about values, priorities, or ways of being — that needs to be worked through rather than papered over. While this is uncomfortable, the card is not necessarily pessimistic: couples who can argue honestly and still choose each other often build more resilient partnerships than those who have never tested their bond under pressure. The card encourages clarity over comfort.',
      },
    ],
  },

  'six-of-wands': {
    up2: `The Six of Wands is the tarot's image of hard-won public recognition — the rider returning in triumph, acknowledged by the crowd for something genuinely achieved. The psychological dimension of this card is interesting precisely because of the relationship between internal and external validation. The six is not a card about needing approval; it is about receiving recognition that genuinely reflects merit. That distinction matters. When upright, this card affirms that your confidence in your own work is not self-deception — others are seeing what you have done and responding to it. It can also represent a moment of coming into your own publicly: stepping into a role, presence, or reputation that feels authentic rather than performed. There is sometimes a leadership dimension — the figure leads rather than merely being led — suggesting that this is a moment to show others the way forward through your own demonstrated capability rather than just your declared intentions.`,
    rev2: `The reversed Six of Wands complicates the relationship between achievement and recognition. In one reading, it can mean that genuinely good work is going unacknowledged — either because you are not advocating for it, because you are in an environment that doesn't reward the right things, or because the timing is simply off. In another reading, it can reflect something more uncomfortable: recognition that has been pursued too aggressively, or an inflated sense of one's own accomplishments that isn't quite matched by reality. The card in reversal asks for honesty on both sides of this equation. It can also point to a fall from a previous position of visibility — public difficulties, damaged reputation, or the demoralising experience of having your standing questioned. Recovery in this context usually comes through consistent, quiet work rather than through assertive attempts to reclaim the spotlight.`,
    love2: `Reversed in love, the Six of Wands can indicate a relationship in which one partner consistently feels overlooked or underappreciated, their contributions going unacknowledged by the other. Over time, this imbalance in recognition erodes the emotional foundation. It can also reflect ego dynamics — competition for primacy within the relationship rather than genuine partnership. In early-stage romance, it sometimes points to someone who projects confidence but whose self-image is more fragile and approval-dependent than it initially appears.`,
    career2: `Professionally, this reversal often signals a period in which your accomplishments are not receiving the visibility they deserve. This might call for more deliberate self-advocacy — learning to speak about your work with appropriate confidence — rather than assuming that quality will speak for itself in environments that don't automatically reward quiet competence. Alternatively, it can flag overconfidence: taking on a public-facing role before the underlying expertise is fully developed, leading to credibility issues that take time to repair.`,
    spirit2: `Spiritually, the reversed Six of Wands offers a valuable invitation to examine your relationship with external validation. How much of your sense of worth depends on being seen and acknowledged by others? Genuine spiritual development often moves in the opposite direction: toward an internality that remains steady regardless of the crowd's response. The practice of doing good work in private — without needing it witnessed — can be unexpectedly clarifying.`,
    faq: [
      {
        q: 'What does the Six of Wands mean in tarot?',
        a: 'The Six of Wands represents success, recognition, and the satisfaction of having your efforts acknowledged by others. It often appears after a period of hard work or struggle, signalling that you are emerging into a phase of well-deserved visibility and respect. It can indicate public recognition, promotion, or simply a moment when others see and affirm the quality of what you have brought. The card carries a theme of confident leadership — not arrogance, but the natural authority that comes from having genuinely earned your position through demonstrated capability and effort.',
      },
      {
        q: 'Is the Six of Wands a yes or no card?',
        a: 'The Six of Wands is a strong yes — particularly for questions involving success, recognition, promotion, competition, or situations in which you are hoping your efforts will be seen and rewarded. It is one of the most affirming cards in the tarot for questions about outcomes, suggesting that the trajectory you are on is headed toward a positive conclusion. It is especially favourable when asking whether hard work will pay off, whether you will receive deserved credit, or whether a public-facing endeavour will land well. Reversed, it becomes a more cautious maybe, with qualifications.',
      },
      {
        q: 'What does the Six of Wands mean in love?',
        a: 'In love, the Six of Wands can indicate a relationship in which you feel genuinely seen, celebrated, and valued — a partnership in which your qualities are appreciated rather than taken for granted. For those who are single, it sometimes heralds a connection with someone who is admirable and successful in their own right, or suggests that you yourself are entering a period of personal confidence that naturally attracts others. It can also speak to the importance of mutual acknowledgement within a relationship: making sure that both partners feel genuinely recognised for what they contribute.',
      },
    ],
  },

  'seven-of-wands': {
    up2: `The Seven of Wands depicts a figure holding their ground against multiple challengers from a position of height — significantly, the advantaged position. This nuance matters. The card is not about fighting from a position of weakness; it is about defending something of genuine value that you have already earned or built. The psychological territory here is the experience of success that attracts opposition — the way that visibility, achievement, or strong convictions inevitably draw challenge. This can take the form of professional competition, social criticism, or simply the experience of being questioned at the moment when you most need to hold your nerve. The Seven of Wands asks whether you have the psychological stamina to stand by what you believe and what you have built, even when that position requires sustained effort. It also quietly asks whether what you are defending is genuinely worth defending — because the card's energy is most honestly deployed in service of real conviction rather than mere stubbornness.`,
    rev2: `A reversed Seven of Wands often describes a person who is exhausted by the demands of constantly holding their ground. The defensiveness that felt necessary has become a default posture, even in situations where it is no longer called for. This can manifest as an inability to receive feedback without experiencing it as attack, or a level of vigilance that is disproportionate to the actual level of threat. In other cases, the reversal points to a genuine capitulation — abandoning a position or principle under pressure from others, not because you have genuinely reconsidered, but because maintaining it has simply become too tiring. The card in reversal asks you to distinguish between healthy flexibility — genuinely updating your position in response to good argument — and the kind of exhaustion-driven surrender that you will later regret. Both feel similar in the short term.`,
    love2: `In love, the reversed Seven of Wands can signal a relationship dynamic in which one or both partners have become defensive by default — where interactions carry an undertone of guardedness or mild conflict, even in relatively neutral moments. This often develops after a period of genuine hurt or repeated disappointment, and represents the heart protecting itself through a kind of pre-emptive self-defence. While understandable, this posture makes genuine intimacy very difficult. Recognising the pattern is the first step toward loosening it.`,
    career2: `Professionally, this reversal can indicate that you are overextending yourself in the defence of a position that may actually benefit from being reconsidered. It sometimes appears when someone is investing significant energy in workplace politics or interpersonal conflict rather than the core work itself. It can also point to a loss of competitive edge — a position or reputation that is slipping despite your efforts to maintain it — calling for a reassessment of strategy rather than simply more of the same.`,
    spirit2: `Spiritually, the reversed Seven of Wands invites you to examine what you are protecting and why. Sometimes what we defend most vigorously — our beliefs, our identities, our established ways of seeing — are precisely the things that most need to be questioned. The willingness to hold your deepest convictions lightly enough to genuinely interrogate them, while remaining rooted in your core values, is a mark of real spiritual maturity.`,
    faq: [
      {
        q: 'What does the Seven of Wands mean in tarot?',
        a: 'The Seven of Wands represents the challenge of holding your ground when you face opposition, competition, or challenge to what you have built. It speaks to the resilience and conviction required to defend a position or achievement against multiple pressures — and to the importance of doing so from a place of genuine belief rather than mere habit or pride. The card often appears during periods when you are experiencing pushback on your ideas, values, or success, and encourages you to trust the validity of your position while remaining open to reconsidering it on genuinely good grounds.',
      },
      {
        q: 'Is the Seven of Wands a yes or no card?',
        a: 'The Seven of Wands is a conditional yes — specifically for questions where the answer depends on your willingness to persist in the face of opposition. It suggests that the outcome you are hoping for is achievable, but will require you to hold your ground and resist pressure to abandon your position prematurely. If you are asking whether to give up or back down, the card says no — stay the course. If you are asking whether a situation will be easy or uncontested, the card also says no. It rewards determination and clarity of conviction.',
      },
      {
        q: 'What does the Seven of Wands mean in love?',
        a: 'In love, the Seven of Wands can indicate the effort required to protect a relationship that is under some form of external or internal pressure. This might mean standing up for a relationship that others disapprove of, maintaining your commitment through a difficult phase, or defending your own needs and worth within a partnership that has become unbalanced. It can also point to defensiveness within a relationship — a pattern of protecting yourself so vigilantly that genuine closeness is becoming difficult. The card asks you to distinguish between protecting love and merely armoring against it.',
      },
    ],
  },

  'eight-of-wands': {
    up2: `The Eight of Wands is one of the few tarot cards with no human figure — just eight wands in swift, parallel flight across an open sky. This absence of a central protagonist is itself meaningful: the energy described here is not about individual agency but about the remarkable experience of being carried forward by momentum that is larger than personal effort. Psychologically, this card represents those periods when everything suddenly aligns — when the right people, timing, and circumstances converge and progress that had been laborious becomes rapid and almost effortless. The invitation is to act decisively and swiftly during this window rather than allowing the momentum to pass unused through over-deliberation. Communication is also central to the Eight of Wands — the movement of information, messages, and ideas at speed. It often appears when important news is on its way, or when a conversation long-delayed needs to happen now, while the conditions are right.`,
    rev2: `When the Eight of Wands reverses, that sense of swift momentum encounters friction. Things that should have moved quickly are delayed, communications are misunderstood or lost, and plans that seemed ready to launch stall at the threshold. There can be a frustrating quality of being almost-but-not-quite there: arrangements that keep falling through, messages that don't land as intended, or timing that is consistently slightly off. In some readings, the reversal points to an overload of incoming information or demands — a scatter of activities without sufficient focus to execute any of them well. The reversal can also represent a deliberate slowing of pace: sometimes the card appears to signal that the speed of events is genuinely too fast, and that some strategic deceleration would serve you better than continuing to race. Discerning which dynamic applies requires honest reflection on whether the delays are external obstacles or internal ambivalence.`,
    love2: `Reversed in love, the Eight of Wands often describes a connection that has lost its momentum — what felt exciting and rapidly developing has slowed, and it is no longer clear whether the relationship is progressing or stalling. There may be communication breakdowns: conversations that keep being postponed, messages that seem to carry a different weight than intended, or a general sense that you and a partner are not quite in sync. For new connections, the initial rush of feeling may have calmed faster than expected, leaving uncertainty about what remains beneath it.`,
    career2: `Professionally, this reversal frequently signals delays in projects that should be moving quickly — approvals held up, communication breakdowns within teams, or a general feeling of swimming against the current after a period of good progress. It can also indicate burnout from sustained high-pace working: the cost of running at speed for too long without adequate rest. Revisiting project plans, clarifying communication protocols, or simply taking a step back to assess priorities can help restore productive flow.`,
    spirit2: `Spiritually, the reversed Eight of Wands invites you to consider what happens when you slow down. Much of modern life is structured around speed, and the reversal of this card can be an invitation — albeit an unwelcome one — to discover what becomes available when the pace drops. Stillness sometimes reveals what movement has been obscuring. What has been rushing past that you haven't had time to notice?`,
    faq: [
      {
        q: 'What does the Eight of Wands mean in tarot?',
        a: 'The Eight of Wands is the tarot\'s most direct representation of swift movement, momentum, and rapid progress. It appears when events are accelerating — when plans that were slowly building suddenly gather speed, when communications intensify, or when a window of opportunity opens and demands decisive action. It is a card of good timing and aligned energy: the sense that the universe is briefly cooperating rather than resisting. The card encourages you to act during this window, to reach out, to launch, to say what needs to be said — because the conditions for fast progress are particularly favourable.',
      },
      {
        q: 'Is the Eight of Wands a yes or no card?',
        a: 'The Eight of Wands is a clear yes — and typically a swift one. It suggests not only a positive outcome but a relatively rapid one. For questions involving timelines, communications, travel, or the launch of projects, it is particularly affirming, suggesting that things will move faster than expected. It encourages bold action rather than continued waiting. Reversed, it introduces delay and complication — shifting toward a "yes, eventually" or "yes, but obstacles first" rather than an immediate positive response.',
      },
      {
        q: 'What does the Eight of Wands mean in love?',
        a: 'In love, the Eight of Wands often heralds a rapid development in a romantic situation — feelings that intensify quickly, a relationship that accelerates from early interest to something deeper in a short span of time, or news of a connection that arrives unexpectedly and with notable force. It can also indicate a long-distance relationship that is finally bridging the gap, or a communication — a message, conversation, or declaration — that breaks through an impasse. It encourages acting on feelings when the moment presents itself, rather than waiting for a theoretically more perfect time.',
      },
    ],
  },

  'nine-of-wands': {
    up2: `The Nine of Wands is a card of battle-worn perseverance — the figure is not fresh, not energised in the way of the Ace, but still standing. There is something deeply human about this image: the person who keeps going not out of naive optimism but out of hard-won determination. Psychologically, this card speaks to resilience as it actually exists, not as an idealised virtue. Genuine resilience is not the absence of exhaustion or self-doubt; it is the decision to continue despite them. The card often appears in readings when someone has been through a genuinely difficult period and is now close to completion but struggling to find the energy to finish. The nine wands behind the figure represent experience accumulated through difficulty — not wounds to be ashamed of, but evidence of capacity. The card also carries a theme of appropriate wariness: the figure is not paranoid, but neither is he naively trusting. He has learned, at some cost, that vigilance matters.`,
    rev2: `The reversed Nine of Wands amplifies the exhaustion that the upright version is managing. Here, the strain of continued effort against sustained opposition may be genuinely overwhelming — the point at which persistence tips into something that looks more like self-destruction. This can manifest as stubbornness that refuses to acknowledge legitimate limits, or conversely, as a collapse of resolve at the very moment when one final effort would have carried things through. The reversal also sometimes points to a failure to learn from experience: repeating patterns despite the evidence that they are not working, because change feels more threatening than continued difficulty. A compassionate reading of this card in reversal often involves encouraging the person to put the wands down — not permanently, but long enough to genuinely recover. Sustainable effort requires periods of genuine restoration, not just grudging rest.`,
    love2: `In love, the reversed Nine of Wands often appears in situations where someone is chronically giving more than they receive, and yet continues anyway out of loyalty, hope, or the sunk-cost of prior investment. The emotional exhaustion is real and visible, yet the idea of stepping back feels like failure. The card asks whether the relationship is genuinely nourishing both people, or whether one partner is consistently depleted by the effort of maintaining it. Genuine love should not require this level of sustained, one-sided effort.`,
    career2: `Professionally, this reversal is a signal that burnout has moved beyond a temporary state into something more serious. The commitment and work ethic that this person brings to their role are genuine and admirable, but they are being pushed past sustainable limits — either by external demands or by internal drivers they have not yet examined. It may also point to a pattern of taking on others' responsibilities out of fear that things will fall apart without personal intervention, which over time becomes both exhausting and counterproductive.`,
    spirit2: `Spiritually, the reversed Nine of Wands invites an examination of the relationship between endurance and self-compassion. Many spiritual traditions honour fortitude, but fewer adequately honour the necessity of rest. The question this card poses is whether your continued pushing is in service of genuine growth or whether it has become a way of avoiding the deeper vulnerability that comes with admitting you need to stop, receive help, and recover before continuing.`,
    faq: [
      {
        q: 'What does the Nine of Wands mean in tarot?',
        a: 'The Nine of Wands represents resilience, perseverance, and the determination to keep going even when you are genuinely worn down. It often appears near the end of a difficult period — when the finish line is within sight but the person is struggling to find the resources for the final push. The card honours the reality of being tired while refusing to let that tiredness be the last word. It also acknowledges the healthy wariness that develops through experience: you may be more cautious than you once were, and the card validates that as wisdom rather than weakness.',
      },
      {
        q: 'Is the Nine of Wands a yes or no card?',
        a: 'The Nine of Wands is a qualified yes — specifically, a yes that requires continued effort and perseverance. It suggests that a positive outcome is achievable but will not arrive without a genuine, final push. If you are feeling depleted and asking whether it is worth continuing, the card answers affirmatively but with the caveat that you should also care for yourself in the process of persisting. It is not a card that encourages reckless push-through regardless of cost; it honours genuine effort while recognising that sustainable effort requires attention to the person doing it.',
      },
      {
        q: 'What does the Nine of Wands mean in love?',
        a: 'In love, the Nine of Wands often speaks to the effort required to sustain a relationship through a challenging period. It can represent the loyalty and determination of a person who keeps showing up for a partnership even when it has been difficult, or the emotional guardedness of someone who has been hurt before and is now protective of themselves in new connections. The card affirms the value of that commitment while also gently asking whether the caution or effort is proportionate to the actual situation — and whether the relationship genuinely reciprocates the investment being made.',
      },
    ],
  },

  'ten-of-wands': {
    up2: `The Ten of Wands is the suit's image of accumulated responsibility — the figure bent under a heavy load of wands, trudging toward a distant destination. Crucially, the figure has taken on all ten wands themselves; this is not a burden imposed entirely from outside but one that has grown through the natural accumulation of success, commitment, and, often, the inability to delegate or let go. Psychologically, this card speaks to the particular exhaustion that comes from high achievers who add responsibility upon responsibility without asking whether each new addition is genuinely theirs to carry. There is often a pride wound tangled in here — the sense that needing help is a form of failure, or that no one else will do things to the right standard. The Ten asks you to examine whether you are carrying what is genuinely yours and to consider what might be set down, redistributed, or simply released without the catastrophic consequences you have imagined.`,
    rev2: `The reversed Ten of Wands can represent two quite different experiences. The first is positive: an overdue release of burden — finally setting down responsibilities that were not serving you or were honestly not yours to carry, and experiencing the relief of that unburdening. This reading invites you to acknowledge that laying something down is not failure. The second, more difficult reading points to a collapse under the weight: the person who has been carrying too much for too long finally reaches a point of genuine breakdown. Here the card is not a gentle invitation but an urgent signal that something must change before the damage becomes more serious. In either case, the reversed Ten almost always involves an examination of the question of help: whether you have been asking for it, accepting it when offered, and whether you even believe you deserve it.`,
    love2: `In love, the reversed Ten of Wands often describes a relationship dynamic in which the emotional labour is deeply unequal — one partner carrying the weight of maintaining connection, managing conflict, and sustaining the household while the other remains relatively uninvested. The card can also appear when someone is so burdened by external demands — work, family obligations, health concerns — that they have little capacity left for their relationship, causing a slow erosion of intimacy that may not be immediately visible but is genuinely consequential.`,
    career2: `Professionally, this reversal signals that a workload has become genuinely unsustainable. The driven, capable energy that got you to this position is now working against you by preventing you from recognising and enforcing necessary limits. It may be time to have difficult conversations about scope, capacity, and support. There is also sometimes a theme of strategic release: identifying which responsibilities, commitments, or projects are consuming disproportionate energy relative to their value, and making considered decisions about what to put down.`,
    spirit2: `Spiritually, the Ten of Wands reversed asks a deceptively simple question: what are you carrying that was never yours to carry? Many burdens we accumulate through life originated in other people's expectations, fears, or unresolved pain that was passed on to us. Recognising which responsibilities are authentically yours and which are inherited — and doing the slow work of setting the latter down — is one of the more significant acts of spiritual self-reclamation.`,
    faq: [
      {
        q: 'What does the Ten of Wands mean in tarot?',
        a: 'The Ten of Wands represents the exhaustion and strain that come from carrying too many responsibilities, often as the by-product of genuine ambition and success. It acknowledges the very real weight of accumulated commitments and the particular difficulty faced by people who find it hard to ask for help or delegate. The card is not critical of the effort or capability it describes — it honours both — but it asks whether the current level of burden is sustainable and whether some of what is being carried might legitimately be set down or shared without compromising what actually matters.',
      },
      {
        q: 'Is the Ten of Wands a yes or no card?',
        a: 'The Ten of Wands leans toward no, or at minimum a caution. It suggests that current conditions involve too much strain, and that taking on more — or pushing through a demanding situation without addressing the underlying burden — is likely to lead to exhaustion or diminishing returns rather than success. However, it is not a definitive no so much as a prompt to reassess before proceeding. If you can address the issue of overload — by delegating, setting limits, or releasing unnecessary responsibilities — the path forward becomes considerably clearer.',
      },
      {
        q: 'What does the Ten of Wands mean in love?',
        a: 'In love, the Ten of Wands often appears when external pressures are putting significant strain on a relationship — when work demands, family obligations, or personal challenges are consuming so much of a person\'s energy that their partnership is suffering from neglect rather than deliberate disregard. It can also speak to the emotional labour within a relationship itself: the exhaustion of being the person who holds everything together. The card invites honest conversation about what is sustainable and what each person needs in order to show up fully, rather than allowing the slow erosion of connection through unaddressed overwhelm.',
      },
    ],
  },

  'page-of-wands': {
    up2: `The Page of Wands embodies the quality of enthusiastic discovery — the state of being genuinely captivated by an idea, a craft, or a direction without yet having the experience to execute it fluently. This is not a flaw; it is a necessary stage. Pages in the tarot represent a particular kind of freshness: the beginner's mind that has not yet calcified into habit or expertise. Psychologically, the Page of Wands represents the phase in which passion outpaces skill, and the challenge is to stay in the discomfort of that gap long enough for mastery to gradually develop, rather than retreating when enthusiasm collides with difficulty. This card also carries a quality of expressiveness — the Page has something to say, something to share, and communicates it with an infectious directness that more seasoned figures sometimes lose. There is wisdom in surrounding yourself with people who embody this card: their excitement is contagious and generative, even when their execution needs time to develop.`,
    rev2: `A reversed Page of Wands often describes creative energy that is present but poorly directed — the person who is full of ideas but struggles to develop any of them into something sustained. There can be a pattern of enthusiastic starts followed by rapid disillusionment when the excitement of the initial idea gives way to the unglamorous work of development. This is sometimes about impatience and sometimes about genuine uncertainty over direction. The reversal can also point to an environment or relationship that has dampened someone's natural creative spark — the young person whose enthusiasm has been repeatedly met with scepticism or criticism until they stop trusting their own impulses. Recovering this quality often involves finding safe spaces to experiment without immediate pressure for competence or results.`,
    love2: `Reversed in love, the Page of Wands can describe someone who is enthusiastic about romantic potential but struggles to convert that enthusiasm into genuine depth or consistency. Connections may feel exciting at the start but cool quickly once the novelty fades. It can also describe a person who is not yet ready for the sustained vulnerability that love requires — not because they don't care, but because they haven't yet developed the emotional maturity to navigate intimacy's more demanding terrain. Patience with this person, and with yourself if you recognise this pattern, is warranted.`,
    career2: `Professionally, this reversal often indicates creative blocks, difficulty completing projects, or a frustrating sense that your skills are not yet adequate to the vision you carry. It can also point to someone who is still searching for their professional calling — trying various directions without settling, which can feel like failure but is often part of a genuine process of discernment. The challenge is to find the balance between exploration and commitment: sufficient openness to discover what fits, but enough follow-through to genuinely develop in a direction.`,
    spirit2: `Spiritually, the reversed Page of Wands invites you to reconnect with beginner's mind — to approach your spiritual life with genuine curiosity rather than the defended posture of someone who already knows the answers. If your practice has grown stale or obligatory, the Page asks what first sparked your spiritual interest and whether you can find your way back to that quality of open, expectant curiosity rather than weary competence.`,
    faq: [
      {
        q: 'What does the Page of Wands mean in tarot?',
        a: 'The Page of Wands represents the early stages of creative and entrepreneurial energy — the enthusiastic beginner who is genuinely captivated by a new idea, direction, or passion, and is beginning to explore it with characteristic excitement and curiosity. As a person, they tend to be expressive, adventurous, and full of creative potential that is still finding its form. The card often appears when a new creative project, direction, or passion is emerging in your life and encourages you to embrace the exploratory phase without demanding premature mastery or certainty.',
      },
      {
        q: 'Is the Page of Wands a yes or no card?',
        a: 'The Page of Wands leans toward yes, particularly for questions about beginning something new, exploring an idea with genuine enthusiasm, or pursuing a creative or personal passion. It is an encouraging card for new ventures and carries a sense of good omens around novelty and exploration. However, it is not a card that guarantees long-term success on its own — it speaks more to the rightness of beginning than to the certainty of completion. The work of developing something from initial excitement into genuine mastery still lies ahead.',
      },
      {
        q: 'What does the Page of Wands mean in love?',
        a: 'In love, the Page of Wands often represents the exciting early phase of attraction — the rush of new connection, genuine curiosity about another person, and the willingness to take playful risks in pursuit of romantic possibility. As a person in a reading, they are likely charming, spontaneous, and enthusiastic, though possibly not yet ready for the deeper demands of sustained partnership. The card can encourage you to approach love with this same quality of open, playful curiosity rather than the heavily managed caution that sometimes develops after previous disappointments.',
      },
    ],
  },

  'knight-of-wands': {
    up2: `The Knight of Wands is the most intensely kinetic figure in the Wands court — a figure of passionate action, bold initiative, and the exhilarating but somewhat precarious energy of someone who moves faster than they plan. Knights in the tarot represent the dynamic, unmodified expression of their suit's element, and in Wands this means fire at its most impulsive and expansive. The Knight is not reckless for recklessness's sake; he is genuinely inspired and genuinely courageous, often doing things that more cautious figures would not dare. The question this card consistently raises is not whether the Knight's instincts are right — they often are — but whether the execution has sufficient preparation behind it to sustain the initial surge of energy through to meaningful completion. The Knight of Wands invites you to honour the boldness while also asking whether a small amount of additional planning might transform a brilliant start into a lasting achievement.`,
    rev2: `When the Knight of Wands reverses, the qualities that make the upright figure so compelling become liabilities. The confidence tips into arrogance; the spontaneity into impulsivity that causes damage before reflection kicks in. Anger can be a significant feature of this reversal — not the cold, strategic kind, but the hot flash of frustration that says things and makes decisions it later regrets. There may also be a pattern of combustible energy that dissipates before it does any lasting good: a person who enters situations with tremendous force and exits just as rapidly, leaving disruption rather than transformation. The reversed Knight can also represent someone who is all movement and no direction — busy, forceful, impressive in their activity — but without a meaningful destination that gives that activity purpose. The invitation is to slow down long enough to ask where the motion is actually headed.`,
    love2: `In love, the reversed Knight of Wands often describes a partner who is intensely compelling in the early stages — the excitement, spontaneity, and passionate attention can feel genuinely intoxicating — but who struggles to sustain the depth that a relationship requires once the initial heat cools. There may be a pattern of intense pursuit followed by withdrawal, or impulsive declarations that are not backed by consistent behaviour. If you recognise this in yourself, the card invites reflection on what commitment actually asks of you beyond the initial surge of feeling.`,
    career2: `Professionally, this reversal often indicates someone who is excellent at launching and initiating but struggles with the sustained, systematic work required to see things through. Projects may be abandoned when they stop feeling exciting, or impulsive decisions may undermine work that was otherwise going well. It can also describe an environment characterised by reactive, disorganised energy — where things happen fast but without strategic direction, creating perpetual urgency and exhaustion. Developing the capacity to stay present in the less glamorous phases of a project is the key growth area here.`,
    spirit2: `Spiritually, the reversed Knight of Wands invites you to examine your relationship with stillness. The fire element, at its most unbalanced, cannot tolerate pause — it needs constant movement and stimulation to feel alive. But genuine spiritual development often happens in the spaces between action: in silence, in reflection, in the willingness to sit with what has happened before rushing toward the next experience. Can you let the fire be still long enough to illuminate rather than simply to burn?`,
    faq: [
      {
        q: 'What does the Knight of Wands mean in tarot?',
        a: 'The Knight of Wands embodies bold, passionate, and fast-moving energy — the archetype of someone who acts on inspiration with courage and enthusiasm, often before all the details are settled. He represents the exciting momentum of pursuing a vision with full commitment, and frequently appears when you are being called to act decisively, take a creative risk, or pursue something with genuine daring. The card honours these qualities while also carrying an implicit question about sustainability: bold beginnings are wonderful, but the work of sustaining them requires patience and planning alongside passion.',
      },
      {
        q: 'Is the Knight of Wands a yes or no card?',
        a: 'The Knight of Wands is generally a yes — especially for questions involving action, adventure, travel, creative pursuits, or situations that benefit from bold, decisive movement. He is a positive omen for situations where daring is called for, where momentum matters, and where taking a well-timed leap is more valuable than waiting for complete certainty. However, he is less reliable as a yes for questions requiring sustained, methodical effort or careful long-term planning — those contexts call for the King\'s energy rather than the Knight\'s. Reversed, he shifts toward a more cautionary response.',
      },
      {
        q: 'What does the Knight of Wands mean in love?',
        a: 'In love, the Knight of Wands is often associated with intense chemistry, passionate pursuit, and relationships that feel exciting and alive. As a person, he is likely charismatic, adventurous, and capable of grand romantic gestures — the kind of partner who makes you feel genuinely seen and desired in the early stages. The question the card raises is one of consistency: the fire is real and the attraction is genuine, but the longer arc of relationship — commitment, emotional depth, sustained presence through ordinary days — asks more of this energy than its most natural expression provides.',
      },
    ],
  },

  'queen-of-wands': {
    up2: `The Queen of Wands is perhaps the most fully integrated expression of fire energy in the court — she has all of the passion and creative vitality of the suit, but has developed the maturity and self-possession to channel it effectively rather than simply broadcasting it. Unlike the Knight, who acts first and reflects later, the Queen has learned to direct her considerable power with intention. She tends to be warm, magnetically self-confident, and capable of bringing others into her orbit not through domination but through genuine enthusiasm and leadership. Psychologically, she embodies what it looks like when someone has genuinely made peace with their own power — they don't need to diminish themselves to make others comfortable, nor do they need to perform dominance to feel secure. The black cat at her feet suggests an integration of shadow: she knows her darker impulses and has found a way to live with them rather than disown them, which paradoxically makes her less volatile and more trustworthy.`,
    rev2: `In reversal, the Queen of Wands' considerable strengths can curdle into less constructive expressions. The confidence becomes imperious; the warmth becomes conditional and possessive; the natural leadership instinct tips into controlling behaviour. There can also be a more inward manifestation: the qualities the Queen embodies upright — confidence, self-direction, creative vitality — are temporarily eclipsed by self-doubt, jealousy, or a sense of having lost access to one's own power. This latter reading is often more accurate than the external one: frequently when this card reverses for someone who generally embodies the Queen's energy, it signals a period of disconnection from their own fire rather than a genuine character flaw. The invitation is to identify what has dimmed the light and address it directly rather than directing the resulting frustration outward.`,
    love2: `Reversed in love, the Queen of Wands can indicate someone whose natural magnetism and self-sufficiency are creating a subtle barrier to genuine vulnerability. Being attractive and capable, she may rarely need to ask for what she wants emotionally, making relationships sometimes feel like extended performances of strength rather than spaces for mutual softness. In a relationship context, this reversal can also signal jealousy or possessiveness — the fire energy, when insecure, can become controlling. Learning to need people without feeling diminished by that need is the key growth edge here.`,
    career2: `Professionally, this reversal often appears when a naturally strong, creative person is operating in an environment that doesn't suit them — one that is too restrictive, too hierarchical, or insufficiently appreciative of their particular gifts. The result is frustration that can manifest as difficult behaviour, though the root cause is misalignment rather than genuine character issues. It can also point to self-sabotage: undermining your own success through a fear of the visibility that comes with it, or difficulty sustaining collaborative relationships because of an over-developed independence.`,
    spirit2: `Spiritually, the reversed Queen of Wands invites examination of the relationship between personal power and spiritual humility. True spiritual authority does not come from never needing anything; it comes from the willingness to be genuinely transformed by experience. If the fire of ambition and self-determination has crowded out the softer, more receptive dimensions of spiritual life — wonder, vulnerability, the capacity to be moved — this card asks you to make space for those qualities alongside your strength.`,
    faq: [
      {
        q: 'What does the Queen of Wands mean in tarot?',
        a: 'The Queen of Wands represents the mature, integrated expression of fire energy — confidence, creativity, warmth, and passion that have been tempered by experience into something both powerful and accessible. She embodies natural leadership not through domination but through the genuinely magnetic quality of someone who is comfortable in their own skin and generous with their enthusiasm. In a reading, she often represents a person with these qualities or an invitation to step into this energy yourself: claiming your power without apology, leading with authentic warmth, and pursuing your passions with wholehearted commitment.',
      },
      {
        q: 'Is the Queen of Wands a yes or no card?',
        a: 'The Queen of Wands is a confident yes, particularly for questions involving confidence, creative power, personal magnetism, and leadership. She is one of the more affirming court cards in the tarot, suggesting that you have — or can access — the personal resources required to handle what you are asking about. Her yes carries an energy of self-assurance: trust yourself, bring your full presence, and proceed without unnecessary self-doubt. Reversed, the yes becomes conditional — the outcome is still possible, but something internal needs addressing before you can access it fully.',
      },
      {
        q: 'What does the Queen of Wands mean in love?',
        a: 'In love, the Queen of Wands is a wonderfully positive presence — someone who brings genuine warmth, passion, and creative energy to their relationships. They tend to be loyal, expressive, and capable of making a partner feel genuinely desired and seen. As an aspect of yourself, the card encourages you to bring your full, unapologetic self into romantic situations rather than dimming your light for the comfort of others. The Queen of Wands reminds us that confidence and authenticity are deeply attractive qualities, and that the right relationship will be drawn to your fire rather than threatened by it.',
      },
    ],
  },

  'king-of-wands': {
    up2: `The King of Wands represents the fullest realisation of fire energy: vision that has been cultivated into genuine wisdom, passion that has been disciplined into effective leadership, and the kind of charisma that comes not from performance but from a long track record of actual achievement. He has done what the Knight only began and what the Queen manages with grace — he has built something. The King leads with a quality of inspired authority, drawing others into his vision through the force of genuine conviction rather than mere positional power. His fire burns steadily rather than explosively: it illuminates and warms rather than simply consuming. Psychologically, this card represents the integration of masculine fire energy at its most mature — the point at which ambition has become purposeful, courage has become considered, and leadership has learned to serve something larger than the self. His shadow — the risk of domination or inflexibility — is present but managed.`,
    rev2: `A reversed King of Wands can take two primary forms, both of which deserve serious attention. The first is the domineering, autocratic expression of unchecked fire: someone who leads through intimidation, who cannot tolerate being challenged, and who uses their considerable force to silence rather than inspire. This energy, when it appears in a reading, often needs to be honestly acknowledged rather than excused as mere leadership style. The second form is the dimmed or compromised King: someone whose natural authority and visionary qualities are not being exercised — either because they are in an environment that doesn't allow it, because they have lost faith in their own direction, or because the fire of ambition has been gradually worn down by accumulated disappointments. Both readings call for different responses but share the same underlying question: how is power being exercised, and in whose service?`,
    love2: `In love, the reversed King of Wands can indicate a partner whose leadership instinct has tipped into control — someone who struggles to allow space for a partner's autonomy and input, or who responds to perceived challenges to their authority with disproportionate force. This may not be malicious; often it comes from a deep insecurity about losing respect. For those who embody this energy themselves, the reversal asks whether the impulse to direct and lead is being balanced with the capacity to genuinely listen, yield, and be changed by a partner's influence.`,
    career2: `Professionally, this reversal often describes a leader who has lost the trust of their team — not necessarily through misconduct, but through an inability to adapt, listen, or acknowledge that they don't have all the answers. The fire of the King, when it stops serving a broader vision and begins simply asserting itself, becomes counterproductive. Alternatively, it can represent someone with genuine King of Wands potential who is not in a position that honours or utilises their real capacities — a mismatch between innate authority and available opportunity that generates frustration and underperformance.`,
    spirit2: `Spiritually, the reversed King of Wands invites a reckoning with the ego's relationship to power. The mature spiritual leader — which this card at its best represents — has learned to hold authority lightly, to lead from service rather than self-aggrandisement, and to remain genuinely open to being wrong. When the fire of conviction becomes self-righteous certainty, spiritual life contracts rather than expands. The King's fire, at its best, illuminates the path for others, not merely the self.`,
    faq: [
      {
        q: 'What does the King of Wands mean in tarot?',
        a: 'The King of Wands is the tarot\'s most mature embodiment of fire energy: a leader, visionary, and entrepreneur whose passion has been tempered into genuine wisdom and whose ambition serves a purpose larger than personal gain. He represents the kind of authority that comes not from positional power but from a demonstrated track record of courageous, inspired action. In a reading, he often points to a person of this character in your life, or an invitation to step fully into your own authority — to lead with the combination of conviction, generosity, and strategic intelligence that characterises his energy at its best.',
      },
      {
        q: 'Is the King of Wands a yes or no card?',
        a: 'The King of Wands is a strong yes, particularly for questions about leadership, entrepreneurship, creative vision, or situations requiring decisive, confident action. He brings the authority of someone who has seen plans through to completion and whose judgement has been tested and refined. For questions about taking on a significant leadership role, launching a major project, or making a bold commitment, his presence is deeply affirming. Reversed, the yes becomes a more nuanced response — the potential is real, but something about the manner or motivation of leadership may need examining before the full positive outcome is available.',
      },
      {
        q: 'What does the King of Wands mean in love?',
        a: 'In love, the King of Wands represents a partner who brings genuine passion, loyal commitment, and the kind of confident, protective presence that can feel deeply reassuring. He tends to love with full engagement — there is little ambiguity about where you stand with this person. As an aspect of yourself, the card encourages you to bring this same quality into your relationships: to be clear about what you feel and want, to invest with genuine wholeness rather than managing the risk of being hurt through emotional distance, and to lead in love with the same courage and vision you would bring to your most significant work.',
      },
    ],
  },
  'ace-of-cups': {
    up2: `The Ace of Cups operates at the level of potential — it is not a feeling you are currently experiencing but a capacity opening within you. Water in its purest form holds no shape of its own; it takes the form of whatever vessel receives it. This card speaks to that plasticity of the emotional self when it is receptive and unguarded. Psychologically, it marks a moment when the defences soften and genuine contact with another person — or with your own interior life — becomes possible again. It often surfaces after a period of emotional numbness or withdrawal, signalling that the heart has not closed permanently but has simply been waiting. The cup overflowing in the traditional imagery is not about excess but about natural abundance: when a source is genuine, it replenishes itself. Creative work, spiritual practice, and intimate relationships all benefit from this quality of open receptivity.`,
    rev2: `When the Ace of Cups is reversed, the vessel itself is the problem. Something is preventing the natural flow of feeling — a cup turned upside down cannot receive, and cannot give. This blockage is rarely deliberate; more often it reflects accumulated scar tissue from past hurts, a learned wariness that once protected you but now keeps nourishment at arm's length. There may also be an element of emotional perfectionism: waiting for conditions to be ideal before allowing yourself to feel, to love, or to create. The reversal asks you to examine what you are protecting yourself from and whether that protection still serves you. Sometimes the card reversed points to grief that has not been fully processed, or to a creative or spiritual well that feels dry. The invitation is not to force feeling but to gently investigate the obstruction.`,
    love2: `In love, the reversed Ace suggests emotional unavailability — either in yourself or a partner. Past wounds may be creating invisible walls that prevent genuine intimacy from taking root. This is not a condemnation but an observation: the capacity for deep connection is present, yet something stands in the way. Honest self-examination about what you fear in closeness can begin to shift the dynamic. Patience with yourself and others is warranted.`,
    career2: `Creatively and professionally, this reversal may manifest as a block — ideas feel stale, motivation is absent, and work that once felt meaningful now seems hollow. The well has not run dry permanently, but it needs attention. Forcing productivity rarely helps; instead, explore what originally drew you to this work and whether those roots still feel alive. Rest and genuine play can restore what striving cannot.`,
    spirit2: `Spiritually, the reversed Ace points to a disconnection from inner life — prayer, meditation, or contemplative practice may feel like going through the motions. The sense of the sacred has temporarily retreated. Rather than pushing harder, try approaching your practice with curiosity rather than expectation. The connection you seek may return through small, unforced moments rather than deliberate effort.`,
    faq: [
      {
        q: 'What does the Ace of Cups mean in tarot?',
        a: 'The Ace of Cups represents the purest potential of the emotional realm — the beginning of a new feeling, relationship, or creative opening. As the seed card of the Cups suit, it does not describe a specific situation but rather a quality of receptivity and possibility. It often appears when someone is on the threshold of emotional growth: ready, whether they know it or not, to receive something meaningful. In practical terms it can signal the start of a relationship, a creative project that genuinely moves you, or a spiritual awakening — any experience that touches the heart at depth.',
      },
      {
        q: 'Is the Ace of Cups a yes or no card?',
        a: 'The Ace of Cups is broadly a yes card, particularly for questions involving relationships, creative endeavours, healing, and emotional wellbeing. Its energy is welcoming and generative. That said, no single card gives a definitive yes or no — the Ace of Cups says yes to openness and possibility, but the outcome depends on what you do with that opening. If your question involves taking an emotional risk or beginning something new that matters to you, this card encourages you forward. Reversed, it urges you to address internal blocks before proceeding.',
      },
      {
        q: 'What does the Ace of Cups mean in love?',
        a: 'In a love reading, the Ace of Cups is one of the most auspicious cards that can appear. It suggests the beginning of a genuine emotional connection — either the start of a new relationship or a significant deepening of an existing one. Crucially, it is not about infatuation or surface attraction but about authentic feeling: the kind of connection that opens you rather than just exciting you. For those who have been single, it often signals that the emotional conditions are finally right for real partnership. For those in relationships, it can mark a renewal of genuine tenderness.',
      },
    ],
  },

  'two-of-cups': {
    up2: `The Two of Cups moves the potential of the Ace into direct relationship. Where the Ace was solitary — a cup held open to the sky — the Two introduces a mirror: another consciousness, another feeling being. What makes this card psychologically rich is that the connection it describes is not one of need or dependency but of mutual recognition. Both figures in the traditional image hold their cups at the same level; neither pours into the other from above. This equality is the card's central teaching. Healthy partnership requires that both people feel seen and valued in their full complexity, not simply as a function they perform for the other. The Two of Cups applies equally to romantic bonds, close friendships, creative collaborations, and therapeutic relationships — any context where genuine reciprocity and care are the foundation. It also speaks to the internal work of integrating opposing parts of oneself.`,
    rev2: `In reversal, the Two of Cups illuminates where reciprocity has broken down. A relationship that was once balanced may have shifted into an unequal dynamic — one person giving more than they receive, or one person's emotional reality consistently overriding the other's. This can happen gradually and without ill intent: life circumstances shift, one person grows while the other does not, or an unspoken resentment quietly erodes the foundation. The reversed Two may also point to a communication breakdown — the cups are present but not meeting. What is felt is not being said, and what is said is not reaching the other person. In some cases, the card reversed signals a relationship that looks like partnership from the outside but lacks genuine intimacy at its core. The honest question to sit with is whether this connection nourishes both people equally.`,
    love2: `Reversed in a love context, this card often signals imbalance: one partner investing significantly more emotional energy, time, or vulnerability than the other. This asymmetry may have been there from the start, or it may have developed over time. Either way, it creates a subtle undercurrent of resentment or loneliness that tends to worsen without direct conversation. Naming the imbalance honestly — without blame — is the first step toward restoring genuine reciprocity.`,
    career2: `In a work context, the reversed Two of Cups can point to a professional partnership or collaboration that has become strained. Agreements that seemed clear may now be interpreted differently by each party. Alternatively, a working relationship that once felt mutually supportive has grown competitive or one-sided. A candid conversation about roles, expectations, and contributions can help, but both parties need to be willing to hear uncomfortable truths.`,
    spirit2: `Spiritually, the Two of Cups reversed may suggest difficulty finding genuine community — feeling isolated even among people who share your path. The longing for a spiritual companion or teacher who truly understands your experience is real. It can also point to an internal division: a conflict between the spiritual values you hold and the way you are actually living, a dissonance worth examining with compassion rather than judgement.`,
    faq: [
      {
        q: 'What does the Two of Cups mean in tarot?',
        a: 'The Two of Cups represents genuine mutual connection — the kind of relationship where both people feel seen, valued, and met as equals. It is one of the most positive cards for any reading that involves partnership, whether romantic, professional, or platonic. Its emphasis is less on passion and more on recognition: the experience of encountering another person (or aspect of yourself) and feeling a deep sense of resonance. This card often appears when a significant bond is forming or when an existing relationship reaches a new level of trust and authenticity.',
      },
      {
        q: 'Is the Two of Cups a yes or no card?',
        a: 'The Two of Cups is a strong yes card, especially for questions about relationships, partnerships, reconciliation, and collaboration. It carries a naturally affirmative energy — two forces coming into alignment rather than conflict. If your question involves whether a connection is genuine, whether a partnership will be mutually beneficial, or whether reconciliation is possible, this card offers an encouraging answer. Reversed, the answer becomes more conditional: yes, if underlying imbalances are acknowledged and addressed. The yes is available, but it requires honesty from both sides.',
      },
      {
        q: 'What does the Two of Cups mean in love?',
        a: 'In love readings, the Two of Cups is exceptional — it describes a meeting of equals, a bond characterised by mutual respect, genuine feeling, and the rare quality of being truly known by another person. It can mark the beginning of a significant relationship or a deepening of an existing one into something more authentic and committed. Importantly, this card does not describe obsession or idealisation but something more mature: a love that is grounded in clear-eyed recognition of who the other person actually is, with all their complexity.',
      },
    ],
  },

  'three-of-cups': {
    up2: `The Three of Cups brings the dyadic energy of the Two into community — the circle of support, celebration, and shared joy that exists beyond the primary pair. Psychologically, this card addresses a need that even the most satisfying romantic partnership cannot fully meet: the need for belonging within a wider web of relationships. The three figures dancing in the traditional imagery are not performing their joy for an audience; they are generating it together, and the joy is greater than any individual could produce alone. This card speaks to the particular nourishment of friendship — especially friendships where you can be fully yourself without editing or performing. It also celebrates creative collaboration: the way that working alongside others who genuinely understand your vision can unlock possibilities that solitary work cannot. In readings, the Three of Cups often signals a time when community is actively available to you, and the invitation is to receive it rather than holding yourself apart.`,
    rev2: `The Three of Cups reversed complicates the picture of community and celebration. One dimension is excess: when the energy of festivity continues past the point of genuine joy and becomes an avoidance mechanism — drinking, socialising, or seeking constant stimulation to avoid sitting with difficult feelings. Another reading speaks to the quality of social connections: surrounded by people yet fundamentally alone, performing friendship without experiencing real intimacy, or investing in relationships that are superficially warm but ultimately hollow. The reversal may also indicate a falling-out within a friendship group — a triangle of tensions, gossip, or betrayal that disrupts what was once a harmonious circle. Sometimes it points to exclusion: feeling shut out of a community or celebration that others share. In all cases, the question is whether your social world is genuinely nourishing or whether it is consuming energy without providing sustenance.`,
    love2: `In love, the reversed Three of Cups can indicate that an outside party — a third person, a group of friends, or a social environment — is creating tension in a relationship. This might be interference from others, incompatible social circles, or the sense that a partner's social life leaves little room for genuine connection. It can also suggest that social engagement is being used to avoid intimacy — perpetual busyness as a shield against depth.`,
    career2: `Professionally, this reversal may reflect a team or creative group that has lost its cohesion. What was once a genuinely collaborative environment may have become competitive, cliquey, or fragmented by interpersonal tension. Office politics, gossip, or favouritism can all produce this dynamic. Alternatively, a celebration or reward may feel hollow — a milestone reached without the sense of genuine accomplishment or connection that would make it meaningful.`,
    spirit2: `Spiritually, the reversed Three of Cups points to the shadow side of spiritual community: the ways that group belonging can become tribal, exclusive, or performative. When a community becomes more concerned with its own internal culture than with genuine growth, something essential is lost. If your spiritual practice has become mostly social — about belonging rather than transformation — this card invites you to reconnect with why you began.`,
    faq: [
      {
        q: 'What does the Three of Cups mean in tarot?',
        a: 'The Three of Cups represents community, celebration, and the particular joy that arises from genuine belonging. It speaks to friendships and social bonds that nourish rather than drain — connections where you can be fully yourself and feel genuinely supported. Beyond the social dimension, it also represents creative collaboration and the amplified energy that emerges when like-minded people work together toward something they all care about. In readings, it often marks a period of social abundance or signals that support is available from your wider community if you are willing to reach out and receive it.',
      },
      {
        q: 'Is the Three of Cups a yes or no card?',
        a: 'The Three of Cups is generally a yes card, particularly for questions involving social situations, events, celebrations, creative collaborations, and questions about support from friends or community. Its energy is joyful and expansive. If you are asking whether to attend a gathering, pursue a creative collaboration, or whether friends will be supportive, this card says yes. Reversed, it becomes a more cautious response — perhaps yes to connection but with a note to examine whether the social situation in question is genuinely nourishing or whether it involves excess, superficiality, or conflict.',
      },
      {
        q: 'What does the Three of Cups mean in love?',
        a: 'In love readings, the Three of Cups most often speaks to the social context of a relationship rather than the relationship itself. It may indicate that friends play an important role in a connection — perhaps a romance that blossoms within a friend group, or an existing relationship that is strengthened by a warm social circle. It can also suggest that shared enjoyment, laughter, and celebration are important qualities in the love you are seeking or experiencing. In some readings it signals the reunion of people who were once close and have been separated.',
      },
    ],
  },

  'four-of-cups': {
    up2: `The Four of Cups occupies a psychologically rich territory that is often misread as simple dissatisfaction. The figure seated beneath the tree is not ungrateful — they are absorbed. Their inner world has become so consuming that what is being offered from outside is momentarily invisible to them. This is the territory of rumination, of deep inward preoccupation, of a mind turning its own concerns over and over while life continues to extend its offerings. The card speaks to the way that introspection, when it becomes excessive or habitual, can tip from productive reflection into a kind of paralysis. It also describes a particular emotional state: jadedness, the sense that what is on offer has already been tried and found wanting, or the numbing that follows overstimulation. However, there is another reading: sometimes withdrawal is genuinely necessary. The Four of Cups can represent a legitimate period of emotional rest and reassessment before re-engaging with the world.`,
    rev2: `When the Four of Cups reverses, the figure under the tree finally looks up. The inward gaze opens outward again, and what was invisible becomes visible: opportunity, connection, possibility. This is often a welcome shift — the end of a period of stagnation, apathy, or withdrawal. Energy that was locked in rumination begins to flow again toward engagement with the world. However, reversal can also mean a different kind of opening that is less comfortable: a forced awakening. Circumstances outside your control compel you to re-engage before you feel ready. The cocoon of introspection is interrupted. In either case, the reversed Four of Cups signals movement out of stasis. The quality of that movement — whether it feels liberating or jarring — depends largely on context. Either way, something that was held inward is now in motion.`,
    love2: `In love, the reversed Four of Cups often signals renewed openness after a period of emotional withdrawal. Someone who had been closed off, preoccupied, or emotionally unavailable begins to re-engage. If you have been in a holding pattern — neither fully present in a relationship nor willing to leave it — this reversal suggests that stance is shifting. An offer of connection or commitment that was previously overlooked may now be seen clearly and considered seriously.`,
    career2: `Professionally, this reversal marks the end of a motivational drought. Work that felt pointless or unrewarding may regain its meaning, or a new opportunity presents itself that finally feels worth pursuing. The reversal can also indicate that a period of deliberate reflection or sabbatical is ending: you have processed what needed processing and are ready to re-engage. Ideas that were incubating during a quieter period may now be ready to bring into action.`,
    spirit2: `Spiritually, the reversed Four of Cups describes a reawakening. A practice or path that had grown stale or mechanical suddenly feels alive again. The divine cup being offered — which the upright figure refused to notice — is accepted. This often happens not through effort but through a moment of genuine openness: a conversation, an encounter in nature, or simply a willingness to stop resisting what is being offered.`,
    faq: [
      {
        q: 'What does the Four of Cups mean in tarot?',
        a: 'The Four of Cups describes a state of emotional withdrawal and inward preoccupation. The figure in the card sits absorbed in contemplation, unaware of — or uninterested in — what is being offered from the outside world. This card speaks to apathy, jadedness, dissatisfaction, or a legitimate need for introspective solitude. It is not inherently negative: sometimes withdrawal from external stimulation is exactly what the psyche needs. However, when the withdrawal has become habitual or defensive, this card is a gentle prompt to look up and notice what life is extending in your direction.',
      },
      {
        q: 'Is the Four of Cups a yes or no card?',
        a: 'The Four of Cups is generally a no — or more precisely, a not yet. It describes a state of disengagement, apathy, or inward withdrawal that is not conducive to forward movement. If you are asking about whether to pursue something, this card suggests you are not fully present or enthusiastic enough to give it your best, and that proceeding from this place may lead to half-hearted results. It encourages you to first address the underlying disengagement. Reversed, it shifts toward a conditional yes — movement becomes possible once the period of withdrawal has served its purpose.',
      },
      {
        q: 'What does the Four of Cups mean in love?',
        a: 'In love readings, the Four of Cups often points to emotional unavailability — in yourself, in a partner, or in the dynamic between you. Someone is withdrawn, preoccupied, or going through the motions without genuine presence. It can also describe the feeling of being unimpressed by available options: a sense that nothing on offer matches what you are looking for, whether or not that assessment is accurate. For singles, it may indicate that you are not yet open enough for connection to take root, regardless of who comes along. For couples, it points to a phase of emotional distance that needs addressing.',
      },
    ],
  },

  'five-of-cups': {
    up2: `The Five of Cups is one of the most psychologically honest cards in the deck. It does not sanitise grief or rush toward silver linings. The figure in the traditional image stands before three spilled cups — genuine losses, genuine sorrows — while behind them two cups remain standing, but they have not turned around to see them. This is not a character flaw; this is grief. In the acute phase of loss, the mind is drawn helplessly toward what is gone. The capacity to notice what remains comes later, and forcing it prematurely can be a form of emotional bypassing. What this card asks for, at its deepest level, is the courage to feel the loss fully rather than deflect from it. Grief that is genuinely processed — rather than suppressed or dramatised — eventually transforms. The tears depicted in many versions of this card are not weakness; they are the body's way of releasing what the mind is trying to hold.`,
    rev2: `The reversed Five of Cups marks a turning point in grief — the moment when the gaze finally shifts from the spilled cups to the ones still standing. This is not a denial of what was lost but a genuine reorientation: a willingness to carry the loss forward as part of your story rather than letting it define the whole of your present. The reversal often coincides with a natural readiness to re-engage with life, not because the grief is fully resolved but because the acute phase has passed and something in you is ready to move. It can also indicate that a previously avoided or suppressed grief is finally being acknowledged and processed — the turn is inward rather than forward, but it is still a turning. In some readings, the reversed Five signals reconciliation or the repair of something that seemed permanently broken.`,
    love2: `In love, the reversed Five of Cups suggests recovery from heartbreak or disappointment. The acute pain of a loss — whether a relationship ending, a betrayal, or an unmet hope — is beginning to ease. You are becoming capable of hope again, of noticing what remains available to you. This does not mean the wound is gone; it means you are learning to carry it rather than being immobilised by it. A new relationship may be possible, or an existing one may enter a period of healing.`,
    career2: `Professionally, this reversal signals the end of a period of demoralisation or disappointment. A failed project, a rejected application, or a professional setback that felt crushing begins to lose its grip. The lessons embedded in the failure are becoming available — you can now see what went wrong and what you would do differently. The reversal encourages you to dust yourself off and apply those lessons, rather than remaining stuck in regret or bitterness.`,
    spirit2: `Spiritually, the reversed Five of Cups represents the integration of suffering into wisdom. What was once a wound becomes a teacher. This card reversed often appears in the lives of people who have been through genuine difficulty and are beginning to find meaning in it — not because the pain was secretly good but because meaning can be made from almost anything when we are ready to look. A spiritual practice that engages honestly with loss tends to deepen rather than console superficially.`,
    faq: [
      {
        q: 'What does the Five of Cups mean in tarot?',
        a: 'The Five of Cups represents grief, loss, and the experience of disappointment — and crucially, the difficulty of seeing what remains when you are focused on what has been lost. It is a psychologically honest card that does not rush toward comfort. In readings, it may indicate the aftermath of a relationship ending, a disappointment that has not yet been processed, or a period of mourning. The card acknowledges that grief is not a problem to be solved quickly but an experience that requires time and genuine feeling. It asks whether you are allowing yourself to grieve fully, or whether you are avoiding the feeling.',
      },
      {
        q: 'Is the Five of Cups a yes or no card?',
        a: 'The Five of Cups is generally a no card, particularly for questions about whether something will work out, whether to move forward, or whether a situation will improve. Its energy is one of loss and regret rather than forward momentum. However, it is worth understanding what the no is pointing toward: this card suggests that something needs to be grieved and integrated before new energy can flow. It is not a permanent no but a no-for-now, and it asks you to honour that timing rather than forcing a premature move forward. Reversed, the answer shifts toward a tentative yes as the processing period concludes.',
      },
      {
        q: 'What does the Five of Cups mean in love?',
        a: 'In love readings, the Five of Cups most often points to grief around a relationship — a loss, a betrayal, or a significant disappointment that has left emotional residue. This might be the aftermath of a breakup, the processing of infidelity, or the recognition that a relationship has not become what you hoped it would be. The card asks whether the grief is being genuinely felt or whether it is being suppressed, dramatised, or deflected. It also gently points out that there may be more available in your emotional life than the loss currently allows you to see.',
      },
    ],
  },

  'six-of-cups': {
    up2: `The Six of Cups occupies a tender and sometimes complex space in the emotional landscape: the territory of memory, nostalgia, and the past's continued presence in the present. The traditional image of a child offering flowers to a smaller child in a golden village scene carries a warmth that is genuine — there is something real and valuable about reconnecting with the innocence, spontaneity, and pure feeling of earlier life. In psychological terms, this card speaks to the inner child: the part of the self that carries both the joys and the wounds of early experience. When the Six of Cups appears in an upright position, it often signals that the past has something to offer the present — a quality of openness, creativity, or wonder that has been overlaid by adult seriousness. It can also represent literal reconnection: people, places, or feelings from the past returning in a form that enriches the present rather than complicating it.`,
    rev2: `Reversed, the Six of Cups raises questions about the relationship between past and present that become more uncomfortable. Nostalgia, which in its healthy form reminds us of what matters, can in excess become a flight from the present — a preference for idealised memory over the complexity of what is actually happening now. The reversal may point to a pattern of living in retrospect: measuring the present by the past, grieving a lost golden age, or holding onto relationships and identities that have outgrown their usefulness. There is also a shadow dimension related to childhood: wounds from early experience that have not been examined, patterns inherited from family systems that continue to operate beneath awareness, or an unmet need for nurturing that colours adult relationships. The reversed Six asks whether the past is informing your present in healthy ways or whether it is obscuring your view of what is actually available to you now.`,
    love2: `In love, the reversed Six of Cups may indicate that past relationships or childhood patterns are casting a long shadow over present ones. You may be unconsciously seeking to recreate an early attachment dynamic — for better or worse — rather than seeing your current partner clearly. An ex re-entering your life may bring more complication than comfort. The invitation is to notice where nostalgia is functioning as avoidance of present-day intimacy.`,
    career2: `Professionally, this reversal can point to a reluctance to move forward in your career because the past feels safer or more known. You may be clinging to a role, a way of working, or a professional identity that no longer fits — because letting it go feels like losing something precious. Alternatively, patterns from early professional experiences (including family attitudes toward work and success) may be limiting what you allow yourself to pursue or achieve.`,
    spirit2: `Spiritually, the reversed Six of Cups invites examination of inherited religious or spiritual frameworks. The faith of your childhood — whether it was nourishing or damaging — continues to exert influence even when consciously rejected. This card asks whether you have genuinely examined your spiritual foundations or whether you are either uncritically repeating them or reactively fleeing from them. A more conscious relationship with your spiritual inheritance is possible.`,
    faq: [
      {
        q: 'What does the Six of Cups mean in tarot?',
        a: 'The Six of Cups represents the past, memory, nostalgia, and the influence of childhood experience on the present. It is generally a warm card — one that speaks to genuine innocence, the nourishment of sweet memories, and the possibility of reconnection with something or someone from earlier in life. At a psychological level it points to the inner child: the part of yourself that retains the capacity for wonder, spontaneity, and pure feeling. In readings it may signal that something from your past is relevant to your present situation, or that qualities you had as a child — openness, creativity, trust — are needed now.',
      },
      {
        q: 'Is the Six of Cups a yes or no card?',
        a: 'The Six of Cups is a mild yes, particularly for questions related to the past, reunion, childhood connections, and anything involving creative innocence or simple pleasure. Its energy is gentle and nostalgic rather than forceful. If you are asking whether to reconnect with someone from the past or revisit something from an earlier chapter of your life, this card is broadly encouraging. Reversed, it becomes more cautious — suggesting that while the impulse toward the past is understandable, there may be a tendency to idealise what was rather than engage honestly with what is.',
      },
      {
        q: 'What does the Six of Cups mean in love?',
        a: 'In love, the Six of Cups most frequently points to either the return of a past relationship or the influence of the past on a current one. An ex may re-enter your life — or feelings for someone from your past resurface. The card encourages a clear-eyed examination of whether this represents genuine growth and a second chance, or whether nostalgia is repainting old difficulties in flattering light. It can also describe a relationship with a particularly comfortable, familiar quality — the feeling of having known someone before, or of being accepted for who you fundamentally are rather than a curated version of yourself.',
      },
    ],
  },

  'seven-of-cups': {
    up2: `The Seven of Cups is the imagination card — and imagination, like water, can be a source of life or a force that overwhelms. The figure in the traditional image faces a cloud filled with seven different visions, each one enticing. This proliferation of possibilities is not random; it maps the specific territory of the psyche when it is operating through wishful thinking, fantasy, and escapism rather than grounded engagement with reality. The card's richness lies in the fact that not all of these visions are equally illusory: some represent genuine possibilities, others are fears masquerading as desires, and still others are distractions that would lead nowhere good. The challenge the Seven of Cups poses is one of discernment: in a field of appealing options and fantasies, how do you identify what is real and worth pursuing? This requires a capacity to sit with uncertainty rather than grasping at whatever feels most dazzling in the moment.`,
    rev2: `The reversed Seven of Cups often signals a welcome return to clarity after a period of confusion or fantasy. The fog lifts. The proliferation of illusions, distractions, and wishful thinking that characterised the upright position gives way to a clearer sense of what is actually real and what actually matters. This can feel like a relief — having one solid path forward rather than seven enticing but ultimately insubstantial ones. However, reversal can also indicate that disillusionment has arrived rather suddenly: the fantasy has collapsed and what remains in its absence is uncomfortable. The dream that sustained you turns out to have been a mirage. This is painful, but it is also the beginning of genuine orientation. In some readings the reversed Seven points to a decision finally being made after prolonged indecision — the paralysis of too many options is resolved.`,
    love2: `In love, the reversed Seven of Cups can mark the end of idealisation — seeing a partner more clearly, for better or worse. The fantasy of who they might be is giving way to who they actually are. This can be a deepening (genuine intimacy rarely survives idealisation intact) or a disappointment, depending on the gap between expectation and reality. For singles, it may signal the decision to stop waiting for a perfect scenario and begin engaging with genuine possibilities.`,
    career2: `Professionally, this reversal marks the end of indecision or pipe-dream thinking and the beginning of a concrete direction. A decision that has been deferred while you entertained multiple fantasised possibilities is finally made. The reversal can also signal that a project or career path that seemed glamorous at a distance is revealed in its actual complexity — which may be exactly the grounding you needed before committing seriously to it.`,
    spirit2: `Spiritually, the reversed Seven of Cups brings discernment. The seeker who has been dazzled by a proliferation of paths, teachers, and techniques begins to settle into a genuine practice rather than remaining perpetually attracted to whatever seems most exotic or exciting. Depth over breadth becomes the organising principle. The spiritual ego — which loves the accumulation of fascinating experiences — is asked to give way to something more patient and less glamorous.`,
    faq: [
      {
        q: 'What does the Seven of Cups mean in tarot?',
        a: 'The Seven of Cups represents the realm of fantasy, imagination, and wishful thinking — both its creative richness and its capacity to mislead. It appears when the mind is generating possibilities faster than reality can support, or when desires, fears, and illusions are difficult to distinguish from one another. In readings it often signals confusion, an overabundance of options, or a tendency to live in fantasy rather than engage with practical reality. At its best it points to genuine creative vision; at its most challenging it describes escapism or self-deception. The card invites honest discernment about what is real and what is projection.',
      },
      {
        q: 'Is the Seven of Cups a yes or no card?',
        a: 'The Seven of Cups is generally a no — or more precisely, a not yet, because the conditions for clear decision-making are not currently present. This card describes a state of confusion, illusion, or overchoice that is not a good basis for action. If you proceed from this place, you are likely acting on fantasy rather than reality. The card encourages you to ground yourself, clarify what you genuinely want versus what merely looks appealing, and wait until the fog clears before committing. Reversed, it shifts toward a qualified yes — clarity has arrived and action from a grounded place is now possible.',
      },
      {
        q: 'What does the Seven of Cups mean in love?',
        a: 'In love readings, the Seven of Cups frequently points to idealisation, wishful thinking, or confusion about what you actually want in a relationship. You may be falling in love with a fantasy version of someone rather than who they genuinely are, or you may be overwhelmed by possibilities and unable to commit to anything real. For those already in relationships, it can indicate that one or both partners are not seeing the relationship clearly — either romanticising it beyond what it is, or projecting fears onto it that distort their perception. The invitation is to bring more honesty and groundedness to how you see this situation.',
      },
    ],
  },

  'eight-of-cups': {
    up2: `The Eight of Cups depicts one of the most quietly courageous acts available to a human being: the conscious decision to leave something that no longer serves, even when nothing obviously terrible has happened, even when others might not understand the departure. The figure in the traditional image turns their back on eight carefully stacked cups — these are not broken or empty but full, orderly, neatly arranged. The leaving is not about escape from disaster; it is a response to an interior signal that this is no longer where you are meant to be. This is the card of emotional integrity: honouring the quiet but insistent voice that says I have outgrown this, or this does not sustain me any longer, or there is something more authentic waiting if I am willing to move toward it. The path in the imagery ascends through difficult terrain — this is not presented as easy. But the figure walks it anyway, guided by something internal rather than external validation.`,
    rev2: `Reversed, the Eight of Cups introduces a different quality of difficulty. The figure who was walking away in the upright position now faces a question: should I leave, or should I stay and try again? In some readings the reversal indicates a genuine return — someone who walked away from a situation comes back, perhaps with new perspective, perhaps with genuine willingness to engage differently. In others it describes a failure of nerve: the recognition that something needs to end, but an inability to act on that recognition. Fear of the unknown keeps a person tethered to what no longer works. The reversal can also point to the uncomfortable moment of wondering whether a departure was premature — second-guessing a choice that was actually correct. Discernment is needed to distinguish genuine return from regression.`,
    love2: `In love, the reversed Eight of Cups raises the question of whether to stay or go in a more explicit form. The relationship may not be fulfilling you, yet leaving feels impossibly difficult — through fear, guilt, financial entanglement, or genuine love that has become complicated. Alternatively, this reversal can signal a return to a relationship after time apart, or a decision to give it one more honest attempt before walking away. Only you can assess whether renewed effort is genuine growth or prolonged avoidance.`,
    career2: `Professionally, the reversed Eight of Cups often points to staying in a job, industry, or project that your better judgment suggests you have outgrown — out of security, habit, or fear of the uncertainty that change would bring. It can also describe someone returning to a previous career path after an attempted departure. The question is whether the return is a genuine re-engagement or a retreat. Sometimes the wisest path really is staying; sometimes it is a way of postponing necessary change.`,
    spirit2: `Spiritually, the reversed Eight of Cups can describe an inability to release a spiritual framework, tradition, or community that no longer serves your genuine development — perhaps because of identity, belonging, or fear of the unfamiliar. It can also point to someone returning to a practice they abandoned, either with fresh commitment or in a way that avoids the deeper examination that prompted the departure in the first place. Honest self-inquiry is the tool this card asks you to use.`,
    faq: [
      {
        q: 'What does the Eight of Cups mean in tarot?',
        a: 'The Eight of Cups represents the decision to leave behind something that is no longer fulfilling — not because it has become terrible, but because the inner self has recognised that it is no longer the right place or path. This is a card of emotional maturity and courage: the willingness to honour an interior signal even when leaving is difficult and others may not understand. It often appears when someone is on the verge of a significant transition — leaving a relationship, a job, a community, or a way of life — that is driven by genuine inner knowing rather than external crisis.',
      },
      {
        q: 'Is the Eight of Cups a yes or no card?',
        a: 'The Eight of Cups is a nuanced card in yes/no readings. For questions about whether to leave, move on, or walk away from something that no longer serves — it leans yes. It validates the impulse to honour your deeper needs even when the departure is difficult. For questions about whether to stay, invest more, or build further in a current situation — it tends toward no, or at least suggests examining honestly whether that investment is in something that genuinely sustains you. The card is less about external circumstances than about interior alignment: is what you are doing consistent with where you actually are?',
      },
      {
        q: 'What does the Eight of Cups mean in love?',
        a: 'In love readings, the Eight of Cups is one of the most honest cards that can appear. It often signals the recognition — sometimes before the mind has fully articulated it — that a relationship has run its course emotionally. Not through dramatic failure, but through a gradual sense that the connection no longer feeds what is deepest in you. This is not a card that encourages impulsive departure, but it does validate the experience of knowing in your body that something has ended before the formal ending. It asks whether you are staying out of genuine love or out of fear, habit, or unwillingness to face the difficulty of change.',
      },
    ],
  },

  'nine-of-cups': {
    up2: `The Nine of Cups carries the popular reputation of being the wish card — the one you want to see when asking whether something you deeply desire will come to pass. That reading has merit, but the card is more nuanced than a simple yes to whatever you want. The figure seated comfortably before their nine displayed cups represents someone who has genuinely attained what they set out to achieve in the emotional realm: contentment, satisfaction, a sense of abundance that is inward as well as outward. What is psychologically significant here is the quality of the satisfaction — it is not feverish or restless but settled. This person has arrived somewhere and they know it. The card speaks to emotional intelligence: the capacity to recognise and receive goodness when it is actually present, rather than immediately reaching for what comes next. This is rarer than it sounds, and in an anxious culture it is a genuine achievement to rest in satisfaction rather than immediately scanning for the next problem or desire.`,
    rev2: `The Nine of Cups reversed is a more uncomfortable card than its upright counterpart, and its discomfort is useful. The wish has been granted — or is about to be — and yet something is not right. Perhaps the desire itself was based on a misunderstanding of what would actually bring satisfaction; the thing you wanted turns out not to deliver what you expected it to. This is the experience of getting what you wanted and discovering it was not what you needed. The reversal may also point to overindulgence: the turning of genuine pleasure into compulsion, the use of comfort and abundance as a defence against feeling, or a satisfaction that has become complacency. There is also a shadow of materialism here — defining wellbeing purely in terms of what you have accumulated rather than what you genuinely feel. The reversed Nine invites honest examination of what you are actually seeking beneath the surface desire.`,
    love2: `In love, the reversed Nine of Cups suggests that a relationship or romantic situation, while apparently satisfying on the surface, may not be providing the genuine fulfilment it seems to promise. You may be staying out of comfort or habit rather than genuine happiness — or you may have a pattern of seeking satisfaction through love that is actually pointing to an unmet need within yourself. The card asks what you are really looking for beneath the surface wish.`,
    career2: `Professionally, this reversal can indicate that achieving a long-held goal has brought disappointment rather than the expected satisfaction — the promotion arrived but the fulfilment did not. Alternatively, it points to complacency: resting so thoroughly on past achievements that growth and genuine engagement have stalled. The comfort has become a ceiling. The reversed Nine invites honest assessment of whether your current work life is genuinely nourishing or merely comfortable.`,
    spirit2: `Spiritually, the reversed Nine of Cups points to a kind of spiritual materialism — the accumulation of experiences, insights, or credentials as a form of ego-enhancement rather than genuine opening. The spiritual seeker who collects peak experiences without allowing them to fundamentally change how they live is operating in this space. True contentment, in the spiritual sense, is not something that can be accumulated; it arises when seeking itself softens.`,
    faq: [
      {
        q: 'What does the Nine of Cups mean in tarot?',
        a: 'The Nine of Cups is widely known as the wish card — the card of contentment, emotional satisfaction, and the genuine attainment of something you have deeply desired. It represents a moment of real abundance in the inner life: not the frantic accumulation of pleasures but a settled sense that you have arrived somewhere good. In readings it often signals that desires are being fulfilled, that emotional and material life are in alignment, and that there is genuine cause for gratitude and satisfaction. It is a card that encourages you to receive what is present rather than immediately seeking what comes next.',
      },
      {
        q: 'Is the Nine of Cups a yes or no card?',
        a: 'The Nine of Cups is one of the most affirmative yes cards in the deck, particularly for questions about whether a desired outcome will materialise. It is often called the wish card precisely because of this quality. For questions about happiness, fulfilment, the success of something you care about, or whether conditions are ripe for something you want — this card says yes with warmth. Even reversed, the energy does not fully invert: it raises questions about the quality of what is being granted rather than denying the grant itself. The yes may come with a note about what genuine satisfaction actually requires.',
      },
      {
        q: 'What does the Nine of Cups mean in love?',
        a: 'In love readings, the Nine of Cups is genuinely encouraging — it points to emotional satisfaction, mutual happiness, and the experience of a relationship that genuinely nourishes. For those seeking partnership, it often signals that what you are looking for is genuinely available and may be closer than you think. For those already in relationships, it describes a period of real contentment and appreciation — a phase where the relationship is experienced as a source of genuine wellbeing rather than effort or anxiety. It is a card that encourages you to recognise and receive the love that is present.',
      },
    ],
  },

  'ten-of-cups': {
    up2: `The Ten of Cups represents the emotional suit's fullest expression: not merely personal satisfaction but the flourishing of love within a larger context — family, community, belonging. The traditional image of figures celebrating before a rainbow arc of cups, with the landscape spread around them, suggests that this wellbeing is not fragile or contingent but has become the atmosphere of a life. Psychologically, the card speaks to something that takes considerable time and work to construct: the experience of feeling genuinely at home — in a relationship, in a family, in a community, in one's own life. This is not presented as an effortless gift but as something that is earned through sustained care, honest communication, and the willingness to remain present through difficulty. The Ten of Cups is not perfection; it is the realisation that the life you have, imperfect and real, is also genuinely good. That recognition — arriving without requiring circumstances to be otherwise — is its own form of grace.`,
    rev2: `The reversed Ten of Cups cracks open the picture of family or community harmony to reveal what lies beneath the surface presentation. This may be the experience of family dysfunction that is denied or concealed — the household that appears happy to outsiders while its members carry unspoken tensions, unresolved conflicts, or deep disconnections. The reversal may also describe the specific pain of feeling like an outsider within a group that is supposed to be yours: the family where you have never quite belonged, the community whose values don't match your own. Another dimension is the gap between the ideal you carry and the reality you inhabit — the way that a fixed idea of what family or home should look like prevents genuine appreciation of what actually is. The reversed Ten asks where the image of happiness is being maintained at the expense of honest engagement with what is actually true.`,
    love2: `In love, the reversed Ten of Cups points to a gap between the idealised picture of partnership and the reality being experienced. A relationship may look harmonious from the outside — and both partners may be working hard to maintain that appearance — while genuine connection and happiness have quietly eroded inside. The reversal asks whether you are living in a real relationship or a performance of one. Honest conversation is more likely to restore genuine happiness than continued maintenance of the facade.`,
    career2: `Professionally, this reversal often reflects a mismatch between work life and personal values — the sense that what you do for a living does not align with what you hold most dear in your inner life. Success may have been achieved by external measures while something essential remains unaddressed. It can also describe workplace cultures that present as familial or community-oriented while actually operating through hierarchy, exclusion, or manipulation. Seeing these dynamics clearly is the beginning of navigating them more honestly.`,
    spirit2: `Spiritually, the reversed Ten of Cups may reflect disillusionment with an idealised spiritual community that has revealed its human failings — the teacher who disappoints, the community that fractures, the tradition that turns out to be more complicated than it appeared. This is not a reason to abandon spiritual life but an invitation to encounter it more honestly: stripped of idealism, what remains that is genuinely worth holding?`,
    faq: [
      {
        q: 'What does the Ten of Cups mean in tarot?',
        a: 'The Ten of Cups represents the fullest expression of the emotional realm: lasting happiness within the context of family, home, and deep belonging. Unlike the Nine of Cups, which speaks to personal satisfaction, the Ten extends that fulfilment into relationship and community. It is the card of genuine domestic harmony and emotional abundance — the sense of having built a life worth living. In readings it often signals a period of real happiness and gratitude, or points toward what is available when the work of building genuine connection is honoured and sustained. It is a card of arrival, of having come home.',
      },
      {
        q: 'Is the Ten of Cups a yes or no card?',
        a: 'The Ten of Cups is a wholehearted yes — one of the most unambiguously positive cards in the deck. For questions about family, relationships, home life, emotional wellbeing, and the possibility of genuine happiness, it says yes with warmth and conviction. It suggests that conditions are genuinely aligned for the kind of lasting fulfilment that the question is reaching toward. Reversed, the yes becomes more conditional: genuine happiness is possible but requires honesty about what is currently obscuring it, rather than continuing to maintain a comforting but inaccurate picture of the situation.',
      },
      {
        q: 'What does the Ten of Cups mean in love?',
        a: 'In love readings, the Ten of Cups is one of the most beautiful cards that can appear. It describes deep, lasting emotional fulfilment within a relationship — not the excitement of early romance but the settled, deeply sustaining happiness of a genuine partnership that has been built over time. It often signals that a relationship has the qualities necessary for long-term happiness: genuine care, compatible values, emotional safety, and a shared sense of what matters. For those seeking love, it points toward the possibility of exactly this kind of connection. It is a card worth taking seriously when it appears.',
      },
    ],
  },

  'page-of-cups': {
    up2: `The Page of Cups brings the fresh, undefended quality of beginner's mind to the emotional realm. Of all the court cards, Pages carry the energy most open to surprise — they have not yet accumulated the certainties and armour that come with more experience. The Page of Cups specifically invites the kind of emotional openness that allows unexpected feelings, intuitions, and creative impulses to surface and be received without immediate dismissal. In the traditional imagery a fish emerges from the Page's cup — a symbol of something rising from the unconscious that the Page regards with delight rather than alarm. This is a psychologically significant posture: the willingness to be surprised by your own inner life, to let what is arising within you become visible rather than immediately managed. The Page of Cups also speaks to the beginning of a creative or intuitive process, or to someone who is learning to trust their emotional and imaginative responses as valid forms of knowing.`,
    rev2: `Reversed, the Page of Cups loses some of its charming openness and begins to show the shadow of emotional immaturity or fragility. The sensitivity that is a gift when it enables genuine feeling and creativity becomes a liability when it slides into excessive reactivity, inability to tolerate discomfort, or difficulty distinguishing between genuine intuition and wishful thinking. The reversed Page may describe someone who is easily wounded by perceived slights, whose emotional responses are out of proportion to events, or who retreats into fantasy or escapism when reality becomes uncomfortable. There is also an element of creative or emotional stagnation: the inspiration has not arrived, the inner well feels empty, or the imaginative impulse cannot find its way to expression. In some cases the reversal points to emotional news or information that is delayed, unclear, or not what was hoped.`,
    love2: `In love, the reversed Page of Cups often points to emotional immaturity — in yourself or in someone you are involved with. This may manifest as difficulty with vulnerability (hiding behind humour or deflection), excessive neediness, the inability to manage difficult feelings without seeking external reassurance, or a pattern of falling intensely and then retreating when genuine intimacy becomes demanding. The potential for real feeling is present, but it needs more development before it can sustain a mature relationship.`,
    career2: `Professionally, the reversed Page of Cups may indicate that a creative or imaginative gift is not yet finding reliable expression. Inspiration comes in fits and starts, self-doubt interrupts the creative process, or the emotional sensitivity that fuels creativity also makes external criticism feel devastating. The reversal encourages patience with the development process and suggests building a more resilient creative practice rather than waiting for inspiration to arrive fully formed and indestructible.`,
    spirit2: `Spiritually, the reversed Page of Cups describes someone who is beginning to open to their intuitive and inner life but whose development is uneven. Flashes of genuine insight alternate with confusion and wishful thinking. Discernment — the ability to distinguish genuine inner knowing from projection and fantasy — is the skill that needs cultivation. A trusted guide or consistent practice can help ground what would otherwise remain scattered and unreliable.`,
    faq: [
      {
        q: 'What does the Page of Cups mean in tarot?',
        a: 'The Page of Cups represents emotional openness, creative sensitivity, and the beginner\'s willingness to be surprised. As the apprentice of the Cups suit, this card brings a quality of receptivity and wonder to the emotional and intuitive realm — an openness to what is arising from within without immediately categorising or dismissing it. In readings it may represent an actual person with these qualities, or it may point to a phase in your own development characterised by emotional learning, creative exploration, or the arrival of intuitive messages that invite genuine attention. It is a card of potential rather than achievement.',
      },
      {
        q: 'Is the Page of Cups a yes or no card?',
        a: 'The Page of Cups is a gentle yes, particularly for questions involving creativity, intuition, emotional openness, and new beginnings in the feeling realm. Its energy is receptive and encouraging rather than boldly affirmative. If you are asking whether to pursue a creative impulse, trust an intuitive sense, or open yourself to a new emotional experience — this card says yes, and with warmth. Reversed, it becomes a more cautious response: the potential is there, but emotional immaturity or lack of discernment may mean that more development is needed before the yes fully lands.',
      },
      {
        q: 'What does the Page of Cups mean in love?',
        a: 'In love readings, the Page of Cups often signals the arrival of romantic news or the beginning of a tender, emotionally open connection. It describes love in its less armoured form — the quality of genuine emotional availability, of being willing to be affected and surprised by another person. This card may represent someone entering your life with an open and sensitive quality, or it may describe your own readiness to approach love with freshness rather than defensiveness. For existing relationships, it can signal a return to playfulness, creativity, and the kind of openness that characterises the early stages of genuine connection.',
      },
    ],
  },

  'knight-of-cups': {
    up2: `The Knight of Cups is the romantic archetype of the Cups court — the figure who approaches life's emotional and creative dimensions with idealism, imagination, and a quality of inspired longing. Where other Knights charge forward with aggression or pragmatism, the Knight of Cups moves at a different pace: they are drawn by what calls to the heart rather than what logic recommends. This is the card of the artist, the romantic, the person who makes decisions from feeling rather than calculation and who genuinely believes that the interior life is worth following wherever it leads. The Knight's strength is their capacity to feel deeply, to inspire others, and to pursue what is beautiful and meaningful with genuine commitment. Their challenge is the tendency to mistake intensity for depth, to fall in love with the idea of something rather than its reality, or to pursue one vision until the next compelling vision appears and redirects their attention entirely. The Knight of Cups is most powerful when feeling is combined with follow-through.`,
    rev2: `Reversed, the Knight of Cups takes on a more difficult quality. The idealism that was inspiring in the upright position becomes a kind of evasion: the romantic who cannot commit to anything real, the artist who endlessly talks about their vision but never produces the work, the partner who sweeps you off your feet and then cannot sustain the connection past the initial intensity. There is also a shadow of emotional manipulation here — charm used consciously or unconsciously to get what is wanted without genuine regard for the other person. The reversed Knight may also describe someone in the grip of disordered emotional life: mood volatility, impulsiveness driven by feeling rather than wisdom, or self-deception disguised as intuition. In either case, the reversal asks whether emotional energy is being channelled toward what genuinely matters or whether it is dissipating in fantasy, manipulation, or inconstancy.`,
    love2: `In love, the reversed Knight of Cups is a caution. This energy can be intensely appealing — romantic, imaginative, emotionally present in a way that feels rare — but it may not translate into the sustained, honest engagement that genuine partnership requires. Watch for patterns of idealisation followed by disappointment, charm that does not match depth of character, or promises that are enthusiastically made and quietly abandoned. The sweep of feeling is real; whether it can be sustained is the question.`,
    career2: `Professionally, the reversed Knight of Cups often describes creative energy that is scattered or undisciplined. Many projects begun and few completed, inspiration that arrives powerfully and then abandons the hard work of execution, or a career path that keeps changing direction in response to whichever new vision seems most compelling. The gift is real — the imagination, the sensitivity, the creative responsiveness — but it needs structure and commitment to produce anything that lasts.`,
    spirit2: `Spiritually, the reversed Knight of Cups may describe a seeker who is perpetually in motion: attracted to one teacher, tradition, or practice and then the next, always in pursuit of the next peak experience or profound insight, but never settling long enough for genuine transformation to occur. The spiritual journey is being experienced as a series of exciting encounters rather than a deepening. The invitation is to slow down and go deeper rather than wider.`,
    faq: [
      {
        q: 'What does the Knight of Cups mean in tarot?',
        a: 'The Knight of Cups represents the archetype of the romantic idealist — someone who pursues what calls to the heart with imagination, sensitivity, and genuine passion. This is the card of the artist, the dreamer, the person who moves through the world guided by feeling and inspired longing rather than calculation. In readings it may represent an actual person with these qualities entering your life, or it may describe your own approach to a situation: leading with the heart, following what is beautiful and meaningful, bringing an emotionally open and creative quality to what you are doing. At its best this energy is inspiring and genuinely moving.',
      },
      {
        q: 'Is the Knight of Cups a yes or no card?',
        a: 'The Knight of Cups is generally a yes card, particularly for questions involving romance, creative pursuits, following your heart, and emotionally motivated decisions. It encourages moving toward what you feel called to rather than holding back out of caution. However, it carries an implicit note about the quality of the yes: this card asks that you combine genuine feeling with some degree of follow-through and honest self-examination. A yes that is driven by romantic fantasy alone may not survive contact with reality. Reversed, it shifts toward a more cautious response — the impulse is genuine but the execution or intention needs examination.',
      },
      {
        q: 'What does the Knight of Cups mean in love?',
        a: 'In love, the Knight of Cups is one of the most romantically evocative cards in the deck. It often signals the arrival of a romantic figure or the beginning of a relationship characterised by genuine passion, emotional depth, and a quality of courtship — being actively pursued, or pursuing, with genuine intention and feeling. This card celebrates love as an adventure of the heart. The caution is simply to assess whether the intensity is matched by substance: the Knight\'s feeling is real, but the test of genuine romantic love is whether it deepens over time or whether it was primarily intensity mistaken for depth.',
      },
    ],
  },

  'queen-of-cups': {
    up2: `The Queen of Cups embodies perhaps the most psychologically complex form of emotional intelligence in the court cards: the ability to be fully present to one's own feeling life and the emotional reality of others, while maintaining sufficient inner stability to remain grounded rather than overwhelmed. This is an exceptionally difficult balance. The Queen does not avoid difficult feelings — her own or anyone else's — but she has developed the inner container that allows her to hold them without being destabilised. In the traditional imagery she holds a covered cup, suggesting an interior life that is rich and deep but not indiscriminately on display. She knows her own depths. This makes her profoundly trustworthy: people sense that she can hold what they bring her without flinching or deflecting. The Queen of Cups speaks to therapeutic skill, creative empathy, intuitive intelligence, and a way of relating that makes others feel genuinely seen — not as a category or a problem to be solved, but as a full human being.`,
    rev2: `Reversed, the Queen of Cups reveals what happens when emotional sensitivity loses its grounding. The intuitive permeability that is a gift in the upright position becomes a vulnerability: absorbing others' emotional states as your own, feeling responsible for the wellbeing of everyone around you, or finding the boundary between your feelings and someone else's chronically unclear. This can manifest as co-dependency, the tendency to lose oneself in relationships, or the exhaustion that comes from perpetually attending to others while neglecting one's own needs. The reversal may also point to emotional manipulation — using sensitivity and emotional intelligence not to serve genuine connection but to influence, guilt, or bind others. It can also describe someone who is overwhelmed by their own inner life: emotions that feel unmanageable, mood instability, or a tendency to fall into the depths without the capacity to return to the surface.`,
    love2: `In love, the reversed Queen of Cups often points to patterns of emotional over-investment or co-dependency. The love you offer may be genuine and deep, but it may also come tangled with the need to be needed, or with a tendency to absorb your partner's emotional world as more important than your own. Alternatively, this reversal can describe a partner whose emotional volatility or manipulation makes it difficult to maintain your own clear sense of self within the relationship. Healthy boundaries serve love rather than threatening it.`,
    career2: `Professionally, the reversed Queen of Cups may describe someone in a caring profession — therapy, medicine, teaching, social work — who has lost themselves in service to others and is approaching or experiencing burnout. The empathic gift has outrun the inner resource needed to sustain it. Alternatively, it can indicate that emotional reactivity is interfering with professional effectiveness: decision-making driven by emotional states rather than clear assessment, or interpersonal dynamics coloured by unprocessed personal material.`,
    spirit2: `Spiritually, the reversed Queen of Cups points to the shadow of psychic or spiritual sensitivity: becoming so open to what is flowing through that the capacity to distinguish your own experience from what you are receiving from others or the environment is compromised. Grounding practices — earthing the body, maintaining clear boundaries, returning regularly to ordinary practical life — are the specific medicine this reversal recommends. Openness without roots is not strength; it is vulnerability.`,
    faq: [
      {
        q: 'What does the Queen of Cups mean in tarot?',
        a: 'The Queen of Cups represents the mature, grounded expression of emotional intelligence: the capacity to feel deeply, intuit accurately, and be fully present to the inner life — both your own and others\' — without losing your footing. She embodies empathy without co-dependency, sensitivity without overwhelm, and genuine care without the need for control. In readings she may represent an actual person with these qualities, or she may describe the qualities that are called for in your current situation: depth of feeling, compassionate presence, attunement to what is beneath the surface, and the willingness to trust your intuitive read of a situation.',
      },
      {
        q: 'Is the Queen of Cups a yes or no card?',
        a: 'The Queen of Cups leans toward yes, particularly for questions involving emotional matters, intuitive decisions, relationships, care, and creative work. Her energy is warm and receptive, and she tends to encourage following genuine feeling rather than suppressing it. However, she is a card that also asks you to bring wisdom and inner stability to your emotional responses — her yes is never about recklessness or wishful thinking, but about trusting what you genuinely feel when you are properly centred. Reversed, her answer becomes more cautious: check whether your emotional read of the situation is clear, or whether overwhelm, projection, or co-dependency is colouring it.',
      },
      {
        q: 'What does the Queen of Cups mean in love?',
        a: 'In love readings, the Queen of Cups describes a relationship characterised by deep emotional attunement — the experience of being genuinely known, held, and understood by another person. She may represent a partner with exceptional empathic gifts, or she may describe what you yourself are bringing to love: a quality of genuine presence and emotional depth that makes real intimacy possible. For those seeking love, this card often signals that you are ready for — and capable of — a connection that operates at genuine emotional depth rather than remaining at a more guarded surface level.',
      },
    ],
  },

  'king-of-cups': {
    up2: `The King of Cups represents the fullest possible integration of emotional intelligence with the capacity for wise, grounded action in the world. Where the Queen of Cups is oriented inward — maintaining the depth and stability of the inner world — the King brings that emotional depth into outward leadership, decision-making, and the management of complexity. He sits on a throne in the midst of a turbulent sea, yet he remains steady: this is not a man who avoids the depths but one who has genuinely mastered them, so that what was once potentially overwhelming has become a source of authority. Psychologically, the King of Cups represents the achievement of emotional integration: the capacity to acknowledge and work with the full range of feeling without being driven by it, to make decisions from a place of genuine wisdom rather than reactivity or denial. This is exceedingly rare and represents considerable developmental work. His authority in emotional matters is earned, not assumed.`,
    rev2: `Reversed, the King of Cups describes the disruption of emotional mastery — either its absence in someone who presents with authority, or a temporary collapse of one's own hard-won equilibrium. One manifestation is the emotionally manipulative authority figure: someone who appears wise and containing but actually uses their understanding of emotional dynamics to control, withhold, or manipulate those around them. The therapy that becomes enmeshment, the leader whose apparent care masks the need for admiration — these are the reversed King's shadows. Another reading describes someone whose emotional suppression has become so thoroughgoing that genuine feeling is inaccessible: the person who prides themselves on being unaffected, who mistakes numbness for mastery. A third dimension is the collapse of previously maintained equilibrium under excessive pressure, resulting in emotional volatility, moodiness, or addictive patterns that were previously held at bay.`,
    love2: `In love, the reversed King of Cups raises questions about genuine emotional availability versus the appearance of it. A partner may seem wise, calm, and containing — but this containment may be emotional distance dressed in mature clothing. Alternatively, someone who normally maintains admirable equilibrium may be going through a period of emotional instability that is making them difficult to be close to. The question is whether genuine feeling and genuine vulnerability can be accessed beneath the composed exterior.`,
    career2: `Professionally, the reversed King of Cups can describe a leader or authority figure whose emotional intelligence is actually emotional manipulation — using understanding of others' feelings and vulnerabilities to maintain power rather than genuinely serve the organisation or team. It can also describe your own difficulty maintaining emotional equilibrium at work: decision-making influenced by unprocessed personal material, or the exhaustion of constantly managing your emotional presentation in a demanding professional environment.`,
    spirit2: `Spiritually, the reversed King of Cups points to the danger of premature authority — someone who has developed genuine gifts of empathy, intuition, or spiritual wisdom but has not yet done the full work of integrating their shadow material, and who then claims a teaching or guiding role from that incomplete foundation. The result is wisdom that is real but partial, and a blind spot that may cause unintentional harm. The remedy is continued honest self-examination alongside any guiding of others.`,
    faq: [
      {
        q: 'What does the King of Cups mean in tarot?',
        a: 'The King of Cups represents the mature, integrated mastery of the emotional realm — the capacity to feel deeply, understand others with genuine empathy, and nevertheless make wise, grounded decisions in the world without being driven by reactive emotion. He is the emotionally intelligent leader: someone whose authority comes not from the suppression of feeling but from its genuine integration. In readings he may represent an actual person with these qualities — a mentor, therapist, or trusted authority — or he may describe the qualities your situation is calling you toward: emotional wisdom combined with the capacity for clear, compassionate action.',
      },
      {
        q: 'Is the King of Cups a yes or no card?',
        a: 'The King of Cups is generally a yes card, particularly for questions that require emotional wisdom, compassionate leadership, or decisions that must balance feeling with clear-headed judgement. His energy is authoritative and stabilising — he has navigated the depths and returned with something solid. For questions about whether to trust someone in an authority or advisory role, or whether you yourself are ready to take on a position of emotional responsibility, this card offers confident encouragement. Reversed, the answer becomes more guarded: examine whether the wisdom being offered — or claimed — is as integrated as it appears.',
      },
      {
        q: 'What does the King of Cups mean in love?',
        a: 'In love readings, the King of Cups describes a partner or potential partner who brings genuine emotional maturity to a relationship: someone who can be present with difficulty without deflecting, who understands their own emotional life well enough to navigate yours with care, and who leads with wisdom rather than reactivity. This is a rare and genuinely valuable quality in a partner. The card may also describe what you are ready to bring to love: a combination of emotional depth, self-knowledge, and the stability that allows genuine intimacy to develop and deepen over time without becoming destabilised by the inevitable difficulties of close relationship.',
      },
    ],
  },
  'ace-of-swords': {
    up2: `The Ace of Swords arrives at that precise moment when fog clears and you see a situation with sudden, unambiguous lucidity. This is the mind at its sharpest — not cold or cruel, but incisive. Where other aces speak of gentle beginnings, this one cuts through. It heralds the courage to name what is true even when doing so is uncomfortable, to begin a difficult conversation, to commit to intellectual honesty over comfortable self-deception. In a broader context, the Ace of Swords often precedes a period of significant mental effort: a project demanding rigorous thinking, a decision requiring you to weigh options without sentimentality, or a breakthrough in understanding that reshapes how you perceive a longstanding problem. The sword is double-edged because truth, once spoken, cannot be unspoken. This card asks whether you are ready for that kind of clarity — and suggests that, in this moment, you are.`,
    rev2: `When the Ace of Swords falls reversed, the sword's edge turns inward or becomes tangled, and the clarity it promises is blocked. There may be confusion masquerading as certainty — strong opinions formed without sufficient information, or a rush to conclusions that bypasses careful reasoning. Reversed, this card sometimes flags that harsh words have been spoken or are being contemplated without the wisdom to know when silence serves better. It can also point to a creative or intellectual block: the ideas are there, but something prevents them from taking coherent form. Occasionally the reversal suggests wilful avoidance of a truth that would require action — keeping yourself deliberately muddled because clarity would demand something of you. The invitation here is to slow down, re-examine your assumptions, gather more information, and ask honestly whether your current certainty is earned or merely convenient.`,
    love2: `In relationships, a reversed Ace of Swords often signals that an important conversation is being avoided, or that words spoken in anger have created distance. One or both partners may be clinging to their own version of events rather than seeking shared understanding. There is a tendency here toward cutting remarks or intellectual sparring that wounds rather than resolves. The path forward involves choosing honesty over being right.`,
    career2: `At work, this reversal may manifest as muddled communication, projects stalled by unclear briefs, or a decision that keeps being deferred because the thinking behind it hasn't solidified. You or your team may be operating on faulty assumptions. It is worth pausing to re-examine the foundation of a plan before pushing further. Getting input from a clear-headed colleague can help restore the clarity this card promises in its upright position.`,
    spirit2: `Spiritually, the reversed Ace of Swords invites examination of beliefs held more from habit or inheritance than from genuine enquiry. Mental noise — anxious looping, over-analysis, or compulsive certainty — may be crowding out genuine insight. The practice here is one of stillness: creating space in the mind for truth to surface on its own terms rather than forcing conclusions.`,
    faq: [
      {
        q: 'What does the Ace of Swords mean in tarot?',
        a: 'The Ace of Swords is the seed of the Swords suit — an emblem of mental clarity, truth, and the courage to cut through confusion. It represents a breakthrough moment: a new idea, a clear decision, or the will to speak honestly about something that has long gone unsaid. Because swords govern the realm of the mind, this ace is about intellectual power — the capacity to think rigorously, communicate directly, and face reality without flinching. It is not a comfortable card so much as a clarifying one, suggesting that honesty, however sharp, leads to better outcomes than comfortable evasion.',
      },
      {
        q: 'Is the Ace of Swords a yes or no card?',
        a: 'Upright, the Ace of Swords generally leans toward yes — particularly for questions involving decisions, new beginnings, creative projects, or situations requiring clarity and directness. It favours action grounded in honest assessment. However, it is worth noting that the "yes" the Ace of Swords offers may come with a requirement: you must be willing to see things clearly and act on what you find, even if that is inconvenient. Reversed, the answer tends toward "not yet" — suggesting that more information or clearer thinking is needed before moving forward.',
      },
      {
        q: 'What does the Ace of Swords mean in love?',
        a: 'In a love reading, the Ace of Swords signals that clarity and honest communication are at the heart of the matter. It can indicate a relationship beginning with genuine intellectual connection and straightforward intentions, or a moment where an important truth needs to be spoken — perhaps a direct declaration of feelings, or an honest conversation about where things stand. It may also appear when someone needs to clear the air after a period of confusion or ambiguity. The Ace of Swords in love is not particularly romantic in a soft sense, but it promises that honesty, even when difficult, creates more durable connection than pretence.',
      },
    ],
  },

  'two-of-swords': {
    up2: `The Two of Swords captures the particular discomfort of a decision that cannot be made from logic alone — or, equally, one that cannot be made without it. The blindfolded figure sits in deliberate balance, sword in each hand, unable or unwilling to look. This is not laziness or cowardice but a genuine stalemate in which two equally weighted options, two conflicting truths, or two competing loyalties hold each other in suspension. There is often a quality of self-protection in this card: the blindfold suggests that some part of you knows that to look clearly at the situation will require you to act, and you are not yet ready. The Two of Swords also appears when you are mediating between opposing forces — two people in conflict, or two parts of yourself that want incompatible things. The card does not rush you, but it does suggest that remaining in stalemate has its own costs, and the information you need to move forward may already be available if you are willing to look.`,
    rev2: `Reversed, the Two of Swords suggests the stalemate is breaking — though not always gracefully. The blindfold is coming off, and what is revealed may be uncomfortable. This can indicate that information previously withheld or avoided is now coming to light, forcing a decision that was long postponed. It can also signal that the paralysis has tipped into anxiety: rather than a still, considered suspension, there is now an agitated spinning of options without resolution. Occasionally the reversal points to a choice made under pressure or with insufficient information — a decision that feels necessary but is not yet fully considered. The invitation is to acknowledge what you already know, accept that no option is without risk, and take a step rather than continuing to circle.`,
    love2: `In relationships, the reversed Two of Swords often indicates that a difficult conversation can no longer be postponed. What has been kept at careful arm's length — a feeling, a conflict, a truth about the relationship — is pressing for acknowledgement. There may be a tendency for one or both people to remain emotionally guarded as a form of self-protection. The reversal asks: what would become possible if you let the swords down and allowed yourself to see clearly?`,
    career2: `At work, this reversal suggests a professional impasse is finally shifting — but perhaps not in the direction you had hoped or expected. A decision is being made for you if you won't make it yourself. Alternatively, information you lacked is now available and requires you to rethink a plan. This is an opportunity, even if it doesn't feel like one: clarity, however unwelcome, is more workable than perpetual indecision.`,
    spirit2: `Spiritually, the reversed Two of Swords speaks to the moment when the avoidance of inner truth becomes unsustainable. The stillness you have been maintaining through carefully managed not-knowing has reached its limit. Something in your inner landscape is asking to be seen directly. Contemplative practice can help here — not to escape the discomfort but to sit with it long enough for genuine insight to emerge.`,
    faq: [
      {
        q: 'What does the Two of Swords represent?',
        a: 'The Two of Swords represents a state of mental impasse — a moment when two competing options, loyalties, or truths hold each other in balance, making it impossible to move forward easily. The classic image of a blindfolded figure holding two crossed swords speaks to deliberate avoidance: the refusal or inability to look at a situation directly, often because doing so would require action. It is a card of difficult decisions, stalemates, and the particular stress of not-knowing. It does not represent permanent paralysis, but a liminal state that requires patience, self-honesty, and eventually the courage to choose.',
      },
      {
        q: 'Does the Two of Swords mean someone is lying?',
        a: 'Not directly, though deception — including self-deception — can be part of its territory. The blindfold in the traditional image more often refers to wilful avoidance of truth rather than active dishonesty: someone who prefers not to look too closely because looking would demand a response. In a reading about another person, the Two of Swords might suggest they are withholding information or are themselves in a state of confusion rather than deliberate deceit. The card is better read as a signal that full information is not yet on the table, whatever the reason, and that clarity will require more than is currently visible.',
      },
      {
        q: 'What does the Two of Swords mean for a relationship?',
        a: 'In a relationship reading, the Two of Swords often signals a standoff: two people at an impasse, perhaps each holding their position without genuine communication, or a relationship that exists in an undefined middle ground — neither fully committed nor fully ended. It can represent a period of deliberate emotional distance as a form of self-protection, or a difficult conversation that both parties know needs to happen but keep deferring. The card is not inherently negative; sometimes a pause is necessary. But it does suggest that the current equilibrium is temporary and that resolution requires one or both people to lower their guard and look honestly at what is there.',
      },
    ],
  },

  'three-of-swords': {
    up2: `The Three of Swords is tarot's most unflinching image of heartbreak — three blades piercing a heart against a stormy sky. Yet the card's power lies not in pessimism but in its refusal to minimise pain. Grief, loss, betrayal, and disappointment are real experiences that deserve acknowledgement rather than spiritual bypass. The Three of Swords arrives to validate suffering that may have been dismissed or that you have been trying to dismiss in yourself. It speaks to the particular ache of something that cannot be undone: a relationship ended, a harsh truth spoken, a trust broken, a hope finally relinquished. But notice that the heart in the image is not destroyed — it is pierced, which is different. Pain leaves marks without necessarily ending capacity for feeling or connection. This card also sometimes appears when the grief is intellectual: realising that something you believed was false, that a plan will not work, or that a situation is not what you thought. All of these are genuine losses deserving genuine mourning.`,
    rev2: `Reversed, the Three of Swords signals a movement through grief rather than a deepening of it. The acute phase of pain is beginning to ease, the wound is slowly closing, and the first tentative steps toward healing are becoming possible. However, the reversal can also indicate that grief is being suppressed or prolonged unnecessarily — either by refusing to feel it at all (pushing through without processing) or by revisiting and rehearsing it long past the point of usefulness. It may point to someone clinging to the narrative of their hurt because releasing it feels like a betrayal of the experience, or because the pain has become part of their identity. The invitation of this reversal is to distinguish between honouring what you have been through and being held captive by it. Healing is not forgetting; it is integrating.`,
    love2: `In love, a reversed Three of Swords can signal that the worst of a heartbreak is passing, and emotional healing is underway — slowly, imperfectly, but genuinely. Alternatively, it may point to unresolved grief from a past relationship that is preventing full presence in a current or potential one. Old wounds may be interpreting new situations through their own distorted lens. Tending to what has not yet healed is the most loving thing you can do for your future relationships.`,
    career2: `At work, this reversal may indicate recovery from a professional disappointment — a rejection, a failed project, a difficult ending — that hurt more than you let on. The grief was real, and now it is becoming workable. It can also suggest that lingering bitterness about a past workplace situation is colouring your current environment. It is worth asking honestly whether you have fully processed a professional loss, or whether you are carrying it forward into situations that don't deserve its weight.`,
    spirit2: `Spiritually, the reversed Three of Swords is an invitation to complete the cycle of grief rather than either bypassing it or perpetuating it. Healing often asks us to sit with sorrow long enough to extract its meaning — not to make pain purposeful in a forced way, but to allow it to teach what it has to teach before releasing it. Compassion for yourself in the aftermath of loss is not weakness; it is the ground from which renewal grows.`,
    faq: [
      {
        q: 'What does the Three of Swords mean?',
        a: 'The Three of Swords is tarot\'s clearest emblem of heartbreak, grief, and painful truth. Its image — three swords piercing a heart — is deliberately stark, because this card refuses to soften what it represents: genuine emotional pain, loss, betrayal, or sorrow. It appears when something or someone has caused real hurt, when a truth has landed hard, or when grief needs to be acknowledged rather than pushed aside. It is not a card of permanent damage but of necessary reckoning — an invitation to feel what is real rather than pretend it is not there. Pain that is acknowledged can eventually be integrated; pain that is denied tends to surface in less useful ways.',
      },
      {
        q: 'Does the Three of Swords always mean heartbreak?',
        a: 'Heartbreak is its most common interpretation, but the Three of Swords encompasses any form of painful reckoning with difficult truth. It can represent intellectual grief — realising a belief was wrong, that a plan won\'t succeed, or that a situation is not what you hoped — as well as emotional grief from loss or betrayal. It appears when clarity hurts: the moment when you can no longer maintain a comforting illusion and must face something as it actually is. In that sense, it is a card of necessary honesty rather than mere suffering, even though the honesty in question is painful.',
      },
      {
        q: 'What does the Three of Swords mean for love and relationships?',
        a: 'In a love reading, the Three of Swords most directly signals heartbreak, separation, or a deeply painful moment of truth within a relationship. This might be infidelity, a difficult breakup, a betrayal of trust, or simply the acknowledgement of something painful that has long been avoided. It does not necessarily mean the end of a relationship — sometimes painful honesty is what is needed for genuine repair. But it does suggest that something is hurting, and that the hurt deserves to be faced directly rather than managed away. After the initial pain, the card holds the possibility of clarity and, eventually, healing.',
      },
    ],
  },

  'four-of-swords': {
    up2: `The Four of Swords depicts a knight in repose — lying still, hands folded, three swords mounted on the wall above while a fourth rests beneath him. This is not defeat but deliberate withdrawal. The figure is not dead but resting, and the distinction matters enormously. After the sharp pain of the Three of Swords, the Four offers the radical proposition that stillness is not laziness but strategy. The mind that has been working hard, fighting battles, or absorbing difficult truths needs time to integrate, recover, and consolidate. This card appears when the most productive thing you can do is stop producing — when rest is not a gap between meaningful activities but a meaningful activity in itself. The church setting in many traditional depictions adds a contemplative quality: this is not mere sleep but a kind of sanctuary, a space apart from the world's noise where inner resources can quietly replenish. The Four of Swords gives permission to pause without guilt.`,
    rev2: `Reversed, the Four of Swords suggests that either rest has gone on too long and stagnation has set in, or that necessary rest keeps being refused. In the first case, a period of recovery has become avoidance: the withdrawal that was once restorative has hardened into isolation or inertia, and the time to re-engage is overdue. In the second case, someone is pushing through exhaustion, anxiety, or burnout when what they most need is to stop. The body and mind have a wisdom that ignores signals at its peril, and this reversal often appears when that wisdom is being overridden by obligation, fear, or the inability to give oneself permission to rest. It can also indicate a restless, anxious quality to sleep or inner life — the mind unable to settle even when the body is still. The invitation is always the same: discern whether you need to return to action or finally grant yourself stillness.`,
    love2: `In relationships, a reversed Four of Swords may indicate that one or both partners need space to recover from a period of intensity or conflict, but that space is not being honoured. Alternatively, a withdrawal that began as healthy distance has calcified into disconnection. There is also a gentle message here for anyone emerging from a painful relationship: rest is part of the healing, and re-engaging before you are ready rarely serves you or a new partner well.`,
    career2: `At work, this reversal often signals burnout that is being denied or a workaholic pace that cannot be sustained. If you have been running on empty, the warning is worth heeding: rest neglected now tends to demand repayment later, at considerably higher cost. On the other hand, if your hiatus has extended further than originally intended, this reversal may be the gentle nudge to begin re-engaging — slowly, but genuinely.`,
    spirit2: `Spiritually, the reversed Four of Swords highlights the relationship between stillness and spiritual renewal. When the practice of quiet — meditation, prayer, contemplation — is neglected, the inner life becomes increasingly reactive and surface-level. Conversely, if spiritual retreat has become a way of avoiding ordinary life, the reversal asks you to bring what you have gathered in stillness back into the world where it can be of use.`,
    faq: [
      {
        q: 'What does the Four of Swords mean in tarot?',
        a: 'The Four of Swords is a card of rest, recovery, and deliberate retreat. It appears after periods of mental strain, conflict, or intense activity to suggest that the most intelligent next step is to stop and allow recovery. It is not a card of defeat or stagnation but of strategic withdrawal — the understanding that sustainable effort requires recuperation. In practical terms, it may suggest taking a holiday, reducing commitments, stepping back from a conflict to gain perspective, or simply allowing yourself adequate sleep and quiet. The Four of Swords treats rest not as a luxury but as a necessity for continued functioning.',
      },
      {
        q: 'Is the Four of Swords a positive card?',
        a: 'Generally, yes — particularly if you are in a period of stress, overwork, or recovery. The Four of Swords brings a welcome message: you are allowed to rest, and doing so is wise rather than weak. The card is positive in its trust that stepping back does not mean falling behind. However, context matters: if you have been resting for an extended period and the question is about moving forward, the Four of Swords might suggest that continued retreat is no longer serving you. Its positivity is situational — it is most helpful when rest is genuinely what is needed.',
      },
      {
        q: 'What does the Four of Swords mean for mental health?',
        a: 'In questions touching on mental health and wellbeing, the Four of Swords is one of the more encouraging cards to receive. It validates the need for mental rest and recovery — for stepping away from sources of stress, reducing cognitive load, and creating space for the nervous system to settle. It suggests that healing from anxiety, burnout, grief, or mental exhaustion is genuinely possible, but requires time and intentional quiet rather than pushing through. The card encourages compassionate pacing: you cannot think your way out of a depleted mind; you have to allow it to restore. Professional support alongside genuine rest is always a worthwhile combination.',
      },
    ],
  },

  'seven-of-swords': {
    up2: `The Seven of Swords carries the unmistakable energy of someone operating outside the usual rules — the figure in traditional images sneaks away from a camp, arms laden with swords, glancing back with a look that is equal parts cunning and unease. This card speaks to strategy that lives in the grey zone: the workaround, the shortcut, the manoeuvre that technically works but that you would not care to explain in detail. Sometimes this is genuinely necessary — there are situations where playing by the rules only serves those who wrote them in their own favour, and a degree of strategic independence is simply intelligent. But the card also asks you to examine your motives. Are you acting independently because the situation genuinely calls for it, or are you avoiding the confrontation that honesty would require? The seven swords are heavy; the figure cannot carry them all. Some part of this plan may be overreaching, and the glance backward suggests an awareness that what is being done may not stand scrutiny.`,
    rev2: `Reversed, the Seven of Swords often brings hidden things to light — strategies that have been operating in the shadows are becoming visible, and deceptions (your own or others') are harder to maintain. This can feel exposing and uncomfortable, but the reversal often marks a positive turning point: the game-playing is over, and more honest engagement becomes possible. It can also indicate a decision to come clean about something — to stop managing a situation through evasion and to speak directly instead. Occasionally the reversal suggests that someone who has been acting deceptively toward you is about to be found out, or that you are gaining clarity about how you have been misled. The deeper message of this reversal is that sustainable progress cannot be built on a foundation of strategic half-truths.`,
    love2: `In love, a reversed Seven of Swords can indicate that deceptions within a relationship are coming to light — whether that is infidelity, withheld information, or simply a pattern of telling people what they want to hear rather than the truth. Alternatively, it may represent a turning point in which you or a partner decide to stop playing games and engage honestly. The relationship cannot move forward on its current foundation; transparency is the only viable path.`,
    career2: `At work, this reversal may expose a strategy, shortcut, or approach that has not been entirely above board. This could involve intellectual dishonesty, taking credit inappropriately, or navigating office politics through manipulation rather than merit. The exposure, while uncomfortable, is an opportunity to recalibrate and rebuild credibility through more straightforward means. It can also signal that a colleague's questionable behaviour is becoming apparent to others.`,
    spirit2: `Spiritually, the reversed Seven of Swords invites radical honesty with yourself about where you have been less than truthful — with others, but more importantly with yourself. Self-deception is perhaps the subtlest form of the sword's shadow, and this reversal asks you to identify the stories you tell yourself that allow you to avoid full accountability. Coming into integrity, even internally, creates a stability that evasion never can.`,
    faq: [
      {
        q: 'What does the Seven of Swords mean in tarot?',
        a: 'The Seven of Swords is the card of strategy, cunning, and the grey area between cleverness and dishonesty. It appears when someone — you or another person — is operating through evasion, indirect means, or deception rather than direct engagement. This is not always malicious; sometimes the card simply reflects tactical thinking, operating independently, or finding creative workarounds to genuine obstacles. But it always raises the question of whether the approach being used could withstand full transparency. It is worth asking, when this card appears, whether you are being strategically smart or whether your approach is undermining the trust and directness on which lasting results depend.',
      },
      {
        q: 'Does the Seven of Swords mean someone is cheating or lying?',
        a: 'It can suggest deception, though it rarely means something as simple or definitive as "someone is lying." More precisely, it signals that something is not being dealt with directly — that there is evasion, strategic omission, or behaviour that would not bear scrutiny. In a relationship context, this might indicate unfaithfulness or dishonesty, but it can equally point to avoidance, emotional unavailability, or someone managing their partner rather than being genuine with them. In any context, the card asks you to look at what is not being said or shown clearly, and to consider whether you are being fully straightforward yourself.',
      },
      {
        q: 'Can the Seven of Swords represent acting alone or independently?',
        a: 'Yes — and this is one of the card\'s more positive readings. The Seven of Swords can represent choosing to act independently of group consensus, particularly when group thinking is flawed or when collective caution is preventing necessary action. It can speak to the lone strategist who sees what others miss, or to someone who must navigate a situation by their own lights because the usual channels are not working. The key distinction is intention and integrity: independent action in service of a genuine goal is very different from deception in service of self-interest. When the Seven appears in this context, it encourages clear-eyed, self-reliant thinking while remaining honest about methods.',
      },
    ],
  },

  'eight-of-swords': {
    up2: `The Eight of Swords shows a figure bound and blindfolded, surrounded by swords driven into the ground — yet if you look carefully, she could walk away. The bindings are loose, the swords form a ring rather than a cage, and the path behind her is clear. This is the visual argument the card makes: that the prison is, in significant part, constructed from belief rather than reality. The Eight of Swords speaks to the experience of feeling trapped by circumstances that are more permeable than they appear — held in place by fear, by the stories told about limitations, by the accumulated weight of "I can't" and "I have no choice." This is not to say the situation is easy or that external constraints don't exist; the swords are real enough, and the blindfold has its reasons. But the card insists that perception is shaping the experience of captivity more than the facts alone justify. The question it poses is: what would you see if you removed the blindfold? What might be possible if you questioned the assumption that nothing is?`,
    rev2: `Reversed, the Eight of Swords marks a significant shift in the relationship to perceived limitations. The blindfold is coming off — not necessarily because external circumstances have changed, but because the mental and psychological hold of the restrictive beliefs is loosening. There is a growing capacity to see the situation more accurately: to identify which constraints are real and which are self-imposed, which fears are proportionate and which are catastrophic thinking in disguise. This reversal can also indicate that a release from a genuinely difficult situation is underway — legal proceedings concluding, an oppressive relationship ending, a health challenge becoming more manageable. Whatever form the loosening takes, the Eight reversed says that you are beginning to find your way back to agency. The process may be slow and the path imperfect, but movement is now genuinely possible.`,
    love2: `In relationships, a reversed Eight of Swords can mean that someone is finally beginning to see past the narrative that kept them stuck — perhaps the belief that they are unworthy of better treatment, or that leaving an unsatisfying relationship is impossible. The emotional bindings are loosening. It can also indicate that a relationship which felt suffocating is becoming more breathable as honest communication begins to replace the anxious assumptions that were driving disconnection.`,
    career2: `At work, this reversal suggests that a professional situation that felt inescapable is beginning to show exits. Opportunities that seemed unavailable are becoming apparent, or the internal conviction that you are not qualified, talented, or positioned for something different is weakening enough to allow tentative movement. This is a good time to update assumptions about what is possible in your professional life — they may be considerably more outdated than you realise.`,
    spirit2: `Spiritually, the reversed Eight of Swords is a powerful moment of emerging from an inner darkness. The limiting beliefs, shame, or fear that made the spiritual landscape feel narrow are beginning to loosen their hold. This is often a slow process rather than a sudden revelation, and gentleness with yourself through the transition is as important as courage. Freedom of the spirit tends to begin with freedom of perception.`,
    faq: [
      {
        q: 'What does the Eight of Swords mean?',
        a: 'The Eight of Swords represents a state of feeling trapped, restricted, or powerless — but with the crucial caveat that the imprisonment is at least partly psychological. The traditional image of a bound, blindfolded figure surrounded by swords that do not quite form a cage captures the card\'s central insight: the constraints that hold us in place are real, but our perception of them as absolute and inescapable tends to exaggerate their power. The card appears when fear, self-doubt, or limiting beliefs are preventing movement that is more possible than it appears. It is an invitation to examine what you believe about your own situation with fresh, honest eyes.',
      },
      {
        q: 'Is the Eight of Swords about anxiety?',
        a: 'Yes, the Eight of Swords has a strong connection to anxiety — particularly the kind characterised by catastrophic thinking, a sense of being overwhelmed by circumstances, and the feeling of having no good options. The card captures the mental state in which the mind generates its own additional constraints on top of whatever is genuinely difficult, creating a sense of being trapped that exceeds the actual situation. It is not dismissive of real difficulty, but it does point to the way that anxious thought patterns narrow the perceived solution space. Seeing this card can be a useful prompt to examine whether the situation is as inescapable as it feels, and whether trusted perspective — from a therapist, a friend, or your own wiser self — might reveal exits not currently visible.',
      },
      {
        q: 'What does the Eight of Swords say about choices?',
        a: 'The Eight of Swords suggests that choices exist — but that you may not be able to see them clearly from your current vantage point. The blindfold in the image is the key: it represents the way that fear, shame, or deeply held limiting beliefs about oneself and one\'s possibilities can obscure options that are objectively available. The card does not pretend that every door is open or that choice is unlimited; the swords are there for a reason. But it insists that the experience of having no choice is not the same as there being no choice, and that examining the assumptions underlying that experience is worthwhile. Often the first available choice is the choice to look.',
      },
    ],
  },

  'ten-of-swords': {
    up2: `The Ten of Swords is tarot's most dramatic image of endings: a figure lying prone, ten swords in their back, against a dark sky beginning to lighten at the horizon. Its very extremity is instructive. This is not a subtle decline but a final, irrevocable conclusion — the kind where something cannot limp along any further and must genuinely end. In its stark way, the Ten of Swords brings a kind of relief: whatever has been dying has finally died, and the pretence that it could recover is over. There is a completeness to this card that is not possible in the earlier numbered swords, where pain is still in process. Here it has reached its terminus. The dawn at the horizon in many versions of the card is not incidental — it signals that the darkest point has already passed, that the ending, however brutal, makes space for something new that the prolonged dying could not. This card also sometimes signals being stabbed in the back — betrayal or a sudden, unexpected blow — but even then, what follows is clarity about where things actually stand.`,
    rev2: `Reversed, the Ten of Swords suggests a process of recovery in the aftermath of a significant ending or blow. The acute phase is over; now comes the slow, unglamorous work of rebuilding. However, the reversal can also indicate a resistance to accepting that something is truly over — a refusal to let a situation reach its necessary conclusion, even when prolonging it only extends suffering. There may be a tendency to catastrophise: to experience difficulties as definitive endings when they are actually setbacks that can be recovered from. Conversely, if you have genuinely been through something terrible, the reversal is a gentle reminder that the rock bottom has been reached, the worst is behind you, and the direction — even if the progress is slow — is now upward.`,
    love2: `In love, the reversed Ten of Swords often signals that a painful ending in a relationship is either being processed in its aftermath, or is being resisted past the point of usefulness. If a relationship has genuinely run its course, continuing to hold it in a state of suspended ending serves neither person. Conversely, if you are recovering from a painful breakup or betrayal, this reversal says that the very worst of the hurt has peaked and healing is beginning, even if it doesn't feel that way yet.`,
    career2: `At work, a reversed Ten of Swords can indicate recovery from a significant professional setback — a redundancy, a project failure, a reputational blow. The card reversed says the lowest point has been reached. It can also caution against seeing a difficult professional situation as more terminal than it actually is: some defeats are genuinely recoverable, and catastrophising about them forecloses options that remain open. It is also worth examining whether a professional situation that should end is being artificially sustained.`,
    spirit2: `Spiritually, the Ten of Swords reversed marks the transition from a dark night of the soul to something like the early light of dawn. The ego\'s certainties may have been thoroughly dismantled — beliefs, identities, and structures that felt permanent may have collapsed. The reversal suggests that this painful deconstruction is complete, and the quieter, more spacious inner life that can emerge from such endings is beginning to become possible.`,
    faq: [
      {
        q: 'What does the Ten of Swords mean in tarot?',
        a: 'The Ten of Swords represents a definitive ending — the moment when something that has been struggling finally concludes, often painfully and with a sense of finality. It is the card of hitting rock bottom, of betrayal, of the sudden blow that makes continuation impossible. Despite its dramatic imagery, it carries a strange clarity: because this is the end, there is no more uncertainty about the direction things are headed. The worst has happened. And because it represents the lowest point, it implicitly signals that from here, the only possible movement is upward. The dawn breaking in many versions of the card makes this explicit: endings create the conditions for genuinely new beginnings.',
      },
      {
        q: 'Is the Ten of Swords a bad card?',
        a: 'It is among the more challenging cards in the deck, representing genuine pain, loss, and endings. However, its significance is not simply negative. The Ten of Swords marks a conclusion — and some conclusions, however painful, are necessary. A situation that has been declining slowly may be brought to a clear end by this card\'s energy, which at least ends the suffering of prolonged uncertainty. The dawn in the background of many depictions is a reminder that this is the lowest point of the cycle rather than a permanent state. In readings, the Ten of Swords is best understood as a card of necessary completion rather than unmitigated disaster.',
      },
      {
        q: 'What does the Ten of Swords mean for the future?',
        a: 'When appearing in a future position, the Ten of Swords suggests that a significant ending or difficult conclusion is approaching. This might be the end of a relationship, a job, a chapter of life, or a belief system. The card counsels preparation rather than panic: knowing that something is coming to a close allows you to grieve its passing in advance, to extract what has been valuable from it, and to consider what you genuinely want the next beginning to look like. The future the Ten of Swords points toward is not simply loss — it is the clearing that comes after loss, which is where new growth becomes possible.',
      },
    ],
  },

  'page-of-swords': {
    up2: `The Page of Swords stands with sword raised, wind-swept, scanning the horizon with a mixture of alertness and eagerness. This is a figure of keen intelligence still finding its discipline — the mind that is quick, curious, and sharp but not yet experienced enough to know when to hold its tongue or when to wait before acting. The Page represents the early stages of the Swords archetype: a love of ideas, a hunger for information, a delight in debate and analysis, and an enthusiasm for truth-seeking that can sometimes outrun tact. There is something genuinely wonderful about this energy — the world seen fresh and scrutinised closely, no assumption accepted at face value. In a reading, the Page may represent a person with these qualities, a message or communication on its way, or an aspect of yourself that is newly awake to intellectual possibility. The Page's youth is an asset — it brings courage to ask questions others have stopped asking. The challenge is to develop patience and wisdom to match the sharpness.`,
    rev2: `Reversed, the Page of Swords' quick mind and sharp tongue tip into less helpful territory. The gift for seeing through things can become cynicism; the love of debate can become argumentativeness; the hunger for information can become gossip or prying. There may be a tendency to speak before thinking, to use intellectual sharpness as a weapon rather than a tool, or to mistake cleverness for wisdom. The reversal can also indicate scattered mental energy — too many ideas, too much information, not enough focus or follow-through. Occasionally it points to someone who uses intelligence to deflect from emotional honesty, keeping everything at the level of analysis where it feels safer. The invitation is to bring the Page's considerable gifts under greater discipline: depth rather than breadth, thoughtfulness before speech, and the humility to recognise that knowing a lot is not the same as understanding.`,
    love2: `In love, a reversed Page of Swords can indicate that someone is approaching a relationship primarily through their head rather than their heart — analysing, testing, and strategising in ways that prevent genuine emotional intimacy. There may be a pattern of using wit as armour, keeping a partner at an intellectually stimulating distance. It can also suggest communication that is cutting rather than honest, or a tendency to win arguments at the expense of the relationship itself.`,
    career2: `At work, the reversed Page of Swords can signal scattered focus — too many interesting projects being started with too little sustained attention on any of them. There may also be issues with communication: sharing information prematurely, stirring up unnecessary conflict with carelessly worded criticism, or missing the right moment to speak because every moment feels like the right moment. Channelling genuine intellectual curiosity into fewer, deeper endeavours will produce better results.`,
    spirit2: `Spiritually, the reversed Page of Swords highlights the limitations of approaching spiritual questions from a purely intellectual standpoint. The mind that dissects every belief and questions every practice can become a barrier to the direct experience that spiritual development ultimately requires. Not every question has an answer that satisfies the analytical mind, and wisdom sometimes arrives through presence and feeling rather than through thinking.`,
    faq: [
      {
        q: 'What does the Page of Swords represent?',
        a: 'The Page of Swords represents an alert, curious, and intellectually eager young energy — whether as a person, a phase of development, or a mode of engaging with the world. Pages in tarot are students and messengers; the Page of Swords brings news and brings the sharp-minded eagerness of someone who wants to understand everything, question everything, and communicate everything they have discovered. They are quick, observant, and enthusiastic about ideas. The Page can represent an actual young person with these qualities, a new intellectual project or communication, or the part of yourself that is newly energised by a question, a subject, or a way of thinking.',
      },
      {
        q: 'Is the Page of Swords a person?',
        a: 'The Page of Swords can represent a person — typically someone young in age or young in experience, characterised by quick wit, intellectual curiosity, a love of debate, and sometimes a certain bluntness that comes from intelligence without yet having developed full tact. They tend to be observant, communicative, and often the first to notice something is off. However, in tarot, court cards need not always refer to external people. The Page of Swords may represent a quality in yourself — perhaps a newly awakened intellectual interest or a more questioning, analytical approach to a situation — or an approaching communication or piece of news.',
      },
      {
        q: 'What does the Page of Swords mean for communication?',
        a: 'The Page of Swords is strongly connected to communication — particularly the kind that is direct, curious, and information-seeking. Upright, it can signal news arriving, a conversation worth having, or an invitation to speak up and ask the questions that need to be asked. The Page does not shy away from difficult truths and encourages you to voice what you have observed or understood, even when others would prefer comfortable silence. However, it also carries a gentle caution: sharpness of expression is most effective when guided by consideration of timing and impact. Truth-telling and tact are not opposites — the most effective communication tends to involve both.',
      },
    ],
  },

  'knight-of-swords': {
    up2: `The Knight of Swords charges forward with a ferocity unmatched among the tarot's sixteen court cards — sword raised, horse at full gallop, leaning so far forward into the wind that he seems barely in control. This is the archetype of pure mental drive made kinetic: the mind that moves at speed, commits completely, argues with conviction, and pursues its goals without hesitation or self-doubt. At its best, this energy is extraordinary: the Knight of Swords cuts through bureaucratic inertia, speaks truth into rooms that prefer comfortable silence, acts decisively when others are still deliberating, and brings a crackling energy to any project or cause he takes up. The challenge lies in what that speed costs. The Knight of Swords does not always check his information before acting on it, does not always consider who might be standing in the path of his charge, and can mistake motion for progress. He is magnificent in a crisis; he creates crises when the situation required something more considered.`,
    rev2: `Reversed, the Knight of Swords' tremendous energy turns turbulent. The forward charge either accelerates into recklessness — all speed and no direction, all conviction and no accuracy — or it stalls, and the bold momentum collapses into frustration, inertia, or burnout. A reversed Knight of Swords can represent impulsive decision-making with significant consequences, aggression that has moved past the point of useful assertion into something harmful, or a brilliant mind that has run out of fuel and doesn't know how to stop. In some readings, the reversal suggests that high-speed thinking has led somewhere unproductive and a deliberate gear-change is needed: slower, more considered, more willing to listen. The gift of the Knight's energy remains — it simply needs channelling through a finer aperture.`,
    love2: `In love, a reversed Knight of Swords often indicates that intensity, speed, and the need to win are overriding sensitivity and care. Debates become battles; passion tips into aggression; the desire to be right eclipses the desire to understand. There may be an issue with acting impulsively in ways that damage trust, or with bringing so much mental energy to a relationship that emotional space gets squeezed out. Slowing down and listening — genuinely listening — is the most counterintuitive and useful thing this energy can do.`,
    career2: `At work, the reversed Knight of Swords may indicate a professional style that is creating friction: coming in too fast, too certain, too ready to override others' views. Excellent ideas are being undermined by the manner in which they are delivered. Alternatively, after a period of high-intensity effort, there may be a significant crash — burnout, disillusionment, or the realisation that speed without strategy has not produced the expected results. Sustainable momentum requires pacing.`,
    spirit2: `Spiritually, the reversed Knight of Swords serves as a reminder that the mind, however powerful, is not the whole of the self. The charging, intellectualising, analysing mode can become a way of staying on the surface of experience, never pausing long enough for deeper dimensions to make themselves felt. The spiritual invitation here is one of radical deceleration: to stop, to breathe, to let wisdom arrive rather than racing out to capture it.`,
    faq: [
      {
        q: 'What does the Knight of Swords mean in tarot?',
        a: 'The Knight of Swords represents rapid, driven, intellectually charged energy — the archetype of a person or force that moves fast, speaks directly, acts decisively, and pursues goals with singular focus. Among the knights, he is the most intense and the most volatile: extraordinary when channelled well, destructive when unchecked. In a reading, he may represent an actual person with these qualities — ambitious, blunt, brilliant, and sometimes difficult — or he may reflect the energy currently operating in a situation: things are moving fast, perhaps very fast, and the quality of the motion depends on whether the underlying thinking is sound.',
      },
      {
        q: 'Is the Knight of Swords a yes or no card?',
        a: 'Upright, the Knight of Swords tends to lean strongly toward yes for questions about action, speed, decisiveness, and communication. His energy favours forward movement, and when he appears, the situation often calls for directness and courage rather than delay. However, the yes comes with the implicit advice to make sure you know where you are charging before you charge there — the Knight\'s confidence is not always proportionate to his preparation. Reversed, the answer is more cautious: yes, but slow down; or yes, but check your information and your approach before proceeding.',
      },
      {
        q: 'What kind of person does the Knight of Swords represent?',
        a: 'The Knight of Swords as a person tends to be intellectually sharp, fast-moving, and driven — someone who sees what they want and goes for it without much hand-wringing. They are often witty, direct to the point of bluntness, and capable of extraordinary focus when engaged. They tend to be stimulating company and formidable allies, but difficult opponents and sometimes challenging partners, because they operate at a speed and intensity that not everyone can match or that does not always leave room for other people\'s pacing. At their best, they are advocates, pioneers, and truth-tellers. At their worst, they are impatient, combative, and heedless of the people in their wake.',
      },
    ],
  },

  'queen-of-swords': {
    up2: `The Queen of Swords sits with one hand open and one holding her sword upright, her gaze clear and direct, neither welcoming nor hostile but entirely undeceived. She has known difficulty and has transformed it into discernment. This is the court card of intellectual clarity earned through experience — not the brightness of someone who has never been tested, but the clear-eyed wisdom of someone who has been through something and emerged with their perception sharpened rather than embittered. The Queen of Swords tends to have few illusions about people or situations, which makes her simultaneously more realistic and more compassionate than she might at first appear. She does not tell you what you want to hear; she tells you what she sees. Her open hand suggests a willingness to receive what is offered — she is not closed, just unwilling to pretend. In a reading, she represents the capacity for honest assessment, the ability to maintain clear standards without cruelty, and the wisdom that comes from experience transformed into insight.`,
    rev2: `Reversed, the Queen of Swords' formidable clarity and honesty tip into something sharper and colder. The capacity for incisive perception becomes a tendency to find fault, to withhold warmth as a form of power, to use intelligence as a weapon. There may be bitterness in the mix — old hurts unprocessed, losses that have calcified into a worldview that sees threat or disappointment in most things. The reversed Queen can also represent someone using their perceptiveness to manipulate rather than to illuminate: seeing clearly and using what they see strategically rather than with integrity. Occasionally the reversal points to the suppression of the Queen's gifts: someone who is perceptive and clear-thinking but who has learned to hide or diminish these qualities, perhaps in a relationship or environment that found them threatening. The invitation is always to return to the honest, clear, and open-handed quality of the card upright.`,
    love2: `In love, a reversed Queen of Swords can signal that defensiveness, emotional unavailability, or a sharp tongue is creating distance in a relationship. Past hurts may have built walls that now exclude intimacy along with harm. There is a pattern of keeping people at the length of analysis rather than allowing genuine vulnerability. The medicine here is not to lower your standards but to distinguish between healthy discernment and protective coldness that outlived its usefulness.`,
    career2: `At work, the reversed Queen of Swords may represent someone using their intelligence to undermine colleagues rather than to build anything, or a work environment in which sharp criticism is doled out without equally clear acknowledgement. It can also represent a tendency to hold everyone to impossibly high standards — a drive for quality that has become perfectionism working against itself. The Queen's genuine gifts — clear thinking, high standards, direct communication — are most effective in service of shared goals rather than in service of control.`,
    spirit2: `Spiritually, the reversed Queen of Swords invites examination of where the sword has become a wall. The faculty of discernment — a genuine spiritual gift — can become a barrier to the heart's opening if it is used to evaluate and defend against every experience rather than to guide genuine engagement. Spiritual maturity often involves knowing when to analyse and when simply to be present.`,
    faq: [
      {
        q: 'What does the Queen of Swords mean in tarot?',
        a: 'The Queen of Swords is one of tarot\'s most complex and often misread court cards. She represents clarity, honesty, and the kind of wisdom that comes from having navigated genuine difficulty with one\'s integrity intact. She is perceptive, direct, and undeceived, with a warmth that tends to be expressed through honesty rather than sentimentality. Historically she has been associated with widowhood or loss — not because she is necessarily in mourning, but because her clear-eyed quality suggests someone who has experienced enough of life to have no illusions. In a reading, she represents the capacity for honest assessment, independent thinking, and clear communication grounded in real experience.',
      },
      {
        q: 'Is the Queen of Swords cold or unkind?',
        a: 'This is a common misreading. The Queen of Swords is direct rather than cold, and honest rather than unkind. There is an important difference between withholding the truth to protect feelings (which may not be kind at all) and speaking clearly and accurately (which, however uncomfortable, tends to be more genuinely caring). The Queen does not deal in false comfort, but she is not cruel — she has an open hand as well as a raised sword. The reversed Queen can tip into coldness or harshness, but the Queen upright is better understood as clear rather than cold: someone who sees well and speaks honestly, which is ultimately a form of respect.',
      },
      {
        q: 'What does the Queen of Swords mean in a love reading?',
        a: 'In a love reading, the Queen of Swords often represents someone who brings clear thinking and high standards to relationships — someone who is looking for genuine connection rather than romantic fantasy, and who will not sustain a relationship built on convenient fictions. If she represents you, the card may be affirming your discernment and your willingness to hold out for something real. If she represents a potential or current partner, they are likely independent, perceptive, and emotionally self-sufficient — not someone who needs to be needed, but someone who chooses to be present. The Queen asks that honesty be the foundation of any relationship she is part of.',
      },
    ],
  },

  'king-of-swords': {
    up2: `The King of Swords sits upright on his throne, sword raised or held steady, gaze direct and level. Of all the court cards, he represents the most developed expression of the Swords suit's gifts: a mind that is disciplined, principled, and capable of holding complexity without losing clarity. Where the Knight charges and the Page asks questions, the King deliberates and decides — and his decisions carry weight because they are grounded in genuine knowledge, ethical thinking, and the capacity to set aside personal feeling where the situation requires it. This is not coldness but a form of mastery: the ability to think clearly under pressure, to communicate with precision and authority, to see through the noise of a complex situation to what actually matters. The King of Swords values truth, fairness, and integrity not as abstract ideals but as practical foundations for leadership and relationship. He may not be warm in a demonstrative sense, but he is just, and in the right situation that is far more valuable.`,
    rev2: `Reversed, the King of Swords' formidable mental authority becomes tyrannical or corrupted. The capacity for decisive thinking hardens into dogmatism; the willingness to make difficult decisions tips into callousness; the standards that made him a fair judge become weapons of control. A reversed King of Swords can represent the misuse of intelligence and authority — using rationality to justify cruelty, deploying arguments to dominate rather than to arrive at truth, or wielding expertise and status to silence rather than to lead. He can also represent a version of these qualities within oneself: the inner critic that has escalated beyond useful self-regulation into something brutal, or the tendency to intellectualise everything into emotional numbness. The invitation is to reconnect mental power with the ethics and compassion that make it worth having.`,
    love2: `In love, a reversed King of Swords can manifest as emotional unavailability elevated to a principle — the partner who has rationalised their distance as strength or self-sufficiency, and who uses intellectual frameworks to avoid genuine vulnerability. There may be a controlling quality: using superior knowledge, argumentation, or certainty to manage rather than relate. The relationship cannot flourish on these terms; genuine intimacy requires a willingness to be affected by another person, which the reversed King is resisting.`,
    career2: `At work, the reversed King of Swords may represent someone in authority who uses their position and intelligence to dominate rather than to lead — the manager who is always right, whose expertise has become a means of control rather than service. It can also reflect an internal dynamic: perfectionism, relentless self-criticism, or an inability to accept imperfection in work processes or colleagues. Authority exercised with integrity requires humility alongside capability.`,
    spirit2: `Spiritually, the reversed King of Swords highlights the shadow of the fully developed mental archetype: the belief that understanding is the same as wisdom, or that the capacity to articulate and systematise spiritual truth is equivalent to living it. The invitation is to bring the formidable intellectual gifts of this card into alignment with the heart — not to abandon rigour, but to place it in service of genuine understanding rather than mastery for its own sake.`,
    faq: [
      {
        q: 'What does the King of Swords mean in tarot?',
        a: 'The King of Swords represents the fullest expression of the Swords suit\'s qualities: intellectual mastery, clear and principled thinking, the capacity for fair and decisive judgement, and the ability to communicate with authority and precision. He is the archetype of the just authority — the judge, the expert, the leader whose decisions can be trusted because they are grounded in careful thought rather than impulse or self-interest. In a reading, he may represent an actual person in your life — someone authoritative, analytical, and ethically grounded — or a quality or phase: a moment calling for disciplined, principled thinking rather than emotional reaction.',
      },
      {
        q: 'Is the King of Swords a positive card?',
        a: 'Generally, yes — the King of Swords upright is one of tarot\'s more affirming authority figures, representing the kind of clear, principled, trustworthy intelligence that is invaluable in complex situations. He is positive in the sense that his presence tends to produce fair outcomes, clear communication, and decisions that hold up under scrutiny. However, he is not a comfortable or cosy card: the King of Swords does not do sentimental reassurance, and his influence in a reading may push you toward rigour and difficult honesty rather than ease. Whether that feels positive often depends on what you were hoping to avoid.',
      },
      {
        q: 'What does the King of Swords mean as a person?',
        a: 'As a person, the King of Swords is typically intellectually formidable, direct, ethically principled, and somewhat self-contained. They tend to value competence and honesty above most things, and their respect is earned rather than given freely. They may work in fields that require precision, expert knowledge, or analytical authority — law, medicine, academia, strategy. In relationships, they tend to be loyal and fair-minded but may express care through acts of practical help and honest engagement rather than emotional expressiveness. They are not the warmest of the court cards, but they are among the most reliable. Their strength lies in integrity: what they say they mean, and what they commit to, they follow through on.',
      },
    ],
  },
  'ace-of-pentacles': {
    up2: `The Ace of Pentacles carries the weight of genuine potential — not wishful thinking, but the kind of possibility that has roots. It marks the moment before effort transforms into form: a seed that is viable, ground that is fertile, conditions that are genuinely favourable. What distinguishes this card from mere optimism is its insistence on the physical plane. It is not enough to have ideas; you must do something tangible with them. The ace invites you to treat your resources — time, money, skills, health, attention — as sacred material to be shaped deliberately. There is often a sense of threshold here: a new financial chapter, a business concept ready to be tested, a property decision crystallising. The card does not promise ease, but it does confirm that the raw material for something lasting is genuinely present. What you build with it is your work to do.`,
    rev2: `Reversed, the Ace of Pentacles points to something that is blocking the translation of potential into reality. The seed is there but the conditions are off — poor timing, insufficient preparation, scarcity thinking that stops you from investing in yourself, or simply a plan that has not been thought through practically enough. There is sometimes a pattern of starting well but losing momentum before anything tangible materialises. The reversed ace can also suggest financial opportunities that are less solid than they appear — deals worth scrutinising carefully, income streams that look reliable but are not. At its deepest level, this card reversed invites you to examine your relationship with material stability: do you feel you deserve security? Do you trust yourself to steward resources well? The blockage is rarely permanent — it is usually a signal to slow down and prepare more thoroughly before committing.`,
    love2: `In relationships, the reversed Ace of Pentacles can suggest that practical foundations are shaky. A promising connection may be struggling to become something concrete and committed. Financial stress, different attitudes to security, or one partner's reluctance to invest genuinely in shared life together can all stall progress. This is a prompt to have honest conversations about what you each actually want to build — and whether your material realities are compatible.`,
    career2: `At work, this reversal often signals a missed opportunity or a promising project that stalls before launch. Funding may fall through, a job offer may not materialise as expected, or a business idea may reveal its practical flaws. Rather than forcing it, use this period to strengthen your foundations — shore up savings, develop skills, research more carefully. The right opportunity will be more obvious when you are better prepared to meet it.`,
    spirit2: `Spiritually, the reversed Ace of Pentacles asks whether you are honouring the material dimension of your life as part of your spiritual path. Dismissing practical concerns as unspiritual, or using spiritual practice to avoid dealing with money and security, creates imbalance. Genuine groundedness means tending to your physical world with the same care you bring to your inner life.`,
    faq: [
      {
        q: 'What does the Ace of Pentacles mean in tarot?',
        a: 'The Ace of Pentacles represents the pure potential of the earth element — the very beginning of material manifestation. It signals favourable conditions for financial growth, practical new beginnings, and investment in something tangible. Whether that is a business, a property, a new income stream, or simply a more grounded approach to daily life, the ace marks the moment when possibility becomes workable reality. It is an encouraging card that suggests the resources, circumstances, or ideas you need are genuinely available — but it is also a card of responsibility, reminding you that potential only becomes something real through consistent, practical effort.',
      },
      {
        q: 'Is the Ace of Pentacles a yes or no card?',
        a: 'Upright, the Ace of Pentacles is generally a yes — particularly for questions about financial matters, practical ventures, job offers, or anything requiring a solid foundation. It suggests conditions are favourable and the timing is workable. Reversed, it tilts towards not yet rather than a hard no: the opportunity may need more preparation, better timing, or a closer look at the practical details. For yes/no questions about relationships, it is especially positive when asking whether a connection has long-term, stable potential, and more cautious when reversed.',
      },
      {
        q: 'What does the Ace of Pentacles mean in love?',
        a: 'In a love reading, the Ace of Pentacles is a quietly optimistic card. It suggests a relationship with genuine long-term potential — one that feels stable, real, and grounded rather than purely emotional or idealistic. It can signal a new relationship that will prove durable, or an existing one entering a more committed, practical phase: moving in together, making financial decisions as a unit, building shared life. It is not the most passionate card in the deck, but it speaks of the kind of love that actually sustains — thoughtful, steady, and genuinely invested in shared wellbeing.',
      },
    ],
  },

  'two-of-pentacles': {
    up2: `The Two of Pentacles is the card of dynamic equilibrium — not stillness, but the alert, ongoing act of keeping multiple things in motion without dropping any of them. This is the daily reality of most working lives: managing competing demands, shifting resources between priorities, adapting to circumstances that keep changing. The figure in traditional imagery juggles two coins in an infinity loop while ships navigate rough waves behind him. The sea is not calm, and it is not meant to be. What the card celebrates is the capacity to remain nimble and good-humoured in the midst of flux. It rewards flexibility over rigidity and reminds you that attempting to control everything at once will exhaust you — what you actually need is rhythm, responsiveness, and the wisdom to know which ball needs your hands right now. This is a card of practical intelligence in motion.`,
    rev2: `When reversed, the Two of Pentacles signals that the juggling act has become unsustainable. Too many plates are spinning, and at least one is about to fall. There may be financial disorganisation — bills being shuffled around, debts accumulating quietly, income that never quite reaches the expenses it is supposed to cover. Alternatively, the reversal can point to someone who is so locked into one way of doing things that they cannot adapt when circumstances shift. The deeper pattern is often avoidance: keeping yourself so busy that you never have to confront the financial or practical reality underneath. The reversed two asks you to stop juggling long enough to honestly assess what your situation actually requires — even if that means accepting that something has to be set down for a time so you can deal with what matters most.`,
    love2: `Reversed in love, the Two of Pentacles can indicate that a relationship is being neglected because life has become too overloaded elsewhere. Work, financial stress, or competing responsibilities are eating into the time and energy that a partnership needs. It can also describe a person who is emotionally unavailable because they are too stretched. The relationship deserves more deliberate attention — even small, consistent acts of presence matter more than grand gestures.`,
    career2: `At work, this reversal often points to disorganisation, poor time management, or taking on more than is sustainable. You may be overcommitted across several projects with none receiving adequate attention. Financial management in a business context may also be slipping — cash flow issues, inconsistent invoicing, or costs creeping beyond income. A clear-eyed review of priorities and perhaps some external support with planning would help restore balance.`,
    spirit2: `Spiritually, the reversed Two of Pentacles reflects a disconnection from the natural rhythms of life — rest and activity, giving and receiving, expansion and consolidation. Spiritual practice may feel like just another item on an already impossible to-do list. The invitation here is to simplify: even ten minutes of genuine stillness is more nourishing than a spiritual routine performed on autopilot.`,
    faq: [
      {
        q: 'What does the Two of Pentacles mean in a reading?',
        a: 'The Two of Pentacles typically signals a period of balancing multiple priorities at once — usually financial or practical in nature. You may be managing several income streams, weighing up competing demands on your time, or navigating a period of change that requires constant adaptation. Upright, it suggests you have the flexibility and humour to handle it, even if things feel hectic. It is a card of workable complexity rather than crisis — but it does caution against adding even more to an already full plate. The key is to remain responsive rather than reactive, and to know which priority needs attention first.',
      },
      {
        q: 'Does the Two of Pentacles indicate financial difficulty?',
        a: 'Not necessarily. Upright, the Two of Pentacles more often reflects financial complexity than hardship — managing multiple accounts, budgeting carefully, or navigating variable income. It shows money in motion rather than money lost. However, reversed, the card is more concerning: it can point to financial disorganisation, overspending, debt accumulation, or an inability to adapt when income shifts unexpectedly. If you are asking about finances and this card appears reversed, it is worth doing a careful, honest audit of where your money is actually going before the situation becomes harder to correct.',
      },
      {
        q: 'What does the Two of Pentacles mean for work-life balance?',
        a: 'This is one of the tarot\'s most direct cards about work-life balance, and its message is nuanced. Upright, it acknowledges that true balance is rarely a static state — it is more like a skilled juggler keeping things in motion. You may not achieve perfect equilibrium, but you can manage competing demands with dexterity. Reversed, it is a clearer warning: something is out of proportion, and the current pace is not sustainable. One area of life — often the personal or physical — is being chronically deprioritised. The card asks you to be honest about what needs to be reorganised before exhaustion or resentment sets in.',
      },
    ],
  },

  'three-of-pentacles': {
    up2: `The Three of Pentacles is the tarot's most direct celebration of skilled collaboration. It depicts the moment when individual expertise combines into something none of the contributors could have built alone — a craftsman consulting with architects, plans spread between them, each bringing a different kind of knowledge to the same project. This is not the card of solo genius or the lone entrepreneur; it is the card of the workshop, the team, the professional community. What distinguishes it from mere cooperation is the emphasis on genuine craft: each person brings real competence, and they are all genuinely listening to one another. The card also carries an implicit message about the value of apprenticeship and feedback — being willing to have your work seen and evaluated, to receive critique without defensiveness, and to learn from those whose experience exceeds your own. Excellence here is a collective achievement.`,
    rev2: `Reversed, the Three of Pentacles points to breakdown in collaboration. The dysfunction can take many forms: a team where communication has siloed, where credit is being hoarded or disputed, where someone is coasting on others' efforts, or where roles are unclear enough that important work falls between the cracks. There is sometimes a specific dynamic of someone refusing to take direction or accept feedback — treating critique as attack rather than information. At a personal level, this reversal can indicate working in isolation when partnership would genuinely help, or the opposite: getting involved in group work before you have developed sufficient individual skill to contribute meaningfully. The card asks whether the people around you are genuinely pulling in the same direction — and whether you are.`,
    love2: `In a relationship context, the reversed Three of Pentacles can suggest that two people are no longer working as a team. A partnership that once felt like productive collaboration may now be characterised by miscommunication, unequal contributions, or a sense of working at cross purposes. Someone may feel that their efforts are unrecognised. This is a moment to revisit how you make decisions together and whether both people feel genuinely heard and valued in the shared work of the relationship.`,
    career2: `At work, this reversal highlights team dysfunction, poor project communication, or work that is being done without adequate collaboration and input. Office politics may be interfering with genuine productivity. There may be a skills mismatch — someone in the wrong role, or a gap in expertise that nobody is acknowledging. Alternatively, it can point to mediocre output because standards have quietly slipped and nobody is being honest enough to say so. A structured conversation about expectations and roles would help.`,
    spirit2: `Spiritually, the reversed Three of Pentacles can suggest spiritual isolation — working on your inner development entirely alone when a teacher, community, or practice group would genuinely help you grow faster and more safely. Conversely, it can indicate following a tradition or teacher uncritically without engaging your own discernment. Genuine spiritual craft, like any craft, benefits from both mentorship and individual integrity.`,
    faq: [
      {
        q: 'What does the Three of Pentacles mean in a career reading?',
        a: 'The Three of Pentacles is one of the most positive cards you can draw in a career reading. It speaks to the satisfaction and productivity of skilled teamwork, professional recognition, and the genuine development of your craft. It often appears when collaborative work is going well — when a team is functioning with genuine mutual respect, when your expertise is being utilised and acknowledged, or when you are at a stage of learning that is genuinely deepening your skills. Upright, it is very encouraging for projects, job interviews, and professional development. It suggests that working with rather than around others will produce your best results.',
      },
      {
        q: 'Is the Three of Pentacles about teamwork?',
        a: 'Yes, collaboration is at the heart of this card — but with a specific emphasis on skilled, respectful, purposeful teamwork rather than mere group activity. The Three of Pentacles is about what happens when genuinely competent people bring their different expertise to a shared goal and actually listen to one another. It also carries a strong thread of craftsmanship: the work matters, and doing it well together matters. When this card appears, it often affirms that partnership and open communication will take your work considerably further than trying to do everything yourself — and that your existing collaborative relationships have real potential.',
      },
      {
        q: 'What does the Three of Pentacles mean spiritually?',
        a: 'Spiritually, the Three of Pentacles points to the value of learning within a tradition or community — the idea that spiritual development is often deepened when we engage with teachers, fellow practitioners, or established lineages rather than reinventing everything from scratch in isolation. It honours the sacred dimension of skilled work done with care and intention: any craft practised with genuine presence becomes a form of spiritual discipline. It can also affirm that your efforts in a long-term spiritual practice are producing real results — that the foundation you are building is solid and worthy of your continued investment.',
      },
    ],
  },

  'four-of-pentacles': {
    up2: `The Four of Pentacles sits at one of the tarot's most psychologically interesting intersections — it can represent both the virtue of financial prudence and the shadow of fearful hoarding. At its most functional, this card speaks to the importance of holding your ground, protecting what you have built, and not squandering resources through impulsiveness or generosity that exceeds your means. In a world that perpetually encourages consumption and largesse, there is genuine wisdom in saying "enough — I am going to protect this." But the card also invites scrutiny: is your grip on money, security, or control rooted in genuine prudence, or in a fear that if you let go, everything will collapse? The figure's posture — hunched over his coins, isolated — is not a portrait of abundance but of anxiety. The question is not whether to hold, but why, and whether the holding is actually serving you.`,
    rev2: `Reversed, the Four of Pentacles typically indicates a loosening of excessive control — and this can be either liberating or alarming depending on context. In one reading it marks the welcome release of a miserly pattern: generosity returning, resources starting to flow again, a person finally willing to invest in their own life and others'. In another reading, it signals the opposite: reckless spending after a period of restriction, financial boundaries dissolving in ways that will cause problems, or someone releasing control of their finances in ways that amount to self-sabotage. The reversal can also indicate that the walls a person has built — around money, around emotion, around their life — are starting to crack. That may be exactly what is needed. Or it may require careful management. Context and the surrounding cards matter considerably.`,
    love2: `In love, the reversed Four of Pentacles can signal the thawing of emotional guardedness. Someone who has kept their heart behind walls — protecting themselves from vulnerability — may be starting to open up. Alternatively, if financial control is a dynamic in the relationship, its reversal may mean either the welcome release of that tension or an escalation of conflict around money and resources. The invitation is towards genuine trust and emotional generosity within the partnership.`,
    career2: `At work, reversed Four of Pentacles can indicate a shift in financial approach — sometimes positively, as a period of careful saving gives way to strategic investment, and sometimes less so, as overspending or poor resource allocation starts to surface. If you have been too risk-averse professionally, the reversal can signal readiness to take a calculated chance. If you have been financially careless, it is a prompt to tighten up before the consequences compound.`,
    spirit2: `Spiritually, the Four of Pentacles reversed invites surrender — not of discernment, but of the need to control every outcome. Much spiritual growth requires releasing the grip: on certainty, on familiar comfort, on the identity you have built around what you possess. This card reversed asks where you are clinging, and whether that clinging is actually keeping you safe or simply keeping you small.`,
    faq: [
      {
        q: 'What does the Four of Pentacles mean in tarot?',
        a: 'The Four of Pentacles is the card of holding — of gripping tightly onto what you have built, whether out of wisdom or fear. It speaks to financial conservation, the instinct to protect your resources, and the psychological dimension of security. At its best it represents sensible boundary-setting: not every resource should be shared, and knowing how to protect your material foundations is a genuine skill. At its most challenging, it represents scarcity thinking — the fearful conviction that letting go of anything will lead to ruin. The card invites you to examine your relationship with money and control honestly: is your caution serving you, or has it become a prison?',
      },
      {
        q: 'Does the Four of Pentacles mean I should save money?',
        a: 'It can, but the message is more nuanced than a simple instruction to save. Upright, the card does affirm the wisdom of being financially careful and not overextending yourself — if you have been spending impulsively or giving beyond your means, it suggests pulling back is wise. However, the card also carries a warning about excessive attachment to financial security becoming its own form of poverty. If you are already saving well and the card appears, it may be asking whether you are allowing yourself to actually enjoy and use what you have accumulated, rather than hoarding out of anxiety.',
      },
      {
        q: 'What does the Four of Pentacles mean for relationships?',
        a: 'In relationship readings, the Four of Pentacles often points to emotional withholding rather than financial matters, though money dynamics can be present too. It can describe someone who keeps their feelings tightly controlled — who struggles to give freely, to be vulnerable, or to share themselves openly with a partner. There may be a fear of loss underlying this guardedness: if I give too much, I will be left with nothing. Upright, the card asks whether emotional caution is actually protecting you or preventing genuine intimacy. Reversed, it can indicate someone beginning to open up — or the eruption of long-suppressed feelings when the grip finally loosens.',
      },
    ],
  },

  'five-of-pentacles': {
    up2: `The Five of Pentacles confronts one of the most difficult human experiences the tarot addresses: material hardship and the isolation that so often accompanies it. The traditional image is stark — two figures moving through snow, ragged and cold, while a warm, illuminated window glows above them. The window matters. There is warmth, resource, and support available, but it is not yet being accessed, perhaps because the figures have not noticed it, cannot bring themselves to ask, or feel they do not deserve to enter. This card does not spiritualise poverty or minimise its real difficulty. It takes financial struggle seriously as a physically, emotionally, and psychologically taxing experience. But it also asks what narratives of unworthiness or shame might be keeping you locked outside in the cold even when shelter is available. Material hardship and the belief that you must endure it alone are both addressed here.`,
    rev2: `Reversed, the Five of Pentacles most commonly signals an improvement in material circumstances after a difficult period — the end of a financial hardship, a path back into stability, the beginning of recovery. There is a sense of turning a corner: help that was unavailable or unsought is now more accessible, and the worst of the crisis has passed. However, the reversal can also speak to the inner aftermath of hardship: financial circumstances may be improving but the scarcity mindset, the shame, or the anxiety about poverty may linger long after the immediate crisis has eased. Sometimes it points to someone so accustomed to struggle that they cannot recognise or accept that their situation has genuinely improved. The invitation is to allow yourself to receive — to step inside from the cold.`,
    love2: `In a love reading, the reversed Five of Pentacles can indicate healing after a painful period in a relationship — coming back together after estrangement, finding renewed warmth after a cold patch, or finally allowing support to flow between partners where it was previously blocked. If a relationship has suffered because of financial stress, conditions may be beginning to ease. The key is allowing real vulnerability and connection rather than maintaining the defensive isolation that hardship sometimes creates.`,
    career2: `At work, this reversal usually brings encouraging news: a period of financial or professional difficulty is beginning to lift. A job loss may be followed by a new opportunity; a struggling business may find its footing; income that was precarious may stabilise. There is also sometimes a message about reclaiming professional confidence after a setback — allowing yourself to re-engage with ambition and opportunity rather than remaining contracted in the aftermath of a difficult chapter.`,
    spirit2: `Spiritually, the reversed Five of Pentacles can signal the recognition that you are not alone in your struggles — that support (whether from community, inner resources, or something larger than yourself) is genuinely available. It marks the moment when the story of isolation and unworthiness begins to soften, and when genuine spiritual nourishment becomes accessible again. The first step is simply turning towards the light.`,
    faq: [
      {
        q: 'What does the Five of Pentacles mean in a reading?',
        a: 'The Five of Pentacles is the tarot\'s card of material hardship — financial difficulty, job loss, poverty, or the feeling of being excluded from the security and comfort that others seem to have. But it carries an equally important psychological dimension: the experience of isolation, shame, and the belief that help is not available or not deserved. When this card appears, it acknowledges that something genuinely difficult is happening on the material plane. It does not offer false comfort, but it does consistently point towards the presence of resources and support that are closer than they may feel — and asks what might be preventing you from reaching for them.',
      },
      {
        q: 'Is the Five of Pentacles a bad card?',
        a: 'The Five of Pentacles is one of the tarot\'s more challenging cards because it deals honestly with experiences of hardship, scarcity, and exclusion — experiences that are genuinely difficult and deserve to be taken seriously rather than minimised. However, "bad" is not quite the right framing. The card appears not to confirm that things are hopeless, but to shine a light on a difficult situation so that it can be addressed. It almost always carries the implicit message that support or resources are available — the illuminated window in the classic imagery — and it asks what internal or external barriers are preventing you from accessing them. It can also mark the darkest point before conditions begin to improve.',
      },
      {
        q: 'What does the Five of Pentacles mean for finances?',
        a: 'Financially, the Five of Pentacles directly addresses periods of real material difficulty — reduced income, mounting debt, unexpected expenses, job loss, or the grinding anxiety of financial insecurity. It takes these experiences seriously rather than offering reassuring platitudes. At the same time, it consistently asks whether available resources — financial assistance, professional support, community help, or the guidance of people who have navigated similar situations — are being overlooked or avoided out of pride or shame. Reversed, it usually signals that the worst is passing and that financial conditions are beginning to stabilise, though the psychological aftermath of hardship may take longer to heal.',
      },
    ],
  },

  'six-of-pentacles': {
    up2: `The Six of Pentacles is the tarot's most nuanced card about the dynamics of giving and receiving, generosity and dependency, power and gratitude. The classic image is deliberately complex: a wealthy merchant weighs coins on scales while distributing them to two figures kneeling below him. The scales are important — they suggest that genuine generosity involves judgement, fairness, and balance, not simply scattering resources wherever they seem wanted. This is a card about the ethics of abundance: how do you use resources when you have them? And how do you receive with grace and without compromising your dignity when you need them? It can describe a generous mentor, a charitable act with real impact, fair financial dealings, or the satisfying reciprocity of a relationship where giving and receiving flows naturally between both parties. It is also worth noting whose position you occupy in the image at any given moment.`,
    rev2: `Reversed, the Six of Pentacles exposes the shadow side of the giving and receiving dynamic. Generosity that comes with strings attached — help offered in ways that create dependency or obligation rather than genuine empowerment. Financial control as a form of power over another person. Charity that demeans rather than uplifts. Alternatively, it can point to someone who gives too much without being able to receive — chronically depleting themselves in service of others, unable to allow the reciprocity that would sustain them. There is also a reading in which someone is taking more than they are giving in a relationship, business, or community context, and the imbalance has become significant. Whichever face of the reversal applies, the underlying question is always about whether the flow of resources between people is genuinely fair and mutually nourishing.`,
    love2: `In love, the reversed Six of Pentacles can indicate a meaningful imbalance in how give and take is operating within the relationship. One person may be consistently over-functioning — financially, emotionally, or practically — while the other takes without equivalent reciprocity. It can also describe a partner who uses money or resources as a form of control. This reversal asks for an honest conversation about whether the exchange between you both feels genuinely fair and mutual.`,
    career2: `At work, this reversal can indicate unfair financial treatment — being underpaid, denied recognition, or experiencing a power imbalance in professional relationships. It may also point to someone in a position of resource or authority who is not exercising it with integrity. If you are in a leadership position, the card asks whether you are genuinely empowering those around you or inadvertently creating dependency. Fair dealing and transparent communication about compensation and credit matter here.`,
    spirit2: `Spiritually, the reversed Six of Pentacles invites reflection on the economy of your spiritual life: are you in genuine exchange with the world, or are you either chronically depleting yourself through over-giving or taking nourishment without contributing? Spiritual generosity is real and valuable, but it requires that your own well be full enough to draw from. The card asks you to restore genuine reciprocity in how you engage with your community and your own inner life.`,
    faq: [
      {
        q: 'What does the Six of Pentacles mean in tarot?',
        a: 'The Six of Pentacles is the card of generosity, giving and receiving, and the ethics of how resources flow between people. Upright, it is a positive card about genuine giving — whether that is financial generosity, sharing of time and expertise, or the natural reciprocity of a healthy relationship or community. It can indicate receiving unexpected help, being in a position to help others, or engaging in financial dealings that are genuinely fair. Its deeper message is about the balance of the scales: generosity at its best empowers rather than creates dependency, and receiving at its best is done with grace and genuine appreciation rather than entitlement.',
      },
      {
        q: 'Does the Six of Pentacles mean I will receive financial help?',
        a: 'It can. The Six of Pentacles upright often appears when unexpected generosity, financial assistance, or a gift is incoming — whether from a person, an institution, or simply a fortunate turn in circumstances. It can also affirm that help you have been considering asking for is worth pursuing: support is available and will be offered with good will. However, the card also asks you to consider the terms and dynamics of any help offered. Generosity that comes with significant strings attached, or that subtly diminishes your autonomy, may be worth reflecting on carefully before fully accepting.',
      },
      {
        q: 'What does the Six of Pentacles mean in a love reading?',
        a: 'In love, the Six of Pentacles points to the balance of give and take within a relationship. Upright, it suggests a relationship with healthy reciprocity — where both people contribute and receive in ways that feel fair and mutually nourishing. It can indicate a generous partner who genuinely invests in shared wellbeing, or a period of natural flow where care and resources move freely between you both. Reversed, it raises questions about imbalance: is one person consistently doing more than the other? Are financial dynamics creating a power differential? Is generosity being used as a form of control? The card asks whether the exchange is genuinely mutual.',
      },
    ],
  },

  'seven-of-pentacles': {
    up2: `The Seven of Pentacles captures a moment that is rarely celebrated but deeply valuable: the pause. A figure leans on a staff, looking at the pentacles growing on a vine, clearly having worked for a long time and now stopping to assess. This is the card of the mid-point evaluation — you have invested considerable effort and resources into something, and now is the moment to step back and ask whether the return is commensurate with the input. This is not laziness or doubt but mature, strategic thinking. Not every investment of time, money, or energy yields the results that justify continuing at the same pace or in the same direction. The Seven of Pentacles honours patience — genuine, eyes-open patience, not passive waiting — and the kind of long-term thinking that is willing to forego immediate gratification for significant future return. It is the card of the gardener who knows that growth cannot be rushed.`,
    rev2: `Reversed, the Seven of Pentacles points to frustration with slow returns, impatience undermining a process that requires time, or the genuine realisation that an investment has not been — and will not be — yielding sufficient results. There is a distinction between the two: sometimes what is needed is simply more patience and trust in a process that is genuinely working at its own pace. Other times, the honest assessment is that you have been putting considerable energy into something that is not going to give back what it has cost you, and it is time to redirect. The reversal can also indicate perfectionism or over-investment in a project — pouring more and more into something beyond the point of reasonable return out of reluctance to accept diminishing yields.`,
    love2: `In a love reading, the reversed Seven of Pentacles can describe a relationship in which one or both people are questioning whether the investment they are making is yielding what they had hoped for. This is not necessarily a sign to leave, but it is an honest signal that something needs to be assessed. If you have been patient with a difficult dynamic for a long time, the reversal asks whether that patience has genuine evidence to support it, or whether it has become waiting for something that is unlikely to change.`,
    career2: `Professionally, this reversal can indicate stalled progress despite genuine effort — a project that is not delivering, a career investment that is not producing expected returns, or a business that is consuming resources without growing proportionally. Before doubling down or pulling out completely, this is a moment for clear-eyed assessment: what is actually working? What evidence suggests this will improve? Where might energy be better redirected? Sunk-cost thinking is a real risk here.`,
    spirit2: `Spiritually, the reversed Seven of Pentacles can reflect spiritual impatience — wanting transformation to happen faster than organic development allows — or, conversely, a long investment in a spiritual path that has become stale and is no longer producing genuine growth. The card invites discernment: is this a period of necessary fallow, or have you outgrown what you have been practising?`,
    faq: [
      {
        q: 'What does the Seven of Pentacles mean in tarot?',
        a: 'The Seven of Pentacles is the tarot\'s card of assessment, patience, and long-term investment. It depicts the moment of stepping back to honestly evaluate whether the effort you are putting into something is yielding proportionate results — and whether the direction you are heading is still the right one. It deeply honours the ability to think in longer time horizons than immediate gratification allows. Whether in finances, career, relationships, or personal projects, this card affirms that sustainable success is usually built slowly, with regular honest evaluation and willingness to adjust course when the evidence supports it.',
      },
      {
        q: 'Is the Seven of Pentacles about patience?',
        a: 'Yes, but it is a specific and active kind of patience rather than passive waiting. The card depicts someone who has done real work and is now in the assessment phase — looking at what has grown and deciding how to proceed. It is the patience of a farmer who has planted, tended, and now waits for the harvest while continuing to evaluate conditions. This is different from hoping things will work out without engaging. Seven of Pentacles patience involves continuing to tend what you have planted while trusting a process that operates on its own timeline — and being willing to adjust your approach if the results of your assessment warrant it.',
      },
      {
        q: 'What does the Seven of Pentacles mean for money and investments?',
        a: 'Financially, the Seven of Pentacles is a card about long-term thinking and honest evaluation of returns. It can affirm that a financial strategy you have been committed to — savings, investment, a business you have been building slowly — is on track and deserves continued patience. It asks you to resist the temptation to liquidate or change course prematurely, when the compound effect of consistent investment has not yet had time to materialise. Reversed, it can indicate that a particular financial strategy is not producing sufficient return and may need reassessment — or that impatience is leading to decisions that will undermine a process that is actually working.',
      },
    ],
  },

  'eight-of-pentacles': {
    up2: `The Eight of Pentacles is the card of dedicated, absorbed, purposeful work — the kind that produces genuine mastery over time. The artisan in the traditional image sits alone, entirely focused, striking the same form again and again, not because the repetition is mindless but because it is through this kind of deliberate practice that excellence is built. This is the tarot's most direct treatment of craftsmanship: the understanding that real skill is not a gift but a sustained commitment, that mastery comes not from talent alone but from showing up consistently and attending carefully to the quality of your work. There is something quietly joyful about this card — the satisfaction of total absorption in work that matters to you, the pleasure of improving, the dignity of doing something well. It is also a card of career development and training — learning new skills, investing in education, deepening expertise rather than skimming the surface.`,
    rev2: `Reversed, the Eight of Pentacles can indicate a loss of focus or care in one's work — going through the motions rather than genuinely engaging, producing output without attention to quality, or being present in body while the mind and intention are elsewhere. It can also describe someone who has become stuck in meaningless repetition without the growth that deliberate practice should produce: doing the same things in the same way, not because it is developing mastery but simply out of habit. Alternatively, the reversal can point to perfectionism taken to an unhealthy degree — working obsessively at the expense of broader life, or never being satisfied with the quality of what you produce. The question worth asking is whether your work currently demands the best of you, and whether you are genuinely bringing it.`,
    love2: `In a relationship context, the reversed Eight of Pentacles can suggest that the daily work of a partnership is being neglected — showing up for the small, consistent acts of care and attention that build genuine intimacy over time. Relationships require a kind of craftsmanship too: thoughtful listening, regular investment of energy, willingness to improve as a partner. This reversal asks where that effort has slipped and how to restore it before small neglect compounds.`,
    career2: `At work, this reversal may point to disengagement, boredom with routine tasks, or a job that no longer challenges or develops you. The quality of your work may be suffering as a result — not from lack of ability but from lack of genuine investment. It can also indicate a mismatch between your actual skills and the role you are in. Honestly asking what kind of work would re-engage your genuine effort is the starting point for addressing this pattern.`,
    spirit2: `Spiritually, the reversed Eight of Pentacles reflects a spiritual practice that has become rote — performed habitually without genuine presence or intention. The outer form of the practice continues but the inner engagement has diminished. Rather than abandoning the practice, the invitation is to return to it with fresh attention: approach familiar ground as if for the first time, and notice what you have been mechanically passing over.`,
    faq: [
      {
        q: 'What does the Eight of Pentacles mean in tarot?',
        a: 'The Eight of Pentacles is the tarot\'s card of craftsmanship, mastery, and dedicated work. It represents the process of developing genuine skill through sustained, focused practice — the understanding that excellence is built through consistent effort and careful attention to quality rather than through shortcuts or raw talent alone. When this card appears, it often affirms that your commitment to doing your work well is on the right track, or it is an invitation to bring that level of intentional dedication to an area of your life that has been receiving less than your full attention. It is one of the most encouraging cards for career, education, and creative development.',
      },
      {
        q: 'Does the Eight of Pentacles mean I should study or learn a new skill?',
        a: 'Very often, yes. The Eight of Pentacles is strongly associated with education, professional development, and the deliberate cultivation of expertise. It can appear when you are considering further training, a course of study, or deepening your knowledge in a particular area — and it is generally a positive sign that such investment will pay off. It also affirms the value of on-the-job learning: the kind of expertise that comes from genuine engagement with your work over time rather than just formal qualifications. The card rewards those who commit to improvement rather than coasting on existing abilities.',
      },
      {
        q: 'What does the Eight of Pentacles mean for career?',
        a: 'In a career context, the Eight of Pentacles is one of the most positive and actionable cards you can draw. It speaks to a period of genuine skill development, diligent work that is being — or will be — recognised, and the satisfaction of building real competence in your field. It can indicate a new role that is genuinely stretching your abilities, a period of training or apprenticeship that will advance your career considerably, or simply an affirmation that the quality of your current work deserves recognition. It rewards focus, care, and genuine investment in the craft of what you do.',
      },
    ],
  },

  'nine-of-pentacles': {
    up2: `The Nine of Pentacles is one of the tarot's most beautiful portraits of achieved independence — a figure standing at ease in an abundant garden, falconed bird on wrist, surrounded by the pentacles that represent the fruits of her own labour. What makes this card distinctive is its emphasis on self-sufficiency: this is abundance that has been built through genuine effort and good judgement, not received as an inheritance or gifted by someone else's generosity. The figure has cultivated her material life with intelligence and care, and she is now able to enjoy it with genuine ease. There is a quality of quiet pride here — not vanity, but the deep satisfaction of knowing you created what surrounds you. The card also honours the capacity to enjoy life alone, without requiring another person's presence or validation to feel complete. This is self-reliance as a form of freedom.`,
    rev2: `Reversed, the Nine of Pentacles can point to the erosion of the independence and self-sufficiency it upright represents. Financial security built on unsound foundations — dependency on another's income in ways that compromise autonomy, living beyond your means to project an image of success, or sacrificing genuine wellbeing for material appearances. There is sometimes a quality of isolation that has curdled: the person who has pursued self-sufficiency to such a degree that they are unable to receive help, connection, or collaboration when it would genuinely serve them. The reversal can also indicate a period in which the comfortable life you had built is under threat — requiring a reassessment of your resources, your values, and what genuinely sustains you beyond the material.`,
    love2: `In love, the reversed Nine of Pentacles can indicate tension between independence and partnership. Someone who deeply values their autonomy may be struggling to allow real intimacy, fearing that committed relationship will compromise their hard-won self-sufficiency. Alternatively, it can point to financial dependency in a relationship that creates an uncomfortable power imbalance. The invitation is to find ways to honour both genuine independence and genuine connection — they are not mutually exclusive.`,
    career2: `Professionally, this reversal can suggest that self-sufficiency is being undermined — perhaps by financial decisions that have created dependency, or by a professional situation in which your independence and autonomy are more constrained than they appear. It can also indicate working so hard to maintain an appearance of success that the actual substance of your financial situation is less stable than others see. An honest audit of where you actually stand — and what steps would genuinely restore independence — is the practical starting point.`,
    spirit2: `Spiritually, the Nine of Pentacles reversed can reflect an imbalance between solitary spiritual practice and genuine connection with others. A deeply independent spiritual path has great value, but taken to an extreme it can become spiritual isolation — cutting yourself off from the nourishment of community, tradition, or shared practice. The card asks whether your spiritual life genuinely feeds you, or whether it has become another domain of self-sufficiency that keeps intimacy at arm's length.`,
    faq: [
      {
        q: 'What does the Nine of Pentacles mean in tarot?',
        a: 'The Nine of Pentacles is the card of achieved independence, self-sufficiency, and the refined enjoyment of what you have built through your own effort and good judgement. It represents material comfort that is genuinely earned — the result of sustained work, intelligent choices, and a disciplined approach to cultivating your life. It is also strongly associated with the ability to stand alone — not out of loneliness, but out of the confidence and capacity that genuine self-reliance provides. When it appears, it often affirms that you are close to or already in a position of real financial and personal independence, or it invites you towards that kind of cultivated self-sufficiency.',
      },
      {
        q: 'Is the Nine of Pentacles a good card for money?',
        a: 'Yes — the Nine of Pentacles is one of the most encouraging cards in the deck for financial questions. Upright, it typically indicates financial independence, the enjoyment of accumulated wealth, or the approach of material security built through your own efforts. It often appears when a long period of work is about to pay off in meaningful, tangible ways, or when your current financial approach is genuinely sound and building well. It is particularly positive for questions about investments, savings, self-employment, and any situation where your own skills and efforts are the primary driver of your income.',
      },
      {
        q: 'What does the Nine of Pentacles mean for a single person?',
        a: 'For someone who is single, the Nine of Pentacles is an affirming and sometimes specifically positive card. It celebrates the capacity to build a rich, satisfying, abundant life that does not require a partner to be complete — to be genuinely content and fulfilled in your own company. This is not a consolation prize but a genuine statement of self-sufficiency and inner richness. At the same time, the card is not anti-relationship: it suggests that when partnership does come, you will enter it from a place of genuine wholeness rather than need. The most rewarding relationships tend to be between people who are already complete rather than seeking completion.',
      },
    ],
  },

  'ten-of-pentacles': {
    up2: `The Ten of Pentacles represents the fullest expression of the Pentacles suit — not just individual prosperity but the transmission of that prosperity across time and between generations. The traditional image is multi-generational: elders, parents, children, and dogs all present in a prosperous setting, the pentacles arranged in the pattern of the Kabbalistic Tree of Life. This is legacy: what you build not just for yourself but for those who come after you. It speaks to the kind of wealth that is structural and lasting — wealth embedded in family, in community, in reputation, in tradition and accumulated wisdom. The Ten also carries a note of completion: you can see across the full arc of a life well-built, and what you see is good. This is the card of inheritance in both the literal sense and the broader sense — the traditions, values, and accumulated capital of human experience passed lovingly forward.`,
    rev2: `Reversed, the Ten of Pentacles points to the rupture of what should be enduring — family conflict around inheritance or shared resources, the unravelling of structures that were built to last, or the discovery that what appeared to be a solid foundation is less secure than it seemed. There is often a quality of disappointment here: the gap between the ideal of family stability and its sometimes messier reality. The reversal can also indicate being trapped in family patterns or inherited expectations that do not serve your individual flourishing — carrying the weight of tradition without being able to question it. On a broader level, it can indicate short-term thinking that undermines long-term stability, or the sacrifice of lasting value for immediate gain.`,
    love2: `In a relationship context, the reversed Ten of Pentacles can indicate conflict around family expectations, inheritance, or the question of building a lasting life together. Family interference in the relationship may be creating strain. Alternatively, it can point to a partnership that looked stable and enduring from the outside but has significant cracks beneath the surface. The gap between the relationship you are presenting to the world and the reality you are living is worth examining honestly.`,
    career2: `Professionally, this reversal can suggest that a business, career, or professional legacy that seemed solid is on shaky ground. Long-term financial planning may have been neglected. A family business may be experiencing internal conflict that threatens its stability. On a personal level, it can indicate a career that looks successful by conventional measures but does not actually align with the kind of legacy you want to build with your working life.`,
    spirit2: `Spiritually, the reversed Ten of Pentacles asks you to examine what you have truly inherited — not just materially but in terms of beliefs, values, and worldview. What has been passed down to you that genuinely serves your growth and what has been passed down unconsciously, needing to be questioned and perhaps released? Authentic spiritual legacy requires discernment about which traditions to carry forward and which patterns to consciously end with you.`,
    faq: [
      {
        q: 'What does the Ten of Pentacles mean in tarot?',
        a: 'The Ten of Pentacles is the card of lasting wealth, generational legacy, and the fulfilment that comes from building something genuinely enduring. It represents the culmination of the Pentacles journey — material abundance that is embedded in family, community, and tradition rather than belonging to any one individual. It speaks to inheritance in the fullest sense: not only financial inheritance but the transmission of values, wisdom, and stable foundations across generations. When this card appears, it often affirms that you are building — or are part of — something that will last considerably beyond the immediate moment, and that your material and familial foundations are genuinely strong.',
      },
      {
        q: 'Is the Ten of Pentacles about family?',
        a: 'Family is one of the card\'s central themes, yes — it is the most explicitly familial card in the Pentacles suit, often depicting multiple generations in a single scene. It speaks to family wealth, family legacy, family stability, and the question of what you are building not just for yourself but for those who come after you. However, its scope is broader than the nuclear family: it can represent any close-knit community or tradition that creates enduring value together. It is also relevant to questions about inheritance — both literal inheritances of money and property, and the less tangible inheritances of values, patterns, and beliefs.',
      },
      {
        q: 'What does the Ten of Pentacles mean for the future?',
        a: 'As a future card, the Ten of Pentacles is one of the most positive outcomes you can draw for questions about long-term stability, financial security, or the lasting impact of decisions you are making now. It suggests that what you are building has real permanence — that the foundations you are laying will endure and potentially benefit people beyond just yourself. It is particularly encouraging for questions about buying property, starting a family, building a business with longevity in mind, or making financial decisions with long time horizons. It rewards thinking in decades rather than quarters, and values that prioritise lasting worth over quick returns.',
      },
    ],
  },

  'page-of-pentacles': {
    up2: `The Page of Pentacles is the tarot's portrait of the earnest, attentive beginner — someone who holds a pentacle before them with absorbed concentration, studying it with genuine curiosity and a readiness to learn everything about the material world they are just beginning to engage with. There is something moving about this figure: the willingness to not yet know, to ask questions, to invest in learning before claiming to have mastered. The Page represents a new approach to practical matters, finances, or the physical world — one characterised by openness, diligence, and a genuine eagerness to develop skills. This is not flashy energy; it is the energy of someone who understands that groundwork matters, that the real thing must be built on solid knowledge, and that patience with the learning process is itself a form of intelligence. The Page also carries messages — new practical opportunities, invitations to study, the beginning of a tangible project.`,
    rev2: `Reversed, the Page of Pentacles points to an immaturity in practical matters that is causing problems. This can manifest as poor financial habits — careless spending, reluctance to engage with budgets or plans, avoidance of the practical details of life. It can also describe someone who is perpetually starting new projects or educational paths without the staying power to follow through — all beginning and no development, the seed scattered but never watered. There is sometimes a quality of daydreaming: elaborate plans for material improvement that never translate into actual steps. The reversed Page can also indicate learning that has stalled, or a young person (or the younger, less mature aspects of anyone) who needs to develop more discipline and focus in relation to practical and financial responsibilities.`,
    love2: `In love, the reversed Page of Pentacles can indicate immaturity in how practical aspects of a relationship are being handled — avoiding conversations about money, future plans, or shared responsibility. It can describe a partner who is full of promise but struggles to deliver consistently on practical commitments. If you are looking for a sign that someone is ready to build a genuine future with you, this reversal suggests there is still growing up to do in the realm of material reality and practical commitment.`,
    career2: `Professionally, the reversed Page of Pentacles may point to poor focus at work, difficulty concentrating on tasks that require sustained attention, or an inability to follow through on the foundational work that career development requires. There may be an interest in advancement without the willingness to put in the groundwork. Alternatively, it can indicate a project that has been started but is languishing for lack of consistent effort and discipline. Developing better practical habits and study skills would address the underlying issue.`,
    spirit2: `Spiritually, the reversed Page of Pentacles reflects a disconnection from the embodied, earthly dimension of spiritual life. Spiritual interest may be abundant but untethered from any consistent practice. The invitation is to ground your spiritual aspirations in something concrete and regular — even a simple daily practice done with genuine intention will build more than elaborate plans that never make contact with the actual ground.`,
    faq: [
      {
        q: 'What does the Page of Pentacles mean in tarot?',
        a: 'The Page of Pentacles represents the beginning of a new practical journey — a fresh engagement with the material world, money, career, or physical reality that is characterised by genuine curiosity, diligence, and a readiness to learn. It is the card of the dedicated student: someone who understands that mastery begins with foundational knowledge, and who is willing to invest the careful attention that real learning requires. When this card appears, it often signals a new practical opportunity — a course of study, a business idea in its early stages, a new approach to financial management, or simply a renewed commitment to developing real, useful skills.',
      },
      {
        q: 'Does the Page of Pentacles represent a person?',
        a: 'In traditional tarot, court cards can represent actual people, aspects of yourself, or the energy surrounding a situation. As a person, the Page of Pentacles often describes someone young in age or in experience — someone who is studious, practically minded, reliable in their attention if not yet in their execution, and genuinely motivated to develop themselves. They may be a student, a new employee, or someone embarking on a new practical venture with real commitment. As an aspect of yourself, the Page represents your capacity for earnest engagement, practical curiosity, and the kind of patient, disciplined attention that turns potential into skill.',
      },
      {
        q: 'What does the Page of Pentacles mean for money?',
        a: 'For financial questions, the Page of Pentacles is a promising card that points to new beginnings in how you approach money — a willingness to learn, the beginning of better financial habits, or a new practical opportunity that could prove valuable with sustained effort. It is not the card of immediate windfall but of the diligent foundational work that leads to lasting financial health. It often appears when someone is beginning to take their finances more seriously — setting a budget for the first time, starting a savings practice, or learning about investing. The card affirms that this earnest engagement is exactly the right approach, and that the discipline you are developing now will compound over time.',
      },
    ],
  },

  'queen-of-pentacles': {
    up2: `The Queen of Pentacles is one of the tarot's most warmly grounded figures — a sovereign not of grand gestures or distant power but of practical wisdom, nurturing care, and the deep intelligence that knows how to make things grow. She sits in a lush garden, a pentacle in her lap, surrounded by abundance she has cultivated and continues to tend. What distinguishes her from mere comfort is her competence: this is not someone who has been handed prosperity but someone who understands how to create and sustain it. She embodies the integration of the material and the nourishing — financial acumen married to genuine warmth, practical problem-solving alongside deep care for those within her sphere. She is the person whose home always has enough, whose counsel is grounded and trustworthy, who creates environments where others can thrive. Sensuality, the pleasure of the physical world, and the body's wisdom are all part of her domain.`,
    rev2: `Reversed, the Queen of Pentacles can manifest in two contrasting ways. The first is a smothering or controlling version of care — nurturing that creates dependency rather than independence, generosity that comes with an implicit ledger of obligation, or practical management that tips into micromanagement and control. The second is the depleted version: a person who gives so consistently and so fully to the needs of others that their own wellbeing, finances, or sense of self has been chronically neglected. Both shadows arise from the same source: a conflation of one's worth with one's usefulness to others. The reversed Queen is an invitation to examine whether your giving is genuinely free, whether your practical care of others has a sustainable foundation, and whether you are extending to yourself even a fraction of the nourishment you so readily give.`,
    love2: `In love, the reversed Queen of Pentacles can describe someone who over-functions in a relationship — taking on the emotional and practical labour of sustaining the partnership without reciprocal support. It can also indicate that warmth and care have hardened into control, or that financial management within the relationship has become a source of power rather than partnership. The invitation is to receive as well as give, and to examine whether your mode of caring genuinely serves both people or quietly exhausts you.`,
    career2: `Professionally, the reversed Queen of Pentacles may indicate burnout from over-responsibility — someone who has taken on too much of the practical and emotional management at work and is running low. It can also point to financial disorganisation that contradicts an otherwise competent exterior, or someone whose considerable practical abilities are not being recognised or compensated fairly. Reclaiming boundaries and ensuring your own professional needs are met is the essential first step.`,
    spirit2: `Spiritually, the reversed Queen of Pentacles can indicate a disconnection from the body as a source of wisdom and spiritual intelligence. An overly cerebral or ascetic approach to spiritual life may be cutting you off from the earthly, sensory, embodied dimension of experience that this queen represents. She invites you back into the garden — into the physical world, the pleasures of the senses, the intelligence of the body — as a legitimate and necessary part of spiritual wholeness.`,
    faq: [
      {
        q: 'What does the Queen of Pentacles mean in tarot?',
        a: 'The Queen of Pentacles represents the integration of practical wisdom, genuine nurturing, and material competence. She is a figure of warmth and groundedness — someone who knows how to create abundance and sustain it, who cares deeply for those within her sphere, and who brings both financial intelligence and genuine human warmth to everything she touches. She represents the understanding that material care — providing a warm home, managing resources wisely, tending to the physical needs of those you love — is a genuinely sophisticated and valuable form of intelligence. She is one of the most thoroughly competent and warmly human figures in the entire tarot.',
      },
      {
        q: 'What kind of person does the Queen of Pentacles represent?',
        a: 'As a person, the Queen of Pentacles typically describes someone who is deeply practical, nurturing, and resourceful — someone who creates warm, well-managed environments, who has genuine financial competence, and whose care for others is expressed through concrete, tangible acts rather than purely emotional gestures. This person is often someone others turn to in practical difficulty: their advice is grounded, their home is welcoming, their resources are well-husbanded. They tend to have a strong connection to nature and the physical world, a sensory appreciation of beauty and comfort, and an ability to make things grow — whether gardens, businesses, families, or communities.',
      },
      {
        q: 'What does the Queen of Pentacles mean in a love reading?',
        a: 'In love, the Queen of Pentacles represents a deeply nourishing and grounded form of partnership. She suggests a relationship built on genuine practical compatibility, shared values around security and comfort, and a warmth that expresses itself through tangible acts of care rather than purely romantic gestures. If she represents you, she may be affirming your capacity to create a genuinely sustaining relationship. If she represents a partner or potential partner, she speaks to someone who is deeply reliable, practically capable, and whose love is expressed through real, consistent investment in shared wellbeing. She is the person who makes a house into a home.',
      },
    ],
  },

  'king-of-pentacles': {
    up2: `The King of Pentacles is the ultimate archetype of earned, grounded wealth. Unlike cards that speak of windfalls or luck, the King represents what is built slowly and deliberately over time — property, business empires, investment portfolios, reputations. When he appears in your reading, the message is that you have reached (or are close to reaching) a level of mastery where your resources can now work for you. This is the energy of the entrepreneur who has survived the lean years and now leads from a place of solid experience rather than ambition alone. He is not flashy; he is secure. He does not need to prove his worth because his track record speaks for itself.`,
    rev2: `When the King of Pentacles appears reversed, the shadow side of material success comes into focus. This may indicate a preoccupation with wealth that has crowded out everything else — relationships, health, joy. There can be a tendency toward stubbornness or an unwillingness to adapt to changing financial conditions. Alternatively, it can point to someone who appears successful on the surface but whose foundations are built on poor decisions or dishonest means. Check whether you are managing your finances from a place of abundance or from fear and scarcity thinking. The reversed King asks: are you serving money, or is money serving you?`,
    love2: `In a relationship reading, the King of Pentacles reversed can indicate a partner who prioritises work and financial security at the expense of emotional connection. There may be a sense of being provided for materially but neglected emotionally. Alternatively, issues around financial control or possessiveness can arise. If you are single, the reversed King may warn against choosing partners primarily for security rather than genuine connection — or reflect a need to examine your own relationship with material comfort before entering partnership.`,
    career2: `In career questions, the King of Pentacles reversed suggests poor financial decisions, mismanagement of resources, or a leader whose authority has become rigid and counterproductive. If you are in a leadership role, ask whether your decisions are being driven by long-term vision or short-term greed. For employees, this card reversed may indicate a boss or company culture that treats people as financial assets rather than human beings. Review your relationship with money — whether personal finances, business decisions, or salary negotiations — and look for where fear-based thinking is replacing sound strategy.`,
    spirit2: `The reversed King of Pentacles spiritually asks whether your pursuit of security has become a form of spiritual avoidance. When we are overly focused on building and protecting material stability, we can lose touch with the deeper questions that give life meaning. This card reversed invites a reassessment: not an abandonment of material care, but a rebalancing so that the spiritual and relational dimensions of life receive their proper attention. True security, the reversed King teaches, cannot be achieved through bank accounts alone.`,
    faq: [
      {
        q: 'What does the King of Pentacles mean in tarot?',
        a: 'The King of Pentacles represents financial mastery, practical wisdom and grounded leadership. He is the archetype of the self-made person who has built lasting security through discipline and patience. In a reading, he signals that abundance, stability and professional success are available through methodical, trustworthy effort.',
      },
      {
        q: 'Is the King of Pentacles a yes or no card?',
        a: 'Yes — the King of Pentacles is a strong yes card, particularly for questions about money, business, career and long-term stability. He confirms that the practical foundations are sound and that success is achievable. Reversed, the answer becomes more conditional: yes, but check whether greed or poor management is creating unnecessary obstacles.',
      },
      {
        q: 'What does the King of Pentacles mean in love?',
        a: 'In love, the King of Pentacles represents a stable, generous and committed partner — someone who provides security and builds a life with care. He may not be the most emotionally expressive, but his reliability and devotion are deep. For singles, he suggests attracting or becoming a grounded, trustworthy partner.',
      },
    ],
  },

  'knight-of-pentacles': {
    up2: `Where the other knights charge ahead with fire, passion or dreams, the Knight of Pentacles plods — and that is precisely his superpower. He does not seek glory or quick wins. He understands that lasting achievement is built through unglamorous, consistent effort applied day after day. If you have drawn this card, it is likely that you are being called to embrace the long game: to show up even when motivation fades, to honour your commitments even when they become tedious, and to trust that slow progress is still progress. The Knight of Pentacles succeeds not because of brilliance, but because of trustworthiness — to others and to himself.`,
    rev2: `The Knight of Pentacles reversed can manifest as stagnation — being so stuck in routine that genuine growth has stopped. There is a difference between healthy persistence and stubborn repetition of what is no longer working. Reversed, this Knight may also indicate perfectionism so intense that it becomes paralysing: the project never gets finished because it is never good enough. On the other end of the spectrum, reversed energy can suggest irresponsibility or a failure to follow through on commitments. Ask yourself honestly: are you being reliably consistent, or are you just going through the motions?`,
    love2: `In love, the Knight of Pentacles reversed can describe a relationship that has grown dull or stagnant — where comfort has replaced genuine connection and neither partner is investing in growth. There may be a reluctance to try new things together or address underlying issues. For singles, this card reversed may indicate that a fear of instability is preventing you from taking a healthy romantic risk, or that you have become too rigid in your expectations of a partner. Sometimes love requires you to move out of your comfortable routine.`,
    career2: `Professionally, the reversed Knight of Pentacles can indicate burnout from grinding without seeing sufficient results, or a situation where steady work is not being recognised or rewarded. It may also suggest that your approach has become outdated — that what worked before is no longer effective, and adaptation is needed. On the flip side, it can point to procrastination dressed up as preparation, or a tendency to wait for perfect conditions before taking action. The work is being done, but is it the right work?`,
    spirit2: `Spiritually, the Knight of Pentacles reversed invites you to examine whether your practice has become merely mechanical. Routine and discipline are powerful foundations for spiritual development, but when they become rigid habit without genuine presence, they lose their transformative power. The reversed Knight asks: are you showing up for your practice in body only, or are you truly present? Real growth requires not just consistency but aliveness — a genuine engagement with what you are doing, not just completion of the task.`,
    faq: [
      {
        q: 'What does the Knight of Pentacles mean in tarot?',
        a: 'The Knight of Pentacles represents reliable, methodical effort and the discipline to follow through over the long term. He is the hardest working of the knights — not the most exciting, but the most trustworthy. In a reading, he encourages patience, routine and a commitment to slow, steady progress over shortcuts.',
      },
      {
        q: 'Is the Knight of Pentacles a yes or no card?',
        a: 'Yes — the Knight of Pentacles is generally a yes card, particularly for questions involving effort, practical achievement and long-term goals. He confirms that patient, consistent work will lead to the desired outcome. Reversed, the answer is more cautious: proceed, but address any stagnation or procrastination that is blocking progress.',
      },
      {
        q: 'What does the Knight of Pentacles mean in love?',
        a: 'In love, the Knight of Pentacles represents a devoted, loyal and dependable partner who is in it for the long haul. He shows love through actions rather than words — through showing up, being reliable and building a secure life together. He may not be the most romantic, but his consistency and commitment are deeply reassuring.',
      },
    ],
  },

  'five-of-swords': {
    up2: `The Five of Swords is one of the most uncomfortable cards in the tarot precisely because it forces us to examine our own role in conflict. The figure in the traditional image picks up the swords of defeated opponents — but look at their faces. The victory is hollow. Something important has been lost or broken in the pursuit of winning. This card shows up when the ego has taken the wheel: when being right has become more important than being kind, when protecting pride has cost something of genuine value. It asks the hardest question: was the fight worth it? And more importantly — is it still worth it? The Five of Swords never suggests that you should be a doormat, but it does insist that not every battle deserves your energy.`,
    rev2: `The Five of Swords reversed carries a more hopeful message than its upright position. Conflict is either ending or you are reaching a point of genuine readiness to move beyond it. There may be an acknowledgement of the damage caused — by yourself or by others — and a desire for reconciliation. However, reversal can also indicate that unresolved guilt or regret is lingering, making it difficult to truly move forward. Old wounds from past battles may be re-emerging. The invitation here is not to re-fight old wars but to genuinely process what happened and choose a different response next time.`,
    love2: `In love, the Five of Swords reversed often marks a turning point in a difficult relationship dynamic. Arguments that escalated beyond reason may begin to settle, and both partners may recognise that the damage done to trust is a serious concern. This card reversed calls for honest conversation rather than score-keeping — a genuine effort to repair rather than retaliate. If the relationship has been characterised by one partner consistently winning arguments while the other loses dignity, the reversed Five of Swords signals that this pattern must change or the relationship cannot survive.`,
    career2: `In career readings, the Five of Swords reversed can indicate the aftermath of workplace conflict — a resolution, however uncomfortable, beginning to take shape. Office politics or competitive dynamics that have been playing out may be losing their intensity. This is an opportunity to rebuild professional relationships damaged by power struggles. Alternatively, it can suggest finally choosing to walk away from a toxic work environment — accepting the short-term discomfort of a career change over the long-term damage of remaining in a place of constant conflict.`,
    spirit2: `Spiritually, the Five of Swords reversed is a powerful invitation to examine the ego's role in your life. Conflict — whether external or internal — is one of the ego's favourite territories. The reversed card asks: what in you still needs to win, to be right, to dominate? True spiritual maturity is not about never feeling competitive or defensive, but about recognising those impulses and choosing a response aligned with your deeper values. Forgiveness — of others and of yourself for past battles — is the primary spiritual work of this card.`,
    faq: [
      {
        q: 'What does the Five of Swords mean in tarot?',
        a: 'The Five of Swords represents conflict, hollow victory and the cost of ego-driven behaviour. It warns that winning at all costs can destroy what matters most — relationships, reputation and self-respect. In a reading, it signals a need to choose battles wisely and consider whether the pursuit of victory is truly worth the price being paid.',
      },
      {
        q: 'Is the Five of Swords a yes or no card?',
        a: 'No — the Five of Swords is generally a no card, particularly for questions involving conflict, competition or aggressive tactics. It cautions that forcing an outcome through power or manipulation will lead to a hollow result. Reversed, the answer softens: not yet, but healing and resolution are becoming possible.',
      },
      {
        q: 'What does the Five of Swords mean in love?',
        a: 'In love, the Five of Swords is a warning sign. It often indicates arguments where someone is more focused on winning than on the health of the relationship, or a dynamic of manipulation, betrayal or disrespect. It calls for an honest assessment of whether the relationship brings out the best or worst in both partners.',
      },
    ],
  },

  'nine-of-swords': {
    up2: `The Nine of Swords is famously known as the card of the dark night of the soul — those 3am hours when the mind runs relentlessly through worst-case scenarios, past regrets and feared futures. The important thing to understand about this card is that the suffering it depicts is real, but it is also amplified by the mind's tendency to catastrophise. The nine swords hang on the wall — they are not actually stabbing the figure. The nightmare is happening inside, not outside. This does not minimise the pain; anxiety and mental anguish are genuine forms of suffering. But it does suggest that the path forward involves working with the mind itself: finding support, challenging distorted thinking, and recognising that the dawn will come even in the depths of the darkest night.`,
    rev2: `The Nine of Swords reversed is one of the more complex reversals in the tarot. On the positive side, it can indicate that you are beginning to emerge from a period of intense anxiety — that the worst of the mental storm is passing and clarity is returning. On the more challenging side, it can suggest that anxiety or depression has become so deep that it is now hidden — suppressed rather than faced, or manifesting as secrecy around mental health struggles. It can also indicate releasing — finally — a burden that was never truly yours to carry. Notice which interpretation resonates most honestly with your current situation.`,
    love2: `In love, the Nine of Swords reversed can indicate that anxiety about a relationship is beginning to ease. Fear of abandonment, jealousy or obsessive thinking that has been tormenting you may be losing its grip as you develop greater self-trust. Alternatively, it can suggest that a relationship has been a source of such significant anxiety that recovery requires distance from it — that the stress the partnership has caused needs to be genuinely processed rather than suppressed. Therapy or honest self-examination is often the most loving next step this card can suggest.`,
    career2: `Professionally, the Nine of Swords reversed points to a release from extreme work-related stress or imposter syndrome. You may be beginning to see that the fear of failure you have been carrying does not reflect your actual capabilities. Alternatively, it can indicate that burnout has reached a point where the body or psyche is forcing a stop — and this forced pause, while unwelcome, may ultimately be the beginning of recovery. A conversation with a mentor, therapist or trusted colleague about what you are truly carrying professionally could be one of the most useful actions this card suggests.`,
    spirit2: `The Nine of Swords reversed spiritually marks a significant turning point: the willingness to face the darkness within rather than flee it. The most powerful spiritual growth often happens not in moments of peace, but in the depths of genuine struggle. When this card appears reversed, there is often an invitation to seek spiritual support — whether through community, a teacher, a therapist with spiritual sensitivity, or a practice of honest journaling and reflection. The reversed Nine of Swords does not promise that the darkness is over; it promises that you are finally facing it, and that facing it is the beginning of healing.`,
    faq: [
      {
        q: 'What does the Nine of Swords mean in tarot?',
        a: 'The Nine of Swords represents anxiety, mental anguish, nightmares and worst-case thinking. It is the card of the sleepless night, the obsessive worry loop and the fear that things are worse than they are. In a reading, it calls for compassionate self-examination: what thoughts are causing unnecessary suffering, and what genuine support is needed?',
      },
      {
        q: 'Is the Nine of Swords a yes or no card?',
        a: 'No — the Nine of Swords is a no card, indicating that fear and anxiety are distorting your perception of the situation. It suggests that now is not the right time to make major decisions, as the mind is not operating from clarity. Reversed, it offers cautious hope: healing is beginning, but proceed gently.',
      },
      {
        q: 'What does the Nine of Swords mean in love?',
        a: 'In love, the Nine of Swords often indicates anxiety and fear within a relationship — worrying about a partner\'s feelings, fearing loss or abandonment, or experiencing sleepless nights over relationship problems. It can also reflect guilt about past relationship behaviour. The card asks for honesty about what you are truly afraid of, and whether those fears are rooted in present reality or old wounds.',
      },
    ],
  },

  'six-of-swords': {
    up2: `The Six of Swords depicts a small boat moving across still water, away from rough shores toward a calmer horizon. The journey is not joyful — the figures are huddled and silent, and the swords still sit in the bow of the boat — but it is necessary and it is happening. This is the card of the healing transition: leaving behind what has been painful and allowing yourself to be carried toward something better, even if you cannot yet see clearly where you are going. The Six of Swords appears when you are in the middle of the crossing — not at the departure point (that was the Five) and not yet at the destination. You are between worlds. This is an uncomfortable but ultimately hopeful place to be, and the card asks you to trust the process of moving, even when the destination is uncertain.`,
    rev2: `The Six of Swords reversed speaks to the difficulty of moving on. There may be a genuine desire to leave a painful situation behind, but something is creating resistance — fear of the unknown, unfinished emotional business, a sense of not being ready, or external circumstances that are making transition difficult. It can also indicate rough waters ahead — the journey toward calmer conditions is proving bumpier than hoped. The invitation of the reversed Six of Swords is patience and self-compassion: moving on is a process, not an event, and it is okay if your transition is taking longer than you expected.`,
    love2: `In love, the Six of Swords reversed often appears during the hardest phase of a breakup or separation — when the decision to leave has been made but the emotional processing is far from complete. You may know intellectually that a relationship is over while still feeling deeply connected to it, or still grieving what was lost. This is a normal and necessary part of healing. The reversed card asks you to be patient with yourself and avoid rushing back into the situation (or into a new relationship as a distraction) before the genuine inner work of transition has been done.`,
    career2: `Professionally, the Six of Swords reversed may indicate a career transition that is proving more difficult than anticipated — a job search that is taking longer, a new role that is not living up to expectations, or a struggle to truly leave behind the stress of a previous workplace. It can also suggest resistance to necessary change: knowing that a professional situation is not working but being unable or unwilling to make the move away from it. Clarity about what you are truly moving toward (rather than just away from) may be the missing piece that helps the transition finally happen.`,
    spirit2: `The Six of Swords reversed spiritually invites you to examine what you are still carrying from the past that is weighing down your boat. Old grief, outdated beliefs, spiritual wounds from previous experiences — these are the swords in the bow that are slowing your crossing. The reversed card does not demand that you drop them all immediately; it simply asks you to notice them, and to consider which ones you are ready to release. Sometimes a spiritual guide, therapist or honest journalling practice can help identify exactly what has been packed for the journey that does not actually belong on the boat.`,
    faq: [
      {
        q: 'What does the Six of Swords mean in tarot?',
        a: 'The Six of Swords represents transition, healing and movement away from turmoil toward calmer waters. It is the card of necessary journeys — physical relocations, leaving behind difficult relationships or life chapters, and the slow emotional process of moving on. It carries hope without pretending the crossing is easy.',
      },
      {
        q: 'Is the Six of Swords a yes or no card?',
        a: 'Yes — the Six of Swords is a gentle yes, particularly for questions about moving on, making transitions or leaving difficult situations behind. It confirms that movement in a better direction is not only possible but already underway. Reversed, the answer becomes a "not yet" — the transition is needed but not quite flowing yet.',
      },
      {
        q: 'What does the Six of Swords mean in love?',
        a: 'In love, the Six of Swords most often signals moving away from a turbulent relationship or a painful emotional chapter. It can indicate a separation, a healing period after loss, or a relationship that is transitioning to a calmer, more mature phase. The key message is that peace is coming — but the crossing takes time.',
      },
    ],
  },

}
